/*
 * contextdata.locals.js  (SC.contextDataLocals) – Arbeits-/Alltags-Kontext für die
 * LOCALS-Lernkarten (Track es-en: Spanisch-Sprecher lernen Englisch). REINE DATEN.
 * Pendant zu contextdata.js, nur in der GEDREHTEN Lernrichtung. Wird in context.js
 * (expandLocals) an die loc-* Karten gehängt – nur im Locals-Track (data.locals.js
 * hat die Karten dann in SC.data.CARDS eingehängt). Schlüssel = Karten-id.
 *
 * Kompakte Schreibweise pro Eintrag:
 *   e   = englischer Beispielsatz – echter, sprechbarer Satz aus dem Arbeitsalltag
 *         (Hostelería/Tourismus, Tag-für-Tag, Job). Die zu lernende Sprache.
 *   t   = spanische Übersetzung des Satzes (Verständnishilfe, LatAm-Spanisch)
 *   s   = situación (Spanisch) – konkrete Situation: wann sagt man das?
 *   sEn = situation (Englisch) – gleiche Aussage auf Englisch
 *   n   = consejo (Spanisch) – kurzer Tipp / Besonderheit / höflichere Variante
 *   nEn = tip (Englisch) – gleiche Aussage auf Englisch
 *
 * Generiert aus den Karten in data.locals.js (ein Eintrag pro Karte). Inhaltsregeln:
 * echter, natürlicher Satz aus dem Arbeitsalltag – nicht schulisch; Englisch
 * idiomatisch, Spanisch natürlich (LatAm). {name} wird zur Laufzeit ersetzt.
 */
(function () {
  "use strict";

  var C = {
    // ===================== At the restaurant (meseros) =====================
    "loc-mes01": { e: "Are you ready to order, or do you need a few more minutes?", t: "¿Están listos para ordenar, o necesitan unos minutos más?", s: "Cuando te acercas a una mesa después de dejar el menú.", sEn: "When you approach a table after dropping off the menu.", n: "Agregar \"or do you need a few more minutes?\" suena más amable y sin presión.", nEn: "Adding \"or do you need a few more minutes?\" sounds friendlier and less pushy." },
    "loc-mes02": { e: "Anything to drink while you look at the menu?", t: "¿Algo de tomar mientras ven el menú?", s: "Apenas sientas a los clientes, antes de tomar el pedido de comida.", sEn: "Right after you seat the guests, before taking the food order.", n: "\"Drink\" se pronuncia \"drink\", no \"drinc\"; mantén la k suave al final.", nEn: "\"Drink\" ends in a soft k sound, not a hard \"c\"." },
    "loc-mes03": { e: "For here or to go?", t: "¿Para comer aquí o para llevar?", s: "En un mostrador de comida rápida cuando el cliente pide.", sEn: "At a fast-food counter when the customer orders.", n: "En el Reino Unido suele decirse \"eat in or take away?\" para lo mismo.", nEn: "In the UK people often say \"eat in or take away?\" for the same thing." },
    "loc-mes04": { e: "Here is the menu, and I'll be right back to take your order.", t: "Aquí tiene el menú, y vuelvo enseguida a tomar su pedido.", s: "Al entregar la carta a una mesa recién sentada.", sEn: "When handing the menu to a freshly seated table.", n: "Para varias personas di \"here are the menus\" en plural.", nEn: "For several people say \"here are the menus\" in the plural." },
    "loc-mes05": { e: "How would you like your steak — rare, medium, or well done?", t: "¿Cómo desea su bistec: poco hecho, término medio o bien cocido?", s: "Cuando el cliente pide un corte de carne.", sEn: "When the customer orders a cut of meat.", n: "Ofrecer las opciones (rare/medium/well done) ayuda al cliente a responder rápido.", nEn: "Offering the options (rare/medium/well done) helps the customer answer quickly." },
    "loc-mes06": { e: "Do you have any allergies I should tell the kitchen about?", t: "¿Tiene alguna alergia que deba avisarle a la cocina?", s: "Antes de enviar un pedido a la cocina, por seguridad.", sEn: "Before sending an order to the kitchen, for safety.", n: "\"Allergies\" lleva el acento en la primera sílaba: A-ller-gies.", nEn: "\"Allergies\" is stressed on the first syllable: A-ller-gies." },
    "loc-mes07": { e: "Today's special is fish, and it comes with rice and vegetables.", t: "El plato del día es pescado, y viene con arroz y verduras.", s: "Cuando recomiendas el plato del día a la mesa.", sEn: "When you recommend the daily special to the table.", n: "También puedes decir \"the special of the day\" sin cambiar el sentido.", nEn: "You can also say \"the special of the day\" with the same meaning." },
    "loc-mes08": { e: "Would you like any dessert? We have cheesecake and ice cream.", t: "¿Desea algún postre? Tenemos cheesecake y helado.", s: "Después de retirar los platos principales.", sEn: "After clearing the main dishes.", n: "\"Dessert\" (postre) lleva doble s; \"desert\" (desierto) lleva una sola.", nEn: "\"Dessert\" (the sweet) has a double s; \"desert\" (the dry place) has one." },
    "loc-mes09": { e: "Of course, I'll bring you the bill right away.", t: "Claro, enseguida le traigo la cuenta.", s: "Cuando el cliente pide la cuenta.", sEn: "When the customer asks for the check.", n: "En EE. UU. se dice \"the check\" en vez de \"the bill\".", nEn: "In the US people say \"the check\" instead of \"the bill\"." },
    "loc-mes10": { e: "Sorry for the wait — your table is ready now.", t: "Disculpe la demora; su mesa ya está lista.", s: "Cuando el cliente esperó más de lo normal.", sEn: "When the customer has waited longer than usual.", n: "\"Sorry for the wait\" suena más cálido que el formal \"we apologize for the delay\".", nEn: "\"Sorry for the wait\" sounds warmer than the formal \"we apologize for the delay\"." },
    "loc-mes11": { e: "Good evening! Table for how many?", t: "¡Buenas noches! ¿Mesa para cuántos?", s: "Al recibir a un grupo en la entrada del restaurante.", sEn: "When greeting a group at the restaurant entrance.", n: "Más completo: \"a table for how many people?\" si quieres sonar más claro.", nEn: "Fuller version: \"a table for how many people?\" if you want to be clearer." },
    "loc-mes12": { e: "The restroom is in the back, just past the bar.", t: "El baño está al fondo, justo pasando la barra.", s: "Cuando un cliente pregunta dónde está el baño.", sEn: "When a customer asks where the bathroom is.", n: "En lugares públicos \"restroom\" suena más educado que \"toilet\".", nEn: "In public places \"restroom\" sounds more polite than \"toilet\"." },
    "loc-mes13": { e: "Is everything okay here? Can I get you anything else?", t: "¿Todo bien por aquí? ¿Les traigo algo más?", s: "Al pasar por la mesa para revisar a mitad de la comida.", sEn: "When you check on the table partway through the meal.", n: "Acompáñalo con una sonrisa; suena como interés genuino, no como apuro.", nEn: "Pair it with a smile so it sounds like genuine care, not rushing them." },
    "loc-mes14": { e: "Shall I heat up your food? It's been sitting for a few minutes.", t: "¿Le caliento la comida? Lleva unos minutos servida.", s: "Cuando notas que el plato del cliente se enfrió.", sEn: "When you notice the customer's plate has gone cold.", n: "\"Shall I...?\" es muy cortés; en EE. UU. también vale \"Want me to heat it up?\".", nEn: "\"Shall I...?\" is very polite; in the US \"Want me to heat it up?\" also works." },
    "loc-mes15": { e: "Would you like the wine list, or shall I bring something while you decide?", t: "¿Desea ver la carta de vinos, o le traigo algo mientras decide?", s: "Después de sentar a los clientes en un restaurante con buena oferta de vinos.", sEn: "After seating guests at a restaurant with a good wine selection.", n: "'wine list' se dice 'uain list'; evita decir 'wine letter'.", nEn: "'Wine list' is the right term; avoid saying 'wine letter'." },
    "loc-mes16": { e: "How was everything? Can I get you anything else before the bill?", t: "¿Cómo estuvo todo? ¿Le traigo algo más antes de la cuenta?", s: "Al recoger los platos vacíos para saber si todo gustó.", sEn: "When clearing the empty plates to check if everything was enjoyed.", n: "Es más natural que 'how was all'; usa siempre 'everything'.", nEn: "It's more natural than 'how was all'; always use 'everything'." },
    // ===================== At reception (recepcion) =====================
    "loc-rec01": { e: "Welcome, do you have a reservation with us tonight?", t: "Bienvenido, ¿tiene una reserva con nosotros esta noche?", s: "En recepción cuando llega un huésped.", sEn: "At the front desk when a guest arrives.", n: "\"Reservation\" es el término de hotel; \"booking\" es más común en el Reino Unido.", nEn: "\"Reservation\" is the hotel term; \"booking\" is more common in the UK." },
    "loc-rec02": { e: "May I see your passport, please, to complete the check-in?", t: "¿Me permite su pasaporte, por favor, para completar el registro?", s: "Durante el registro de un huésped extranjero.", sEn: "During check-in for a foreign guest.", n: "\"May I...\" es más formal y cortés que \"Can I...\" para pedir documentos.", nEn: "\"May I...\" is more formal and polite than \"Can I...\" when asking for documents." },
    "loc-rec03": { e: "Breakfast is from seven to ten in the dining room downstairs.", t: "El desayuno es de siete a diez en el comedor de abajo.", s: "Al explicar los horarios del hotel durante el check-in.", sEn: "When explaining the hotel schedule during check-in.", n: "Para horas usa \"from... to...\"; \"between seven and ten\" también suena natural.", nEn: "For times use \"from... to...\"; \"between seven and ten\" also sounds natural." },
    "loc-rec04": { e: "Your room is on the second floor, and the elevator is on your left.", t: "Su habitación está en el segundo piso, y el ascensor está a su izquierda.", s: "Al entregar la llave y dar indicaciones al huésped.", sEn: "When handing over the key and giving directions to the guest.", n: "Ojo: en EE. UU. \"second floor\" es el primer piso de arriba; en el Reino Unido eso es \"first floor\".", nEn: "Note: in the US \"second floor\" is one up from ground; in the UK that's the \"first floor\"." },
    "loc-rec05": { e: "The wifi is free, and the password is on the back of your key card.", t: "El wifi es gratis, y la contraseña está atrás de su tarjeta llave.", s: "Cuando el huésped pregunta por internet en la recepción.", sEn: "When the guest asks about internet at the front desk.", n: "\"Wifi\" se pronuncia \"uai-fai\", no \"ui-fi\".", nEn: "\"Wifi\" is pronounced \"why-fy\", not \"wee-fee\"." },
    "loc-rec06": { e: "What time is check-out? I'd like to plan my morning.", t: "¿A qué hora es la salida? Quiero organizar mi mañana.", s: "Cuando un huésped pregunta hasta qué hora puede quedarse.", sEn: "When a guest asks how late they can stay.", n: "\"Check-out\" lleva guion como sustantivo; \"to check out\" sin guion es el verbo.", nEn: "\"Check-out\" is hyphenated as a noun; \"to check out\" without a hyphen is the verb." },
    "loc-rec07": { e: "Do you need an extra towel, or anything else for the room?", t: "¿Necesita una toalla extra, o algo más para la habitación?", s: "Cuando un huésped pide algo en recepción y quieres ofrecerle más.", sEn: "When a guest asks for something at reception and you want to offer more.", n: "Usa \"extra\" antes del sustantivo: \"an extra towel\", no \"a towel extra\".", nEn: "Put \"extra\" before the noun: \"an extra towel\", not \"a towel extra\"." },
    "loc-rec08": { e: "I'm happy to help you with that, just give me one moment.", t: "Con gusto le ayudo con eso, deme un momento.", s: "Cuando un huésped te pide un favor y quieres mostrar buena disposición.", sEn: "When a guest asks you for a favor and you want to sound willing.", n: "\"I'm happy to help\" suena más cálido que \"I can help\".", nEn: "\"I'm happy to help\" sounds warmer than \"I can help\"." },
    "loc-rec09": { e: "I'm sorry, we're fully booked tonight, but I can recommend a place nearby.", t: "Lo siento, estamos llenos esta noche, pero puedo recomendarle un lugar cerca.", s: "Cuando alguien quiere una habitación y no hay disponibilidad.", sEn: "When someone wants a room and there's no availability.", n: "\"Fully booked\" es lo natural en hoteles; \"full\" suena a estómago lleno.", nEn: "\"Fully booked\" is natural for hotels; \"full\" sounds like a full stomach." },
    "loc-rec10": { e: "How was your stay with us? I hope everything was comfortable.", t: "¿Qué tal su estadía con nosotros? Espero que todo haya sido cómodo.", s: "Cuando el huésped se va y quieres saber su experiencia.", sEn: "When the guest is leaving and you want to hear about their experience.", n: "\"Stay\" se pronuncia \"stéi\", no \"estéi\"; evita la 'e' al inicio.", nEn: "\"Stay\" sounds like \"stay\", with no extra 'e' at the start." },
    "loc-rec11": { e: "Do you need help with your luggage? I can take it up to your room.", t: "¿Necesita ayuda con el equipaje? Puedo subírselo a la habitación.", s: "Cuando un huésped llega o sale con maletas pesadas.", sEn: "When a guest arrives or leaves with heavy bags.", n: "\"Luggage\" es incontable: di \"your luggage\", nunca \"luggages\".", nEn: "\"Luggage\" is uncountable: say \"your luggage\", never \"luggages\"." },
    "loc-rec12": { e: "Check-in is at three, but you're welcome to leave your bags with us until then.", t: "El registro es a las tres, pero puede dejar sus maletas con nosotros hasta entonces.", s: "Cuando un huésped llega antes de la hora de registro.", sEn: "When a guest arrives before check-in time.", n: "\"Check-in\" lleva guion como sustantivo; \"check in\" separado es el verbo.", nEn: "\"Check-in\" is hyphenated as a noun; \"check in\" apart is the verb." },
    "loc-rec13": { e: "Would you like me to call a taxi for you?", t: "¿Quiere que le pida un taxi?", s: "Cuando un huésped necesita transporte para salir.", sEn: "When a guest needs transport to go out.", n: "\"Would you like me to...\" es más cortés que \"Do you want me to...\".", nEn: "\"Would you like me to...\" is more polite than \"Do you want me to...\"." },
    "loc-rec14": { e: "Your key, please, and I'll have your bill ready in a minute.", t: "Su llave, por favor, y le tengo la cuenta lista en un minuto.", s: "Cuando el huésped hace el check-out y devuelve la llave.", sEn: "When the guest checks out and returns the key.", n: "Agregar \"please\" suaviza la petición y suena profesional.", nEn: "Adding \"please\" softens the request and sounds professional." },
    "loc-rec15": { e: "Would you like me to store your luggage until your room is ready?", t: "¿Desea que le guarde el equipaje hasta que su habitación esté lista?", s: "Cuando un huésped llega antes de la hora de registro.", sEn: "When a guest arrives before check-in time.", n: "'luggage' es incontable; nunca digas 'luggages'.", nEn: "'Luggage' is uncountable; never say 'luggages'." },
    "loc-rec16": { e: "Just so you know, the pool closes at eight, so plan your swim before then.", t: "Para que lo sepa, la piscina cierra a las ocho, así que planee su baño antes.", s: "Al informar a un huésped sobre los horarios de las instalaciones.", sEn: "When informing a guest about facility hours.", n: "'pool' se pronuncia 'pul', con la 'l' clara al final.", nEn: "'Pool' is pronounced 'pool' with a clear 'l' at the end." },
    // ===================== Tours & guides (guias) =====================
    "loc-gui01": { e: "Welcome to the tour, everyone, I'm glad you could join us today.", t: "Bienvenidos al tour, me alegra que hayan podido acompañarnos hoy.", s: "Al inicio del recorrido, para saludar al grupo.", sEn: "At the start of the tour, to greet the group.", n: "\"Welcome to\" lleva \"to\"; no digas \"welcome at the tour\".", nEn: "\"Welcome to\" needs \"to\"; don't say \"welcome at the tour\"." },
    "loc-gui02": { e: "Please follow me, and stay close so no one gets left behind.", t: "Síganme, por favor, y manténganse cerca para que nadie se quede atrás.", s: "Cuando empiezas a caminar y quieres que el grupo te siga.", sEn: "When you start walking and want the group to follow you.", n: "\"Follow me\" no lleva preposición: nunca digas \"follow to me\".", nEn: "\"Follow me\" takes no preposition: never say \"follow to me\"." },
    "loc-gui03": { e: "This way, please, and mind the step on your right.", t: "Por aquí, por favor, y cuidado con el escalón a su derecha.", s: "Cuando guías al grupo por un lugar con un desnivel o peligro.", sEn: "When you lead the group past an uneven spot or hazard.", n: "\"Mind the step\" es muy común en inglés británico; \"watch your step\" también sirve.", nEn: "\"Mind the step\" is common in British English; \"watch your step\" also works." },
    "loc-gui04": { e: "The city was founded in 1533 by Spanish settlers.", t: "La ciudad fue fundada en 1533 por colonos españoles.", s: "Cuando explicas la historia de un lugar durante el tour.", sEn: "When you explain the history of a place during the tour.", n: "1533 se dice \"fifteen thirty-three\", no \"one thousand five hundred...\".", nEn: "Say 1533 as \"fifteen thirty-three\", not \"one thousand five hundred...\"." },
    "loc-gui05": { e: "We have fifteen minutes for photos, then we'll move on.", t: "Tenemos quince minutos para fotos, luego seguimos.", s: "Cuando das una pausa en un punto bonito del recorrido.", sEn: "When you give a break at a scenic spot on the tour.", n: "Cuida \"fifteen\" (15) vs \"fifty\" (50): el acento va al final en \"fifteen\".", nEn: "Mind \"fifteen\" (15) vs \"fifty\" (50): \"fifteen\" is stressed on the last syllable." },
    "loc-gui06": { e: "Please don't stray from the group, it's easy to get lost here.", t: "No se alejen del grupo, es fácil perderse por aquí.", s: "Cuando el grupo está en un lugar grande o concurrido.", sEn: "When the group is in a large or crowded place.", n: "Una alternativa más simple es \"please stay with the group\".", nEn: "A simpler alternative is \"please stay with the group\"." },
    "loc-gui07": { e: "Let's meet at the bus at three, so please don't be late.", t: "Nos vemos en el bus a las tres, así que por favor no se demoren.", s: "Cuando das tiempo libre y fijas un punto de encuentro.", sEn: "When you give free time and set a meeting point.", n: "\"Let's meet at\" para el lugar y \"at three\" para la hora; no mezcles \"in three\".", nEn: "Use \"meet at\" for the place and \"at three\" for the time; not \"in three\"." },
    "loc-gui08": { e: "Do you have any questions before we continue?", t: "¿Tienen alguna pregunta antes de continuar?", s: "Después de explicar algo, para invitar a preguntar.", sEn: "After explaining something, to invite questions.", n: "\"Any questions?\" solo también funciona y suena natural.", nEn: "\"Any questions?\" on its own also works and sounds natural." },
    "loc-gui09": { e: "Keep your belongings safe, especially in the crowded areas.", t: "Cuiden sus pertenencias, sobre todo en las zonas con mucha gente.", s: "Cuando entran a un lugar lleno de gente o turistas.", sEn: "When you enter a crowded or touristy place.", n: "\"Belongings\" siempre va en plural; no digas \"belonging\".", nEn: "\"Belongings\" is always plural; don't say \"belonging\"." },
    "loc-gui10": { e: "I hope you enjoy the visit, and feel free to take lots of photos.", t: "Espero que disfruten la visita, y tomen muchas fotos sin problema.", s: "Al dejar al grupo explorar por su cuenta un sitio.", sEn: "When you let the group explore a site on their own.", n: "\"Enjoy the visit\" sin \"to\"; \"enjoy\" no lleva infinitivo después.", nEn: "\"Enjoy the visit\" with no \"to\"; \"enjoy\" isn't followed by an infinitive." },
    "loc-gui11": { e: "On your left you'll see the cathedral, one of the oldest in the country.", t: "A su izquierda verán la catedral, una de las más antiguas del país.", s: "Cuando señalas un punto de interés mientras caminan o van en bus.", sEn: "When you point out a landmark as you walk or ride the bus.", n: "Usa \"on your left/right\" para indicar el lado desde el punto de vista del turista.", nEn: "Use \"on your left/right\" to point from the tourist's point of view." },
    "loc-gui12": { e: "Take a photo here, the view of the bay is amazing.", t: "Tomen una foto aquí, la vista de la bahía es increíble.", s: "En un mirador o punto fotogénico del recorrido.", sEn: "At a lookout or photogenic spot on the tour.", n: "\"Take a photo\" es lo natural; \"make a photo\" es un error común.", nEn: "\"Take a photo\" is natural; \"make a photo\" is a common mistake." },
    "loc-gui13": { e: "The tour lasts two hours, so we'll be back before lunch.", t: "El recorrido dura dos horas, así que estaremos de vuelta antes del almuerzo.", s: "Cuando empiezas el tour y el grupo quiere saber cuánto tiempo tomará.", sEn: "When you start the tour and the group wants to know how long it will take.", n: "Di 'lasts' (no 'last') para hablar de duración; suena como 'lasts', con la 'a' corta.", nEn: "Use 'lasts' (with the -s) for duration, and keep the 'a' short." },
    "loc-gui14": { e: "Does anyone need water before we head up the hill?", t: "¿Alguien necesita agua antes de subir la colina?", s: "Cuando revisas si alguien del grupo necesita algo antes de seguir caminando.", sEn: "When you check whether anyone in the group needs something before walking on.", n: "'Anyone' es más natural que 'somebody' para preguntas a un grupo.", nEn: "'Anyone' sounds more natural than 'somebody' when asking a whole group." },
    "loc-gui15": { e: "Please stay together so no one gets lost in the crowd.", t: "Manténganse juntos, por favor, para que nadie se pierda entre la gente.", s: "Al guiar a un grupo por un lugar concurrido durante un tour.", sEn: "When leading a group through a busy place during a tour.", n: "Una variante útil es 'please stay close to me'.", nEn: "A useful variant is 'please stay close to me'." },
    "loc-gui16": { e: "Can everyone hear me okay, or should I speak up?", t: "¿Pueden oírme todos bien, o hablo más fuerte?", s: "Al comenzar una explicación con un grupo grande o ruidoso.", sEn: "When starting an explanation with a large or noisy group.", n: "Añadir 'or should I speak up?' muestra que te importa el grupo.", nEn: "Adding 'or should I speak up?' shows you care about the group." },
    // ===================== Taxi & transport (taxi-en) =====================
    "loc-tax01": { e: "Good evening! Where to?", t: "¡Buenas noches! ¿A dónde lo llevo?", s: "Cuando un pasajero se sube al taxi y le preguntas su destino.", sEn: "When a passenger gets in the taxi and you ask their destination.", n: "'Where to?' es la versión corta y natural de 'Where do you want to go?'.", nEn: "'Where to?' is the short, natural version of 'Where do you want to go?'." },
    "loc-tax02": { e: "Hop in, please, I'll put your bag in the back.", t: "Súbase, por favor, le pongo la maleta atrás.", s: "Cuando invitas al pasajero a subir mientras tú te encargas del equipaje.", sEn: "When you invite the passenger to get in while you handle the luggage.", n: "'Hop in' es amistoso e informal; con clientes muy formales mejor 'Please get in'.", nEn: "'Hop in' is friendly and casual; for very formal clients say 'Please get in'." },
    "loc-tax03": { e: "It's twenty thousand pesos, or you can pay by card.", t: "Son veinte mil pesos, o también puede pagar con tarjeta.", s: "Cuando llegas al destino y le dices al pasajero cuánto debe pagar.", sEn: "When you arrive and tell the passenger how much they owe.", n: "Di 'It's' (no 'It are') aunque sean muchos pesos; el precio total va en singular.", nEn: "Say 'It's' (not 'It are') even for big amounts; a total price stays singular." },
    "loc-tax04": { e: "Are you in a hurry? I can take the highway if you like.", t: "¿Tiene afán? Puedo tomar la autopista si quiere.", s: "Cuando quieres saber si el pasajero necesita llegar rápido para elegir la ruta.", sEn: "When you want to know if the passenger needs to get there fast so you can pick the route.", n: "'Hurry' se dice 'jé-rri'; no pronuncies la 'h' como 'j' fuerte del español.", nEn: "'Hurry' sounds like 'HUH-ree'; don't make the 'h' a hard Spanish 'j'." },
    "loc-tax05": { e: "We'll be there in ten minutes if the traffic stays light.", t: "Llegamos en diez minutos si el tráfico sigue tranquilo.", s: "Cuando el pasajero pregunta cuánto falta y le das un estimado.", sEn: "When the passenger asks how long is left and you give an estimate.", n: "'We'll be there' suena más natural que 'We arrive'; usa 'we'll' para el futuro cercano.", nEn: "'We'll be there' sounds more natural than 'We arrive'; use 'we'll' for the near future." },
    "loc-tax06": { e: "Shall I open the trunk for your suitcases?", t: "¿Le abro el baúl para las maletas?", s: "Cuando ofreces guardar el equipaje del pasajero al inicio del viaje.", sEn: "When you offer to store the passenger's luggage at the start of the trip.", n: "En EE. UU. dicen 'trunk' y en el Reino Unido 'boot'; ambos para el baúl.", nEn: "Americans say 'trunk' and Brits say 'boot' for the car's luggage space." },
    "loc-tax07": { e: "Sorry, I don't have change for a fifty.", t: "Disculpe, no tengo cambio para un billete de cincuenta.", s: "Cuando el pasajero paga con un billete grande y no puedes darle el vuelto.", sEn: "When the passenger pays with a big bill and you can't give change.", n: "'Change' aquí significa vuelto/sencillo; no se usa en plural ('changes').", nEn: "Here 'change' means coins or small bills; it has no plural ('changes')." },
    "loc-tax08": { e: "Here we are. Have a good trip!", t: "Llegamos. ¡Buen viaje!", s: "Cuando dejas al pasajero en su destino y te despides amablemente.", sEn: "When you drop the passenger off and say a friendly goodbye.", n: "Para un vuelo o viaje largo también puedes decir 'Have a safe trip'.", nEn: "For a flight or long journey you can also say 'Have a safe trip'." },
    "loc-tax09": { e: "There's a lot of traffic today, so it might take a little longer.", t: "Hay mucho tráfico hoy, así que puede demorar un poco más.", s: "Cuando avisas al pasajero que el viaje será más lento por el tráfico.", sEn: "When you warn the passenger the ride will be slower because of traffic.", n: "'Traffic' es incontable: di 'a lot of traffic', nunca 'many traffics'.", nEn: "'Traffic' is uncountable: say 'a lot of traffic', never 'many traffics'." },
    "loc-tax10": { e: "Can I help with your bags? They look heavy.", t: "¿Le ayudo con las maletas? Se ven pesadas.", s: "Cuando ofreces cargar el equipaje del pasajero al subir o bajar.", sEn: "When you offer to carry the passenger's luggage getting in or out.", n: "'Bags' y 'luggage' sirven; 'luggage' es incontable y no lleva 's'.", nEn: "Both 'bags' and 'luggage' work, but 'luggage' is uncountable and takes no 's'." },
    "loc-tax11": { e: "Please put on your seatbelt, it's the law here.", t: "Póngase el cinturón, por favor, aquí es obligatorio por ley.", s: "Justo antes de arrancar con un pasajero en el taxi.", sEn: "Right before starting to drive with a passenger in the taxi.", n: "Es más cortés que el imperativo seco 'put your seatbelt'.", nEn: "It's more polite than the blunt command 'put your seatbelt'." },
    "loc-tax12": { e: "Do you mind the air conditioning, or should I turn it down?", t: "¿Le molesta el aire acondicionado, o lo bajo un poco?", s: "Cuando notas que el pasajero podría tener frío en el carro.", sEn: "When you notice the passenger might be cold in the car.", n: "Ojo: 'Do you mind?' significa lo contrario; 'yes' quiere decir que sí molesta.", nEn: "Careful: with 'Do you mind?' a 'yes' means it does bother them." },
    "loc-tax13": { e: "We're almost there, just a couple more blocks.", t: "Ya casi llegamos, solo un par de cuadras más.", s: "Para tranquilizar a un pasajero apurado cuando falta poco.", sEn: "To reassure a passenger in a hurry when you're close.", n: "'almost' se pronuncia 'ólmoust', no 'almost' con la 'l' marcada como en español.", nEn: "'Almost' sounds like 'awl-most'; keep the 'l' soft." },
    "loc-tax14": { e: "Is here okay for you, or would you like me to go a bit further?", t: "¿Le parece bien por aquí, o prefiere que avance un poco más?", s: "Al acercarte al destino para confirmar dónde dejar al pasajero.", sEn: "When approaching the destination to confirm where to drop off.", n: "Puedes decir 'right here?' como versión más corta y casual.", nEn: "You can say 'right here?' as a shorter, more casual version." },
    // ===================== Sales & market (ventas) =====================
    "loc-ven01": { e: "Hi there! How can I help you today?", t: "¡Hola! ¿En qué le puedo ayudar hoy?", s: "Cuando un cliente entra a tu puesto o tienda y lo saludas.", sEn: "When a customer comes into your stall or shop and you greet them.", n: "'How can I help you?' es más amable que 'What do you want?'.", nEn: "'How can I help you?' sounds warmer than 'What do you want?'." },
    "loc-ven02": { e: "If you take two, I'll give you a discount.", t: "Si lleva dos, le hago un descuento.", s: "Cuando quieres cerrar la venta ofreciendo un mejor precio.", sEn: "When you want to close the sale by offering a better price.", n: "Di 'a discount'; el artículo 'a' no se omite como en español.", nEn: "Say 'a discount'; English keeps the article 'a' that Spanish drops." },
    "loc-ven03": { e: "It's handmade, so each piece is a little different.", t: "Es hecho a mano, por eso cada pieza es un poco diferente.", s: "Cuando explicas a un turista por qué tu producto es especial y vale más.", sEn: "When you explain to a tourist why your product is special and worth more.", n: "'Handmade' es una sola palabra; no digas 'hand made' separado.", nEn: "'Handmade' is one word; don't write it as two ('hand made')." },
    "loc-ven04": { e: "What size are you looking for? We have small to extra large.", t: "¿Qué talla busca? Tenemos desde pequeña hasta extra grande.", s: "Cuando un cliente mira la ropa y le ayudas a encontrar su talla.", sEn: "When a customer is browsing clothes and you help find their size.", n: "Para zapatos usa la misma frase; 'size' sirve para talla y número.", nEn: "Use the same phrase for shoes; 'size' covers clothing and shoe sizes." },
    "loc-ven05": { e: "Cash only, please, the card machine isn't working today.", t: "Solo efectivo, por favor, hoy no funciona el datáfono.", s: "Cuando un cliente quiere pagar con tarjeta pero solo aceptas efectivo.", sEn: "When a customer wants to pay by card but you only take cash.", n: "'Cash' suena 'cash'; evita decir 'cesh', la 'a' es abierta como en 'gato'.", nEn: "'Cash' has an open 'a' like in 'cat'; don't say 'cesh'." },
    "loc-ven06": { e: "Shall I wrap it for you? It's a nice gift.", t: "¿Se lo envuelvo? Es un buen regalo.", s: "Cuando el cliente compra algo y le ofreces envolverlo, sobre todo si es regalo.", sEn: "When the customer buys something and you offer to wrap it, especially as a gift.", n: "La 'w' de 'wrap' es muda; se dice 'rap', igual que la música.", nEn: "The 'w' in 'wrap' is silent; it sounds just like 'rap'." },
    "loc-ven07": { e: "It's the last one, so I can't really lower the price.", t: "Es el último que queda, así que no puedo bajar mucho el precio.", s: "Cuando el cliente regatea y tú justificas el precio porque queda solo uno.", sEn: "When a customer haggles and you justify the price because only one is left.", n: "'The last one' lleva 'one' al final; sin él suena incompleto en inglés.", nEn: "'The last one' needs 'one' at the end; leaving it out sounds incomplete." },
    "loc-ven08": { e: "Thank you so much! Come back soon!", t: "¡Muchas gracias! ¡Vuelva pronto!", s: "Cuando te despides de un cliente después de una venta.", sEn: "When you say goodbye to a customer after a sale.", n: "'Come back soon' es cálido e informal; con clientes formales usa 'We hope to see you again'.", nEn: "'Come back soon' is warm and casual; for formal clients use 'We hope to see you again'." },
    "loc-ven09": { e: "Would you like to try it? The fitting room is right behind you.", t: "¿Quiere probarlo? El probador está justo detrás de usted.", s: "Cuando un cliente mira una prenda en tu tienda y dudas si quiere medírsela.", sEn: "When a customer is eyeing a piece of clothing and you want to invite them to try it.", n: "Para comida usa \"try\" igual, pero para ropa también puedes decir \"try it on\".", nEn: "For food just say \"try it,\" but for clothing you can also say \"try it on.\"" },
    "loc-ven10": { e: "We have more colors if that one isn't quite what you want.", t: "Tenemos más colores por si ese no es justo lo que busca.", s: "Cuando el cliente parece dudar del color del producto que tiene en la mano.", sEn: "When a customer seems unsure about the color of the item they're holding.", n: "En inglés \"colors\" no lleva la \"u\" que sí tiene el inglés británico (\"colours\").", nEn: "In US spelling it's \"colors\"; British English adds a \"u\" (\"colours\")." },
    "loc-ven11": { e: "Come in, we're open, feel free to look around.", t: "Pase, está abierto, mire con confianza.", s: "Al invitar a un cliente que duda en la puerta de tu local.", sEn: "When inviting a customer who is hesitating at your shop door.", n: "Añadir 'feel free to look around' quita la presión de comprar.", nEn: "Adding 'feel free to look around' takes the pressure off buying." },
    "loc-ven12": { e: "That looks great on you, the color really suits you.", t: "Le queda muy bien, el color realmente le favorece.", s: "Cuando un cliente se prueba algo y le sienta bien.", sEn: "When a customer tries something on and it fits well.", n: "Para ropa di 'looks great on you', no 'fits you good'.", nEn: "For clothes say 'looks great on you', not 'fits you good'." },
    "loc-ven13": { e: "Is it a gift? I can wrap it nicely for you.", t: "¿Es para regalo? Se lo puedo envolver bonito.", s: "Al cobrar, cuando crees que el artículo puede ser un obsequio.", sEn: "At checkout, when you think the item might be a gift.", n: "Ofrecer envolver después suena atento y aumenta la venta.", nEn: "Offering to wrap it afterward sounds attentive and boosts the sale." },
    "loc-ven14": { e: "We offer home delivery, so we can bring it right to your door.", t: "Tenemos envío a domicilio, así que se lo llevamos hasta la puerta.", s: "Cuando un cliente compra algo grande o pesado.", sEn: "When a customer buys something large or heavy.", n: "'delivery' se pronuncia 'dilíveri', con el acento en la segunda sílaba.", nEn: "'Delivery' is stressed on the second syllable: di-LIV-er-y." },
    // ===================== Greetings & chat (saludos-en) =====================
    "loc-sal01": { e: "Good to see you! How are you today?", t: "¡Qué bueno verte! ¿Cómo estás hoy?", s: "Cuando saludas a un cliente o compañero al empezar la conversación.", sEn: "When you greet a customer or coworker as the conversation begins.", n: "La respuesta corta más natural es \"I'm good, thanks. And you?\"", nEn: "The most natural short reply is \"I'm good, thanks. And you?\"" },
    "loc-sal02": { e: "Nice to meet you, I'm Carlos, your guide for today.", t: "Mucho gusto, soy Carlos, su guía de hoy.", s: "Cuando conoces a alguien por primera vez y te presentas.", sEn: "When you meet someone for the first time and introduce yourself.", n: "Solo se usa la primera vez; al despedirte di \"Nice meeting you.\"", nEn: "Use it only the first time; when saying goodbye say \"Nice meeting you.\"" },
    "loc-sal03": { e: "Where are you from? We get a lot of visitors from Canada.", t: "¿De dónde eres? Recibimos muchos visitantes de Canadá.", s: "Cuando charlas con un turista y quieres conocer su país de origen.", sEn: "When chatting with a tourist and you want to know their home country.", n: "Suena más amable añadir un comentario después en vez de solo preguntar.", nEn: "It sounds friendlier to add a small comment afterward rather than just asking." },
    "loc-sal04": { e: "So what do you do? Are you here for work or vacation?", t: "Y, ¿a qué te dedicas? ¿Estás aquí por trabajo o de vacaciones?", s: "Cuando conversas con un huésped y quieres saber su profesión.", sEn: "When chatting with a guest and you want to know their profession.", n: "\"What do you do?\" significa el trabajo; \"What are you doing?\" es ahora mismo.", nEn: "\"What do you do?\" asks about your job; \"What are you doing?\" means right now." },
    "loc-sal05": { e: "Thanks for stopping by. Have a nice day!", t: "Gracias por venir. ¡Que tengas un buen día!", s: "Cuando un cliente se va y quieres despedirte con calidez.", sEn: "When a customer leaves and you want to send them off warmly.", n: "Variante igual de común y un poco más cálida: \"Have a great day!\"", nEn: "An equally common, slightly warmer variant is \"Have a great day!\"" },
    "loc-sal06": { e: "See you later, take care on the road!", t: "¡Nos vemos luego, cuídate en el camino!", s: "Cuando te despides de alguien que volverás a ver pronto.", sEn: "When saying bye to someone you'll see again soon.", n: "Más informal aún: \"See ya!\"; en lo profesional mejor \"See you soon.\"", nEn: "More casual: \"See ya!\"; in professional settings use \"See you soon.\"" },
    "loc-sal07": { e: "Sorry, can you repeat that, please? It's a little noisy in here.", t: "Perdón, ¿puedes repetir, por favor? Hay un poco de ruido aquí.", s: "Cuando no escuchaste bien y necesitas que el cliente repita.", sEn: "When you didn't catch something and need the customer to repeat it.", n: "Más formal: \"Could you repeat that, please?\"; \"could\" suena más cortés.", nEn: "More formal: \"Could you repeat that, please?\"; \"could\" sounds more polite." },
    "loc-sal08": { e: "I'm sorry, I don't understand. Could you say it another way?", t: "Disculpe, no entiendo. ¿Podría decirlo de otra forma?", s: "Cuando no comprendes lo que pidió el cliente y necesitas aclararlo.", sEn: "When you can't grasp what the customer asked and need it clarified.", n: "Evita \"I don't understand you\"; suena a culpar a la persona.", nEn: "Avoid \"I don't understand you\"; it can sound like you're blaming them." },
    "loc-sal09": { e: "Good morning! Welcome, how can I help you today?", t: "¡Buenos días! Bienvenido, ¿en qué le puedo ayudar hoy?", s: "Cuando saludas a alguien por la mañana al llegar a tu negocio.", sEn: "When you greet someone in the morning as they arrive at your business.", n: "Después del mediodía usa \"Good afternoon\" y tras las seis \"Good evening.\"", nEn: "After noon say \"Good afternoon,\" and after six say \"Good evening.\"" },
    "loc-sal10": { e: "Hi again! How's your day going so far?", t: "¡Hola de nuevo! ¿Qué tal va tu día hasta ahora?", s: "Cuando saludas con confianza a un cliente habitual o compañero.", sEn: "When greeting a regular customer or coworker in a friendly way.", n: "\"How's your day?\" es informal; con clientes nuevos usa \"How are you?\"", nEn: "\"How's your day?\" is casual; with new customers prefer \"How are you?\"" },
    "loc-sal11": { e: "Pleased to meet you, I've heard great things about your work.", t: "Encantado de conocerte, he oído cosas muy buenas de tu trabajo.", s: "Cuando conoces a alguien en un contexto formal o de negocios.", sEn: "When meeting someone in a formal or business setting.", n: "\"Pleased to meet you\" es más formal que \"Nice to meet you.\"", nEn: "\"Pleased to meet you\" is more formal than \"Nice to meet you.\"" },
    "loc-sal12": { e: "Thanks for everything. Take care, and travel safe!", t: "Gracias por todo. ¡Cuídate y buen viaje!", s: "Cuando te despides de alguien deseándole bienestar.", sEn: "When you say goodbye and wish someone well.", n: "Cuida la pronunciación: \"care\" suena \"ker\", no \"car\".", nEn: "Watch the pronunciation: \"care\" sounds like \"ker,\" not \"car.\"" },
    "loc-sal13": { e: "Hi, what's your name? I'll be your guide today.", t: "Hola, ¿cómo te llamas? Seré tu guía hoy.", s: "Cuando conoces a un cliente o compañero nuevo y quieres presentarte.", sEn: "When you meet a new customer or coworker and want to introduce yourself.", n: "\"What's your name?\" es informal; en contextos muy formales di \"May I have your name?\".", nEn: "\"What's your name?\" is informal; in very formal contexts say \"May I have your name?\"" },
    "loc-sal14": { e: "Nice to meet you too. Likewise!", t: "Mucho gusto a ti también. ¡Igualmente!", s: "Cuando respondes a alguien que acaba de decir que le da gusto conocerte.", sEn: "When you reply to someone who just said it was nice to meet you.", n: "\"Likewise\" es una forma corta y educada de decir \"igualmente\" en un saludo.", nEn: "\"Likewise\" is a short, polite way to say \"same to you\" in a greeting." },
    // ===================== On the phone (telefono) =====================
    "loc-tel01": { e: "Good morning, may I ask who's calling?", t: "Buenos días, ¿me permite saber quién habla?", s: "Cuando contestas el teléfono y quieres saber quién es la persona.", sEn: "When you answer the phone and want to know who is on the line.", n: "Más cortés: \"May I ask who's calling?\" en vez de solo \"Who's calling?\"", nEn: "More polite: \"May I ask who's calling?\" instead of just \"Who's calling?\"" },
    "loc-tel02": { e: "One moment, please, I'll check that for you.", t: "Un momento, por favor, se lo reviso.", s: "Cuando necesitas que el cliente espere mientras buscas algo.", sEn: "When you need the caller to wait while you look something up.", n: "Equivalente natural: \"Just a moment\" o \"Hold on a second, please.\"", nEn: "Natural equivalents: \"Just a moment\" or \"Hold on a second, please.\"" },
    "loc-tel03": { e: "She's not in right now. Can I leave a message?", t: "Ella no está ahora. ¿Puedo dejar un mensaje?", s: "Cuando la persona que buscas no está y quieres dejarle un recado.", sEn: "When the person you want isn't available and you'd like to leave a note.", n: "Si tú recibes la llamada, ofrece: \"Would you like to leave a message?\"", nEn: "If you're the one answering, offer: \"Would you like to leave a message?\"" },
    "loc-tel04": { e: "I'll call you back in ten minutes with the details.", t: "Le devuelvo la llamada en diez minutos con los detalles.", s: "Cuando no puedes atender ahora pero prometes volver a llamar.", sEn: "When you can't deal with it now but promise to phone again.", n: "\"Call back\" es por teléfono; para escribir di \"I'll get back to you.\"", nEn: "\"Call back\" is by phone; for writing say \"I'll get back to you.\"" },
    "loc-tel05": { e: "Can you hear me okay? The line sounds a little weak.", t: "¿Me escucha bien? La línea suena un poco débil.", s: "Cuando la llamada se oye mal y quieres confirmar que te escuchan.", sEn: "When the call sounds bad and you want to confirm they can hear you.", n: "\"Hear\" suena \"hir\" (largo), no como \"here\" aunque se escriban parecido.", nEn: "\"Hear\" sounds like \"hir\"; it's a homophone of \"here\" but means to listen." },
    "loc-tel06": { e: "I'm sorry, I think you have the wrong number.", t: "Disculpe, creo que marcó el número equivocado.", s: "Cuando alguien llama buscando a una persona o lugar que no es.", sEn: "When someone calls asking for a person or place that isn't yours.", n: "Suaviza con \"I think\" antes para no sonar brusco al corregir.", nEn: "Soften it with \"I think\" first so the correction doesn't sound blunt." },
    "loc-tel07": { e: "Good morning, thank you for calling. Who would you like to speak to?", t: "Buenos días, gracias por llamar. ¿Con quién desea hablar?", s: "Cuando contestas el teléfono y necesitas saber a qué persona busca quien llama.", sEn: "When you answer the phone and need to know which person the caller is looking for.", n: "Más formal: \"May I ask who you'd like to speak to?\"; evita el directo \"Who do you want?\".", nEn: "More formal: \"May I ask who you'd like to speak to?\"; avoid the blunt \"Who do you want?\"" },
    "loc-tel08": { e: "Thanks for calling, and please don't hesitate to reach out again.", t: "Gracias por llamar, y no dude en contactarnos de nuevo.", s: "Al cerrar una llamada con un cliente para despedirte de forma amable.", sEn: "When closing a call with a customer to say goodbye politely.", n: "Puedes añadir \"have a great day\" al final para sonar más cálido.", nEn: "You can add \"have a great day\" at the end to sound warmer." },
    "loc-tel09": { e: "I'm sorry, could you speak more slowly? The line isn't very clear.", t: "Disculpe, ¿puede hablar más despacio? La línea no está muy clara.", s: "Cuando la persona habla rápido por teléfono y no logras entender.", sEn: "When the person is speaking fast on the phone and you can't follow.", n: "Pronuncia \"slowly\" como \"SLOU-li\"; empieza con \"sorry\" para sonar cortés.", nEn: "Pronounce \"slowly\" as \"SLOH-lee\"; start with \"sorry\" to sound polite." },
    "loc-tel10": { e: "One moment, please. I'll put you through to a colleague who can help.", t: "Un momento, por favor. Le paso con un compañero que puede ayudarle.", s: "Cuando no puedes resolver tú la consulta y transfieres la llamada a otra persona.", sEn: "When you can't handle the request yourself and transfer the call to someone else.", n: "\"Put through\" es muy británico; en EE. UU. se dice más \"transfer you to\".", nEn: "\"Put through\" is very British; in the US people more often say \"transfer you to\"." },
    "loc-tel11": { e: "Can I have your name, please, so I can pull up your booking?", t: "¿Me puede dar su nombre, por favor, para buscar su reserva?", s: "Cuando contestas el teléfono y necesitas identificar al cliente antes de ayudarlo.", sEn: "When you answer the phone and need to identify the caller before helping them.", n: "Agregar \"please\" suena más cortés que solo \"Can I have your name?\".", nEn: "Adding \"please\" sounds more polite than just \"Can I have your name?\"." },
    "loc-tel12": { e: "Please hold the line while I check that for you.", t: "Por favor, espere en línea mientras lo reviso.", s: "Cuando necesitas dejar al cliente en espera para buscar información.", sEn: "When you need to put the caller on hold to look something up.", n: "También puedes decir \"Can you hold for a moment?\" para sonar más suave.", nEn: "You can also say \"Can you hold for a moment?\" to sound softer." },
    "loc-tel13": { e: "I'll connect you now; please stay on the line.", t: "Lo comunico ahora mismo; por favor, no cuelgue.", s: "Cuando vas a pasar la llamada del cliente a la persona correcta.", sEn: "When you're about to transfer the caller to the right person.", n: "\"Put you through\" es una variante muy común: \"I'll put you through now.\"", nEn: "\"Put you through\" is a very common variant: \"I'll put you through now.\"" },
    "loc-tel14": { e: "Can you leave your number and I'll call you back?", t: "¿Me deja su número y yo le devuelvo la llamada?", s: "Cuando la persona que buscan no está y quieres tomar un recado.", sEn: "When the person they want isn't available and you want to take a message.", n: "Repite el número en voz alta para confirmarlo y evitar errores.", nEn: "Repeat the number back out loud to confirm it and avoid mistakes." },
    // ===================== Giving directions (direcciones) =====================
    "loc-dir01": { e: "Go straight ahead for two blocks and you'll see it on your right.", t: "Siga derecho dos cuadras y lo verá a su derecha.", s: "Cuando alguien te pregunta por una dirección y el lugar está de frente.", sEn: "When someone asks you for directions and the place is straight ahead.", n: "\"Straight\" suena \"streit\", no \"es-traight\"; no le pongas la \"e\" al inicio.", nEn: "\"Straight\" sounds like \"strayt\", not \"es-traight\"; don't add an \"e\" at the start." },
    "loc-dir02": { e: "Turn left at the traffic light and the hotel is right there.", t: "Gire a la izquierda en el semáforo y el hotel está justo ahí.", s: "Cuando indicas a alguien que doble a la izquierda para llegar a un lugar.", sEn: "When you tell someone to turn left to reach a place.", n: "Acompaña la frase con un gesto de la mano; ayuda mucho si hay duda.", nEn: "Pair the phrase with a hand gesture; it helps a lot if there's any doubt." },
    "loc-dir03": { e: "Turn right after the bank and the entrance is just ahead.", t: "Gire a la derecha después del banco y la entrada está justo adelante.", s: "Cuando le explicas a alguien que debe doblar a la derecha en su recorrido.", sEn: "When you explain to someone that they need to turn right on their way.", n: "No confundas \"right\" (derecha) con \"left\"; señala con la mano para evitar errores.", nEn: "Don't mix up \"right\" with \"left\"; point with your hand to avoid mistakes." },
    "loc-dir04": { e: "Don't worry, it's only two blocks away, a five-minute walk.", t: "No se preocupe, está a solo dos cuadras, una caminata de cinco minutos.", s: "Cuando indicas qué tan cerca está un lugar contando cuadras.", sEn: "When you indicate how close a place is by counting blocks.", n: "En inglés británico se dice \"two streets away\"; \"blocks\" es más de EE. UU.", nEn: "In British English people say \"two streets away\"; \"blocks\" is more American." },
    "loc-dir05": { e: "The pharmacy is next to the bank, you can't miss it.", t: "La farmacia está al lado del banco, no tiene pérdida.", s: "Cuando ubicas un sitio usando un negocio conocido como referencia.", sEn: "When you locate a place using a well-known business as a reference.", n: "\"You can't miss it\" es la coletilla natural para decir que es fácil de encontrar.", nEn: "\"You can't miss it\" is the natural tag to say it's easy to find." },
    "loc-dir06": { e: "Excuse me, is the market far from here, or can I walk?", t: "Disculpe, ¿está lejos el mercado de aquí, o puedo ir caminando?", s: "Cuando preguntas por la distancia a un lugar antes de decidir cómo llegar.", sEn: "When you ask how far a place is before deciding how to get there.", n: "Para responder corto: \"Not really\" (no mucho) o \"Yes, quite far\".", nEn: "For a short reply: \"Not really\" (not much) or \"Yes, quite far\"." },
    "loc-dir07": { e: "Cross the street here and the bus stop is on the other side.", t: "Cruce la calle aquí y el paradero está al otro lado.", s: "Cuando le dices a alguien que pase al otro lado de la calle para continuar.", sEn: "When you tell someone to go to the other side of the street to continue.", n: "\"Cross\" lleva una sola sílaba; no digas \"croses\" para el imperativo.", nEn: "\"Cross\" is one syllable; don't say \"croses\" for the command form." },
    "loc-dir08": { e: "The café is on the corner, right where those two streets meet.", t: "El café está en la esquina, justo donde se cruzan esas dos calles.", s: "Cuando señalas que un lugar queda exactamente en una esquina.", sEn: "When you point out that a place is exactly on a corner.", n: "Se dice \"on the corner\", no \"in the corner\" (eso es un rincón cerrado).", nEn: "Say \"on the corner\", not \"in the corner\" (that means an inside nook)." },
    "loc-dir09": { e: "Good news, it's nearby, just around the corner from the plaza.", t: "Buena noticia, está cerca, a la vuelta de la esquina de la plaza.", s: "Cuando tranquilizas a alguien diciéndole que el destino está cerca.", sEn: "When you reassure someone that the destination is close.", n: "\"Nearby\" y \"close by\" significan lo mismo; ambos suenan naturales.", nEn: "\"Nearby\" and \"close by\" mean the same thing; both sound natural." },
    "loc-dir10": { e: "Take the second turn on your left and the parking is right there.", t: "Tome el segundo giro a su izquierda y el parqueadero está justo ahí.", s: "Cuando guías a un conductor o peatón a tomar un giro específico.", sEn: "When you guide a driver or pedestrian to take a specific turn.", n: "Más común para autos: \"take the second left\"; \"turn\" sirve también a pie.", nEn: "More common for cars: \"take the second left\"; \"turn\" also works on foot." },
    "loc-dir11": { e: "The pharmacy is right across from the church, you can't miss it.", t: "La farmacia está justo frente a la iglesia, no tiene pierde.", s: "Cuando un turista te pregunta dónde queda un lugar cercano.", sEn: "When a tourist asks you where a nearby place is.", n: "\"Across from\" es lo mismo que \"opposite\"; ambos sirven para \"frente a\".", nEn: "\"Across from\" means the same as \"opposite\"; both work for \"frente a\"." },
    "loc-dir12": { e: "Just walk for five minutes and it'll be on your right.", t: "Solo camine cinco minutos y lo verá a su derecha.", s: "Cuando indicas cuánto debe caminar la persona para llegar.", sEn: "When you tell someone how long to walk to get there.", n: "Puedes decir \"a five-minute walk\" como forma corta: \"It's a five-minute walk.\"", nEn: "You can say \"a five-minute walk\" as a short form: \"It's a five-minute walk.\"" },
    "loc-dir13": { e: "Go up this street and turn left at the corner.", t: "Suba por esta calle y gire a la izquierda en la esquina.", s: "Cuando das direcciones e indicas seguir por una calle en subida.", sEn: "When giving directions and telling someone to head up a street.", n: "Si la calle no sube, usa mejor \"go down this street\" o \"go along this street\".", nEn: "If the street doesn't go uphill, use \"go down this street\" or \"go along this street\" instead." },
    "loc-dir14": { e: "It's right there, just past the blue door.", t: "Está justo ahí, pasando la puerta azul.", s: "Cuando el lugar está muy cerca y casi puedes señalarlo.", sEn: "When the place is very close and you can almost point at it.", n: "\"Right\" aquí significa \"justo\", no \"derecha\"; el contexto lo aclara.", nEn: "\"Right\" here means \"exactly/just\", not the direction; context makes it clear." },
    // ===================== Job interview (entrevista) =====================
    "loc-ent01": { e: "I have experience in customer service, mostly at hotels and restaurants.", t: "Tengo experiencia en servicio al cliente, sobre todo en hoteles y restaurantes.", s: "Cuando te presentas en una entrevista y resaltas tu experiencia.", sEn: "When you introduce yourself in an interview and highlight your experience.", n: "Se dice \"experience in\" (no \"experience of\") para hablar de un campo.", nEn: "Say \"experience in\" (not \"experience of\") when talking about a field." },
    "loc-ent02": { e: "I speak basic English, but I'm practicing every day to improve.", t: "Hablo inglés básico, pero practico todos los días para mejorar.", s: "Cuando el entrevistador pregunta por tu nivel de inglés y eres honesto.", sEn: "When the interviewer asks about your English level and you're honest.", n: "Agregar \"but I'm improving\" da una impresión positiva y proactiva.", nEn: "Adding \"but I'm improving\" gives a positive, proactive impression." },
    "loc-ent03": { e: "I'm punctual and responsible, and I always show up on time.", t: "Soy puntual y responsable, y siempre llego a tiempo.", s: "Cuando describes tus cualidades personales en una entrevista de trabajo.", sEn: "When you describe your personal qualities in a job interview.", n: "\"Punctual\" se pronuncia \"PANK-chual\"; respáldalo con un ejemplo concreto.", nEn: "\"Punctual\" is pronounced \"PUNK-chual\"; back it up with a concrete example." },
    "loc-ent04": { e: "Could you tell me what the hours are for this position?", t: "¿Me podría decir cuál es el horario para este puesto?", s: "Cuando preguntas en la entrevista por la jornada laboral del puesto.", sEn: "When you ask in the interview about the work schedule for the job.", n: "\"Hours\" en plural es lo natural para el horario; \"schedule\" también sirve.", nEn: "Plural \"hours\" is natural for the schedule; \"schedule\" also works." },
    "loc-ent05": { e: "If you choose me, I can start right away, even this week.", t: "Si me eligen, puedo empezar de inmediato, incluso esta semana.", s: "Cuando muestras disponibilidad inmediata al final de la entrevista.", sEn: "When you show immediate availability at the end of the interview.", n: "\"Right away\" y \"immediately\" sirven igual; el primero suena más natural.", nEn: "\"Right away\" and \"immediately\" work the same; the first sounds more natural." },
    "loc-ent06": { e: "I worked at a hotel for two years, mainly at the front desk.", t: "Trabajé dos años en un hotel, principalmente en la recepción.", s: "Cuando cuentas tu experiencia laboral previa en una entrevista.", sEn: "When you describe your previous work experience in an interview.", n: "Usa \"worked\" (pasado) para empleos terminados; \"work\" sería el presente.", nEn: "Use \"worked\" (past) for finished jobs; \"work\" would be the present." },
    "loc-ent07": { e: "Thank you for the opportunity, I really enjoyed meeting the team today.", t: "Gracias por la oportunidad, de verdad disfruté conocer al equipo hoy.", s: "Al terminar la entrevista, cuando te despides del entrevistador.", sEn: "At the end of the interview, when you say goodbye to the interviewer.", n: "Da un apretón de manos firme y sonríe al decirlo para dejar buena impresión.", nEn: "Give a firm handshake and smile as you say it to leave a good impression." },
    "loc-ent08": { e: "Thank you so much, when will I hear back about the position?", t: "Muchas gracias, ¿cuándo me darían respuesta sobre el puesto?", s: "Al cerrar la entrevista, cuando quieres saber los próximos pasos.", sEn: "When wrapping up the interview and you want to know the next steps.", n: "\"Hear back\" suena más natural que \"have an answer\"; pronuncia la 'h' de \"hear\".", nEn: "\"Hear back\" sounds more natural than \"have an answer\"; pronounce the 'h' in \"hear\"." },
    "loc-ent09": { e: "I like working in a team and I think I get along well with people.", t: "Me gusta trabajar en equipo y creo que me llevo bien con la gente.", s: "Cuando te preguntan por tus fortalezas o tu estilo de trabajo.", sEn: "When they ask about your strengths or your work style.", n: "Se dice \"in a team\", no \"in team\"; no olvides el artículo \"a\".", nEn: "Say \"in a team\", not \"in team\"; don't drop the article \"a\"." },
    "loc-ent10": { e: "Don't worry, I learn quickly and I'm not afraid to ask questions.", t: "No se preocupe, aprendo rápido y no me da miedo preguntar.", s: "Cuando el puesto requiere algo nuevo que aún no dominas.", sEn: "When the job needs something new that you haven't mastered yet.", n: "También puedes decir \"I'm a fast learner\", que suena muy natural en inglés.", nEn: "You can also say \"I'm a fast learner\", which sounds very natural in English." },
    "loc-ent11": { e: "I'm available on weekends and I can also cover evening shifts.", t: "Estoy disponible los fines de semana y también puedo cubrir turnos de noche.", s: "Cuando hablan de horarios y quieres mostrar flexibilidad.", sEn: "When they discuss the schedule and you want to show flexibility.", n: "Se usa \"on weekends\", con \"on\", no \"in weekends\".", nEn: "Use \"on weekends\", with \"on\", not \"in weekends\"." },
    "loc-ent12": { e: "That sounds great, so when do I start?", t: "Suena genial, entonces ¿cuándo empiezo?", s: "Cuando ya te ofrecieron el trabajo y quieres confirmar la fecha.", sEn: "When they've already offered you the job and you want to confirm the date.", n: "Usa \"start\", no \"begin\", que suena más formal y menos común aquí.", nEn: "Use \"start\", not \"begin\", which sounds more formal and less common here." },
    "loc-ent13": { e: "May I ask what the salary is for this position?", t: "¿Puedo preguntar cuál es el salario de este puesto?", s: "Cuando en una entrevista quieres saber cuánto pagan por el trabajo.", sEn: "When in an interview you want to know how much the job pays.", n: "Suena más profesional empezar con \"May I ask...\" en vez de preguntar directo.", nEn: "Starting with \"May I ask...\" sounds more professional than asking bluntly." },
    "loc-ent14": { e: "I have good references from my last two jobs.", t: "Tengo buenas referencias de mis dos últimos trabajos.", s: "Cuando en la entrevista mencionas que otros pueden recomendarte.", sEn: "When in the interview you mention that others can vouch for you.", n: "Ofrece: \"I can provide their contact details\" para sonar más seguro.", nEn: "Offer: \"I can provide their contact details\" to sound more confident." },
    // ===================== Office & emails (oficina) =====================
    "loc-ofi01": { e: "No problem, I'll send you the email right away with all the details.", t: "No hay problema, le envío el correo enseguida con todos los detalles.", s: "Cuando un cliente o colega te pide información por correo.", sEn: "When a client or colleague asks you for information by email.", n: "\"Right away\" significa \"enseguida\"; también sirve \"right now\".", nEn: "\"Right away\" means \"enseguida\"; \"right now\" works too." },
    "loc-ofi02": { e: "Thank you for your time; I look forward to your reply.", t: "Gracias por su tiempo; quedo atento a su respuesta.", s: "Para cerrar un correo formal de manera cortés.", sEn: "To close a formal email politely.", n: "Después de \"look forward to\" siempre va sustantivo o verbo en -ing, no infinitivo.", nEn: "After \"look forward to\" always use a noun or -ing verb, never the infinitive." },
    "loc-ofi03": { e: "Can we schedule a meeting for sometime next week?", t: "¿Podemos agendar una reunión para algún día de la próxima semana?", s: "Cuando necesitas coordinar una cita de trabajo con alguien.", sEn: "When you need to arrange a work appointment with someone.", n: "\"Schedule\" se pronuncia \"SKE-dyul\" (US) o \"SHE-dyul\" (UK), no \"esquedule\".", nEn: "\"Schedule\" is pronounced \"SKE-dyul\" (US) or \"SHE-dyul\" (UK), not \"esquedule\"." },
    "loc-ofi04": { e: "I'm attaching the document so you can review it before the call.", t: "Adjunto el documento para que lo pueda revisar antes de la llamada.", s: "Cuando envías un archivo junto con un correo.", sEn: "When you send a file along with an email.", n: "Se dice \"attaching\", no \"attaching to\"; el archivo es el objeto directo.", nEn: "Say \"attaching the document\", not \"attaching to\"; the file is the direct object." },
    "loc-ofi05": { e: "Sorry for the late reply, things have been very busy this week.", t: "Disculpe la demora en responder, ha sido una semana muy ocupada.", s: "Cuando respondes un correo varios días después de recibirlo.", sEn: "When you answer an email several days after receiving it.", n: "Más formal: \"I apologize for the delayed response\".", nEn: "More formal: \"I apologize for the delayed response\"." },
    "loc-ofi06": { e: "I agree, I think that's the best way to handle it.", t: "Estoy de acuerdo, creo que esa es la mejor manera de manejarlo.", s: "Cuando apoyas la propuesta de un colega en una conversación.", sEn: "When you support a colleague's proposal in a conversation.", n: "Se dice \"I agree\", nunca \"I am agree\"; es un verbo, no un adjetivo.", nEn: "Say \"I agree\", never \"I am agree\"; it's a verb, not an adjective." },
    "loc-ofi07": { e: "Sorry, could you explain that again? I didn't quite catch it.", t: "Disculpe, ¿me puede explicar de nuevo? No lo capté bien.", s: "Cuando no entendiste una instrucción y necesitas aclaración.", sEn: "When you didn't understand an instruction and need clarification.", n: "\"Could you\" es más cortés que \"can you\" para pedir algo.", nEn: "\"Could you\" is more polite than \"can you\" when asking for something." },
    "loc-ofi08": { e: "It's getting late, let's talk tomorrow when we're both fresh.", t: "Se está haciendo tarde, hablamos mañana que estemos descansados.", s: "Para terminar una conversación de trabajo y posponerla un día.", sEn: "To end a work conversation and put it off until the next day.", n: "También puedes decir \"let's catch up tomorrow\" en un tono más relajado.", nEn: "You can also say \"let's catch up tomorrow\" for a more relaxed tone." },
    "loc-ofi09": { e: "Hi, just checking, did you get my email from this morning?", t: "Hola, solo confirmando, ¿recibió mi correo de esta mañana?", s: "Cuando das seguimiento a un correo que aún no te responden.", sEn: "When you follow up on an email that hasn't been answered yet.", n: "\"Did you get\" es más natural que \"did you receive\" en el día a día.", nEn: "\"Did you get\" is more natural than \"did you receive\" in everyday use." },
    "loc-ofi10": { e: "I'll copy you on the email so you stay in the loop.", t: "Lo copio en el correo para que esté al tanto.", s: "Cuando vas a incluir a alguien en un correo dirigido a otra persona.", sEn: "When you're going to include someone on an email sent to another person.", n: "También se dice \"I'll CC you\", muy común en oficinas.", nEn: "You can also say \"I'll CC you\", very common in offices." },
    "loc-ofi11": { e: "What's the deadline for sending the report?", t: "¿Cuál es la fecha límite para enviar el reporte?", s: "Cuando necesitas saber para cuándo debes entregar una tarea o documento.", sEn: "When you need to know by when a task or document is due.", n: "\"Deadline\" suena \"déd-lain\"; la \"ea\" se pronuncia como \"e\" corta.", nEn: "\"Deadline\" sounds like \"ded-line\"; the \"ea\" is a short \"e\"." },
    "loc-ofi12": { e: "I'll check and let you know by the end of the day.", t: "Lo reviso y le aviso antes de que termine el día.", s: "Cuando alguien pregunta algo y necesitas verificar antes de responder.", sEn: "When someone asks something and you need to verify before answering.", n: "Útil agregar un plazo (\"by tomorrow\") para que la otra persona sepa qué esperar.", nEn: "It helps to add a time frame (\"by tomorrow\") so the other person knows what to expect." },
    "loc-ofi13": { e: "Could you please forward me the email from the client?", t: "¿Podría reenviarme el correo del cliente, por favor?", s: "Cuando le pides a un colega que te reenvíe un correo que no recibiste.", sEn: "When you ask a colleague to forward you an email you didn't get.", n: "\"Forward\" como verbo significa reenviar; no lo confundas con \"send\" (enviar nuevo).", nEn: "\"Forward\" as a verb means to re-send a received email; don't mix it up with \"send\" (a new one)." },
    "loc-ofi14": { e: "I'm on a call right now, can I get back to you in five minutes?", t: "Estoy en una llamada ahora mismo, ¿le puedo responder en cinco minutos?", s: "Cuando alguien te interrumpe y estás hablando por teléfono.", sEn: "When someone interrupts you while you're on the phone.", n: "\"On a call\" es más natural en oficina que \"talking on the phone\".", nEn: "\"On a call\" sounds more natural at work than \"talking on the phone\"." },
    // ===================== Basic grammar (gramatica-en) =====================
    "loc-gra01": { e: "I am the new receptionist; it's my first day today.", t: "Yo soy la nueva recepcionista; hoy es mi primer día.", s: "Cuando te presentas a un compañero o cliente.", sEn: "When you introduce yourself to a coworker or customer.", n: "En el habla se contrae a \"I'm\"; suena más natural que \"I am\".", nEn: "In speech it contracts to \"I'm\"; it sounds more natural than \"I am\"." },
    "loc-gra02": { e: "You are next in line, sir; I'll be right with you.", t: "Usted es el siguiente, señor; lo atiendo enseguida.", s: "Cuando le indicas a un cliente que es su turno.", sEn: "When you tell a customer it's their turn.", n: "Se contrae a \"you're\", que suena igual que \"your\"; cuidado al escribir.", nEn: "It contracts to \"you're\", which sounds like \"your\"; be careful when writing." },
    "loc-gra03": { e: "He is the manager; he can help you with the refund.", t: "Él es el gerente; él le puede ayudar con el reembolso.", s: "Cuando señalas a otra persona que puede atender al cliente.", sEn: "When you point out another person who can help the customer.", n: "Se contrae a \"he's\"; recuerda la 's' final que en español no existe.", nEn: "It contracts to \"he's\"; remember the final 's' that doesn't exist in Spanish." },
    "loc-gra04": { e: "We are open until ten, so there's plenty of time.", t: "Estamos abiertos hasta las diez, así que hay tiempo de sobra.", s: "Cuando le informas a un cliente el horario del negocio.", sEn: "When you tell a customer the business hours.", n: "Se contrae a \"we're\"; pronúncialo como \"wir\", no como \"güi-ar\".", nEn: "It contracts to \"we're\"; pronounce it like \"wir\", not \"güi-ar\"." },
    "loc-gra05": { e: "What time does the restaurant open?", t: "¿A qué hora abre el restaurante?", s: "Cuando preguntas por una cosa o un dato que no sabes.", sEn: "When you ask about a thing or a piece of information you don't know.", n: "\"What\" suena \"uot\", no \"juat\"; la 'h' es muda.", nEn: "\"What\" sounds like \"wot\", not \"hwat\"; the 'h' is silent." },
    "loc-gra06": { e: "Where is the nearest pharmacy?", t: "¿Dónde está la farmacia más cercana?", s: "Cuando preguntas por la ubicación de un lugar o una cosa.", sEn: "When you ask about the location of a place or a thing.", n: "Recuerda usar \"is/are\" después: \"Where is...?\" o \"Where are...?\".", nEn: "Remember to add \"is/are\" after it: \"Where is...?\" or \"Where are...?\"." },
    "loc-gra07": { e: "When does the tour start?", t: "¿Cuándo empieza el tour?", s: "Cuando preguntas por el momento o la hora de algo.", sEn: "When you ask about the time or moment of something.", n: "Para horas exactas también puedes decir \"What time...?\".", nEn: "For exact times you can also say \"What time...?\"." },
    "loc-gra08": { e: "Why is the bill so high?", t: "¿Por qué la cuenta es tan alta?", s: "Cuando preguntas por la razón o el motivo de algo.", sEn: "When you ask for the reason or motive behind something.", n: "No confundas \"why\" (por qué) con \"because\" (porque), que es la respuesta.", nEn: "Don't mix up \"why\" (the question) with \"because\" (the answer)." },
    "loc-gra09": { e: "I called you yesterday but you didn't answer.", t: "Te llamé ayer pero no contestaste.", s: "Cuando hablas de algo que pasó el día anterior.", sEn: "When you talk about something that happened the day before.", n: "Con \"yesterday\" el verbo va en pasado: \"I worked\", no \"I work\".", nEn: "With \"yesterday\" the verb goes in the past: \"I worked\", not \"I work\"." },
    "loc-gra10": { e: "See you tomorrow at nine.", t: "Nos vemos mañana a las nueve.", s: "Cuando hablas de algo que pasará el día siguiente.", sEn: "When you talk about something happening the next day.", n: "Ojo: \"tomorrow\" es el día futuro; \"morning\" es la mañana del día.", nEn: "Note: \"tomorrow\" is the future day; \"morning\" is the early part of the day." },
    "loc-gra11": { e: "How do you say \"gracias\" in English?", t: "¿Cómo se dice \"gracias\" en inglés?", s: "Cuando no sabes una palabra en inglés y quieres aprenderla.", sEn: "When you don't know a word in English and want to learn it.", n: "Frase clave para salir de apuros; añade \"in English\" al final.", nEn: "A key phrase to get unstuck; add \"in English\" at the end." },
    "loc-gra12": { e: "What does \"sold out\" mean?", t: "¿Qué significa \"sold out\"?", s: "Cuando oyes o lees una palabra y no sabes qué quiere decir.", sEn: "When you hear or read a word and don't know what it means.", n: "Pon la palabra en el espacio: \"What does X mean?\".", nEn: "Put the word in the gap: \"What does X mean?\"." },
    "loc-gra13": { e: "How do you get to the bus station from here?", t: "¿Cómo se llega a la estación de buses desde aquí?", s: "Cuando preguntas la manera de hacer algo o de llegar a un lugar.", sEn: "When you ask the way to do something or to get somewhere.", n: "'How' se pronuncia 'jáu' con 'h' aspirada suave, no como 'ou' en español.", nEn: "'How' is said 'how' with a light breathy 'h', not a hard sound." },
    "loc-gra14": { e: "How much is the room for one night?", t: "¿Cuánto cuesta la habitación por una noche?", s: "Cuando preguntas el precio de algo incontable o de un servicio.", sEn: "When you ask the price of something uncountable or a service.", n: "Usa 'how much' para incontables y 'how many' para cosas contables (how many nights).", nEn: "Use 'how much' for uncountable things and 'how many' for countable ones (how many nights)." },
    // ===================== In class (examen) =====================
    "loc-exa01": { e: "Raise your hand if you have a question.", t: "Levanta la mano si tienes una pregunta.", s: "Cuando un profesor pide a los estudiantes que levanten la mano.", sEn: "When a teacher asks students to raise their hand.", n: "\"Raise\" lleva la 'r' suave; no lo confundas con \"rise\" (subir solo).", nEn: "\"Raise\" means to lift something; don't confuse it with \"rise\" (to go up by itself)." },
    "loc-exa02": { e: "Please read out loud so everyone can hear you.", t: "Por favor lee en voz alta para que todos te escuchen.", s: "Cuando le pides a alguien que lea con voz para el grupo.", sEn: "When you ask someone to read aloud for the group.", n: "También puedes decir \"read aloud\"; significan lo mismo.", nEn: "You can also say \"read aloud\"; they mean the same thing." },
    "loc-exa03": { e: "Hand in your homework before Friday.", t: "Entrega la tarea antes del viernes.", s: "Cuando un profesor pide que se entregue un trabajo.", sEn: "When a teacher asks for work to be turned in.", n: "\"Hand in\" es entregar; \"hand out\" es repartir, no los mezcles.", nEn: "\"Hand in\" means submit; \"hand out\" means distribute, don't mix them up." },
    "loc-exa04": { e: "Excuse me, may I go to the restroom?", t: "Disculpe, ¿puedo ir al baño?", s: "Cuando pides permiso para ir al baño en clase o el trabajo.", sEn: "When you ask permission to go to the bathroom in class or at work.", n: "\"May I\" es más educado que \"Can I\" para pedir permiso.", nEn: "\"May I\" is more polite than \"Can I\" when asking permission." },
    "loc-exa05": { e: "Sorry, I didn't understand the question. Could you repeat it?", t: "Disculpe, no entendí la pregunta. ¿Podría repetirla?", s: "Cuando no captaste lo que te preguntaron y necesitas aclararlo.", sEn: "When you didn't catch what was asked and need it clarified.", n: "Es \"didn't understand\", no \"don't understood\"; el pasado va en \"did\".", nEn: "It's \"didn't understand\", not \"don't understood\"; the past goes in \"did\"." },
    "loc-exa06": { e: "How do you spell it? Letter by letter, please.", t: "¿Cómo se escribe? Letra por letra, por favor.", s: "Cuando necesitas que alguien deletree una palabra o un nombre.", sEn: "When you need someone to spell a word or name out.", n: "Sirve mucho para tomar nombres por teléfono o en recepción.", nEn: "Very useful for taking down names on the phone or at reception." },
    "loc-exa07": { e: "Sorry, could you say it again, please?", t: "Disculpe, ¿podría repetirlo, por favor?", s: "Cuando no escuchaste bien y necesitas que repitan.", sEn: "When you didn't hear well and need it repeated.", n: "Suaviza la frase con \"sorry\" o \"please\" para sonar más amable.", nEn: "Soften it with \"sorry\" or \"please\" to sound more polite." },
    "loc-exa08": { e: "I'm done with the exercise, what should I do now?", t: "Ya terminé el ejercicio, ¿qué hago ahora?", s: "Cuando avisas que acabaste una tarea o actividad.", sEn: "When you let someone know you've finished a task or activity.", n: "\"I'm done\" suena natural; \"I finished\" también sirve.", nEn: "\"I'm done\" sounds natural; \"I finished\" works too." },
    "loc-exa09": { e: "I'm not sure, but I think it's at three o'clock.", t: "No estoy seguro, pero creo que es a las tres.", s: "Cuando das una respuesta de la que no tienes certeza.", sEn: "When you give an answer you're not certain about.", n: "Añade \"but I think...\" para igual dar tu mejor respuesta.", nEn: "Add \"but I think...\" to still offer your best guess." },
    "loc-exa10": { e: "Can you help me with this, please?", t: "¿Me puedes ayudar con esto, por favor?", s: "Cuando necesitas asistencia con algo que no entiendes o no puedes hacer solo.", sEn: "When you need assistance with something you can't do alone.", n: "\"Could you help me?\" suena un poco más formal y educado.", nEn: "\"Could you help me?\" sounds a bit more formal and polite." },
    "loc-exa11": { e: "Open your books to page twenty, please.", t: "Abran el libro en la página veinte, por favor.", s: "Cuando el profesor indica a la clase empezar a leer una página.", sEn: "When the teacher tells the class to start on a certain page.", n: "En clase se usa el plural 'your books' aunque sea un libro por alumno.", nEn: "In class the plural 'your books' is used even though each student has one book." },
    "loc-exa12": { e: "Work in pairs and practice the dialogue together.", t: "Trabajen en parejas y practiquen el diálogo juntos.", s: "Cuando el profesor organiza una actividad de a dos.", sEn: "When the teacher sets up a two-person activity.", n: "'Pairs' se pronuncia 'pers', igual que 'pears'; significa parejas de dos.", nEn: "'Pairs' sounds like 'pers', the same as 'pears'; it means groups of two." },
    "loc-exa13": { e: "Write your name at the top of the page.", t: "Escriban su nombre en la parte de arriba de la hoja.", s: "Cuando el profesor pide identificar el trabajo antes de entregarlo.", sEn: "When the teacher asks students to label their work before handing it in.", n: "La 'w' de 'write' es muda; se dice 'rait', no 'uu-rait'.", nEn: "The 'w' in 'write' is silent; it's said 'rite', not 'wuh-rite'." },
    "loc-exa14": { e: "Can you give me an example so I understand better?", t: "¿Puede darme un ejemplo para que entienda mejor?", s: "Cuando no comprendes una explicación y pides una muestra concreta.", sEn: "When you don't grasp an explanation and ask for a concrete sample.", n: "'Example' se pronuncia 'ig-SÁM-pol', con la sílaba fuerte en el medio.", nEn: "'Example' is said 'ig-ZAM-pul', with the stress on the middle syllable." },
    // ===================== At the bar (bar-en) =====================
    "loc-bar01": { e: "Hi there, what can I get you tonight?", t: "Hola, ¿qué le sirvo esta noche?", s: "Cuando atiendes a un cliente que llega a la barra.", sEn: "When you greet a customer who comes up to the bar.", n: "Es más casual que \"What would you like?\", perfecto para un bar.", nEn: "It's more casual than \"What would you like?\", perfect for a bar." },
    "loc-bar02": { e: "Would you like that with ice or without?", t: "¿Lo quiere con hielo o sin hielo?", s: "Cuando preguntas al cliente cómo prefiere su bebida.", sEn: "When you ask the customer how they want their drink.", n: "\"Ice\" se dice \"ais\"; lo contrario es \"no ice\" o \"without ice\".", nEn: "\"Ice\" sounds like \"ais\"; the opposite is \"no ice\" or \"without ice\"." },
    "loc-bar03": { e: "One or two beers, or should I bring a pitcher for the table?", t: "¿Una o dos cervezas, o les traigo una jarra para la mesa?", s: "Cuando un grupo llega al bar y tomas el primer pedido de bebidas.", sEn: "When a group arrives at the bar and you take the first drink order.", n: "Para sonar más natural di 'a couple of beers' cuando quieren dos.", nEn: "To sound more natural, say 'a couple of beers' when they want two." },
    "loc-bar04": { e: "Happy hour is until seven, so the second drink is half price.", t: "La hora feliz es hasta las siete, así que la segunda bebida es a mitad de precio.", s: "Cuando un cliente pregunta por las promociones de bebidas en la tarde.", sEn: "When a customer asks about drink deals in the afternoon.", n: "Se dice 'happy hour', no 'happy hours', aunque dure varias horas.", nEn: "Say 'happy hour', not 'happy hours', even if it lasts several hours." },
    "loc-bar05": { e: "Would you like the cocktail menu, or are you in the mood for a beer?", t: "¿Quiere ver la carta de cócteles, o tiene ganas de una cerveza?", s: "Cuando un cliente se sienta en la barra y aún no decide qué tomar.", sEn: "When a customer sits at the bar and hasn't decided what to drink.", n: "'Cocktail' se pronuncia 'CÓK-teil', sin pronunciar la 'c' final fuerte.", nEn: "'Cocktail' is pronounced 'COCK-tayl', not with a hard final sound." },
    "loc-bar06": { e: "Anything else, or shall I close out your tab?", t: "¿Algo más, o le cierro la cuenta?", s: "Cuando el cliente parece terminar y revisas si quiere pedir más.", sEn: "When the customer seems finished and you check if they want more.", n: "Más cálido suena 'Can I get you anything else?'.", nEn: "It sounds warmer to say 'Can I get you anything else?'." },
    "loc-bar07": { e: "That's ten thousand, please, and you can pay at the counter.", t: "Son diez mil, por favor, y puede pagar en la caja.", s: "Cuando le dices el total de la cuenta a un cliente en el bar.", sEn: "When you tell a customer the total of their bill at the bar.", n: "Para mayor cortesía agrega 'whenever you're ready' sin presionar.", nEn: "For extra politeness add 'whenever you're ready' to avoid pressure." },
    "loc-bar08": { e: "Cheers, everyone, and welcome to your first night here!", t: "¡Salud a todos, y bienvenidos a su primera noche aquí!", s: "Cuando brindas con un grupo o entregas las bebidas para celebrar.", sEn: "When you toast with a group or hand over drinks to celebrate.", n: "En inglés 'Cheers!' también significa 'gracias' de manera informal.", nEn: "In English 'Cheers!' can also informally mean 'thanks'." },
    "loc-bar09": { e: "Last call is at one, so let me know if you'd like one more.", t: "La última ronda es a la una, así que avíseme si quiere una más.", s: "Cuando el bar está por cerrar y avisas a los clientes que pidan ya.", sEn: "When the bar is about to close and you warn customers to order now.", n: "'Last call' es la frase fija; evita traducir literal como 'last round'.", nEn: "'Last call' is the set phrase; avoid the literal 'last round'." },
    "loc-bar10": { e: "Still or sparkling water? We have both chilled and ready.", t: "¿Agua con o sin gas? Tenemos ambas frías y listas.", s: "Cuando un cliente pide agua y debes saber qué tipo quiere.", sEn: "When a customer asks for water and you need to know which kind.", n: "'Sparkling' es 'con gas' y 'still' es 'sin gas'; no uses 'with gas'.", nEn: "'Sparkling' means fizzy and 'still' means flat; never say 'with gas'." },
    "loc-bar11": { e: "Would you like to see the menu, or do you know what you'd like?", t: "¿Quiere ver el menú, o ya sabe qué desea?", s: "Al atender a alguien que acaba de sentarse en la barra.", sEn: "When serving someone who just sat down at the bar.", n: "'Would you like' es más cortés que 'Do you want' con clientes.", nEn: "'Would you like' is more polite than 'Do you want' with customers." },
    "loc-bar12": { e: "I recommend our house cocktail, it's the most popular one.", t: "Le recomiendo nuestro cóctel de la casa, es el más pedido.", s: "Cuando un cliente no sabe qué pedir y quiere una sugerencia.", sEn: "When a customer is unsure and wants a suggestion.", n: "'cocktail' se dice 'cóctel'; cuida no decir 'coctel' con acento español.", nEn: "'Cocktail' sounds like 'COCK-tail'; mind the English stress." },
    "loc-bar13": { e: "Would you like to open a tab, or are you paying as you go?", t: "¿Le abro una cuenta, o paga cada consumo?", s: "Cuando un cliente planea quedarse y pedir varias bebidas.", sEn: "When a customer plans to stay and order several drinks.", n: "'a tab' es la cuenta abierta en el bar; no confundas con 'bill'.", nEn: "'A tab' is a running bar account, different from the final 'bill'." },
    "loc-bar14": { e: "I'll bring it right over, just give me a second.", t: "Enseguida se lo traigo, deme un segundo.", s: "Justo después de que un cliente hace su pedido en el bar.", sEn: "Right after a customer places their order at the bar.", n: "'right over' suena más natural que 'right now' al llevar algo.", nEn: "'Right over' sounds more natural than 'right now' when bringing something." },
    // ===================== Shopping (compras-en) =====================
    "loc-com01": { e: "Excuse me, how much is this? I don't see a price tag.", t: "Disculpe, ¿cuánto cuesta esto? No veo la etiqueta de precio.", s: "Cuando estás comprando y un artículo no tiene precio marcado.", sEn: "When you're shopping and an item has no marked price.", n: "También puedes decir 'How much does this cost?' con el mismo sentido.", nEn: "You can also say 'How much does this cost?' with the same meaning." },
    "loc-com02": { e: "Do you have a bigger size? This one is a little tight on me.", t: "¿Tienen una talla más grande? Esta me queda un poco ajustada.", s: "Cuando te pruebas una prenda y necesitas una talla mayor.", sEn: "When you try on clothing and need a larger size.", n: "Di 'a bigger size', no 'a more big size', que es incorrecto.", nEn: "Say 'a bigger size', not 'a more big size', which is wrong." },
    "loc-com03": { e: "I'm just looking, thanks, but I'll ask if I need anything.", t: "Solo estoy mirando, gracias, pero pregunto si necesito algo.", s: "Cuando un vendedor se acerca y aún no quieres comprar nada.", sEn: "When a salesperson approaches and you don't want to buy yet.", n: "Es una frase muy cortés para que no te sigan; suena natural y amable.", nEn: "It's a very polite way to ask for space; it sounds natural and kind." },
    "loc-com04": { e: "Can I try it on? Where's the fitting room?", t: "¿Puedo probármelo? ¿Dónde está el probador?", s: "Cuando quieres probarte ropa antes de decidir comprarla.", sEn: "When you want to try on clothes before deciding to buy.", n: "'Try it on' lleva 'on' al final; 'try it' solo sirve para comida.", nEn: "'Try it on' needs the 'on'; 'try it' alone is for tasting food." },
    "loc-com05": { e: "Do you take card, or is it cash only?", t: "¿Aceptan tarjeta, o es solo efectivo?", s: "Cuando vas a pagar y no sabes qué métodos acepta el negocio.", sEn: "When you're about to pay and don't know which methods they accept.", n: "'Take card' es coloquial; 'accept cards' es más formal.", nEn: "'Take card' is casual; 'accept cards' is more formal." },
    "loc-com06": { e: "Can I have a bag, please? These won't fit in my pocket.", t: "¿Me da una bolsa, por favor? Esto no cabe en mi bolsillo.", s: "Cuando terminas de pagar y necesitas una bolsa para llevar tus cosas.", sEn: "When you finish paying and need a bag to carry your things.", n: "Más suave aún suena 'Could I get a bag, please?'.", nEn: "It sounds even softer to say 'Could I get a bag, please?'." },
    "loc-com07": { e: "Is there a discount if I buy two of them?", t: "¿Hay descuento si compro dos?", s: "Cuando regateas o preguntas por una rebaja al comprar varios.", sEn: "When you bargain or ask for a deal when buying several.", n: "Suena natural decir 'Any discount?' de forma breve e informal.", nEn: "It sounds natural to say 'Any discount?' briefly and informally." },
    "loc-com08": { e: "It's perfect, I'll take it. Can you ring it up?", t: "Es perfecto, me lo llevo. ¿Me lo cobra?", s: "Cuando decides comprar algo y se lo dices al vendedor.", sEn: "When you decide to buy something and tell the salesperson.", n: "'I'll take it' es la frase fija para comprar; no digas 'I take it'.", nEn: "'I'll take it' is the set phrase for buying; don't say 'I take it'." },
    "loc-com09": { e: "Where's the fitting room? I'd like to try these on.", t: "¿Dónde está el probador? Quiero probarme estas.", s: "Cuando tienes ropa en la mano y buscas dónde probártela.", sEn: "When you're holding clothes and look for somewhere to try them on.", n: "También se dice 'dressing room'; ambas son correctas y comunes.", nEn: "You can also say 'dressing room'; both are correct and common." },
    "loc-com10": { e: "Do you have another color? I love it, but not in red.", t: "¿Tienen otro color? Me encanta, pero no en rojo.", s: "Cuando te gusta un producto pero quieres verlo en otro color.", sEn: "When you like a product but want to see it in a different color.", n: "En inglés internacional 'color' se escribe sin 'u' (US) o 'colour' (UK).", nEn: "In US spelling it's 'color'; in UK spelling it's 'colour'." },
    "loc-com11": { e: "Excuse me, where do I pay for this?", t: "Disculpe, ¿dónde pago esto?", s: "Cuando ya elegiste algo en una tienda y buscas la caja.", sEn: "When you've picked something in a shop and are looking for the till.", n: "También puedes preguntar \"Where's the checkout?\" o \"Where's the cashier?\".", nEn: "You can also ask \"Where's the checkout?\" or \"Where's the cashier?\"." },
    "loc-com12": { e: "Does it have a warranty in case something breaks?", t: "¿Tiene garantía por si algo se daña?", s: "Cuando vas a comprar un aparato y quieres saber si está cubierto.", sEn: "When buying a device and you want to know if it's covered.", n: "En inglés británico también se usa \"guarantee\"; \"warranty\" es lo más común.", nEn: "British English also uses \"guarantee\"; \"warranty\" is the most common term." },
    "loc-com13": { e: "If it doesn't fit, can I return it?", t: "Si no me queda, ¿puedo devolverlo?", s: "Cuando compras ropa o un producto y preguntas por la política de devolución.", sEn: "When buying clothes or a product and asking about the return policy.", n: "Cuidado: \"return\" es devolver; \"refund\" es el reembolso del dinero.", nEn: "Careful: \"return\" is to give it back; \"refund\" is getting your money back." },
    "loc-com14": { e: "Is it on sale, or is that the full price?", t: "¿Está en oferta, o ese es el precio completo?", s: "Cuando quieres saber si un artículo tiene descuento antes de comprarlo.", sEn: "When you want to know if an item is discounted before buying.", n: "\"On sale\" es en oferta; \"for sale\" significa que está a la venta, no rebajado.", nEn: "\"On sale\" means discounted; \"for sale\" just means it's available to buy." },
    // ===================== Health & pharmacy (salud-en) =====================
    "loc-med01": { e: "I feel sick, I think I need to lie down for a while.", t: "Me siento mal, creo que necesito acostarme un rato.", s: "Cuando le dices a alguien que no te sientes bien físicamente.", sEn: "When you tell someone you're not feeling physically well.", n: "'Sick' es enfermo en general; en EE. UU. también puede ser con náuseas.", nEn: "'Sick' means ill in general; in the US it can also mean nauseous." },
    "loc-med02": { e: "I have a headache, do you have something for it?", t: "Me duele la cabeza, ¿tiene algo para eso?", s: "Cuando pides un analgésico en la farmacia o le avisas a un compañero.", sEn: "When you ask for a painkiller at the pharmacy or tell a coworker.", n: "Se usa 'have a headache', no 'have headache'; el artículo es necesario.", nEn: "Say 'have a headache', not 'have headache'; the article is needed." },
    "loc-med03": { e: "Do you have something for a cough that won't make me drowsy?", t: "¿Tiene algo para la tos que no me dé sueño?", s: "En la farmacia, cuando le pides al farmacéutico un remedio para la tos.", sEn: "At the pharmacy, when you ask the pharmacist for a cough remedy.", n: "Para algo más suave, di \"Could you recommend something for a cough?\".", nEn: "For a softer tone, say \"Could you recommend something for a cough?\"." },
    "loc-med04": { e: "I need a doctor, my daughter has a high fever.", t: "Necesito un médico, mi hija tiene fiebre alta.", s: "Cuando alguien se enferma y pides atención médica urgente.", sEn: "When someone falls ill and you ask for urgent medical care.", n: "En una emergencia real, di \"I need a doctor right now\" para que entiendan la urgencia.", nEn: "In a real emergency, say \"I need a doctor right now\" so they grasp the urgency." },
    "loc-med05": { e: "Please be careful, I'm allergic to penicillin.", t: "Por favor tenga cuidado, soy alérgico a la penicilina.", s: "Cuando te atiende un médico o farmacéutico y debes avisar de tu alergia.", sEn: "When a doctor or pharmacist treats you and you must warn them of your allergy.", n: "Pronuncia \"allergic\" como \"a-LER-yik\", con la g suave, no como en español.", nEn: "Pronounce \"allergic\" as \"uh-LUR-jik\", with a soft g, not the Spanish g." },
    "loc-med06": { e: "Excuse me, where is the pharmacy? My friend isn't feeling well.", t: "Disculpe, ¿dónde está la farmacia? Mi amigo no se siente bien.", s: "Cuando buscas una farmacia en la calle y le preguntas a alguien.", sEn: "When you're looking for a pharmacy on the street and ask someone.", n: "En inglés británico también se dice \"chemist's\" para farmacia.", nEn: "In British English, a pharmacy is also called a \"chemist's\"." },
    "loc-med07": { e: "And how often do I take it, with or without food?", t: "¿Y cada cuánto lo tomo, con o sin comida?", s: "Cuando recibes un medicamento y preguntas por la dosis.", sEn: "When you receive a medication and ask about the dosage.", n: "También puedes preguntar \"How many times a day?\" si es más fácil para ti.", nEn: "You can also ask \"How many times a day?\" if that's easier for you." },
    "loc-med08": { e: "Someone fainted, please call an ambulance!", t: "¡Alguien se desmayó, por favor llamen a una ambulancia!", s: "En una emergencia, cuando necesitas que alguien pida una ambulancia.", sEn: "In an emergency, when you need someone to call an ambulance.", n: "Pronuncia \"ambulance\" como \"AM-byu-lans\", no \"am-bu-LAN-se\".", nEn: "Pronounce \"ambulance\" as \"AM-byuh-lance\", not \"am-boo-LAHN-say\"." },
    "loc-med09": { e: "Take one pill every eight hours with a glass of water.", t: "Tome una pastilla cada ocho horas con un vaso de agua.", s: "Cuando explicas a un cliente o paciente cómo tomar su medicamento.", sEn: "When you explain to a customer or patient how to take their medicine.", n: "\"Pill\" es la pastilla; \"tablet\" o \"capsule\" sirven según la forma.", nEn: "\"Pill\" works for any tablet; use \"tablet\" or \"capsule\" depending on the shape." },
    "loc-med10": { e: "Does it need a prescription, or can I just buy it here?", t: "¿Necesita receta, o lo puedo comprar aquí no más?", s: "En la farmacia, cuando preguntas si requieres receta para un medicamento.", sEn: "At the pharmacy, when you ask if a medicine requires a prescription.", n: "\"Prescription\" se dice \"pre-SKRIP-shun\"; cuidado con no decir \"perscription\".", nEn: "\"Prescription\" is said \"pre-SKRIP-shun\"; avoid saying \"perscription\"." },
    "loc-med11": { e: "I have a stomachache and I feel a bit nauseous.", t: "Me duele el estómago y me siento un poco con náuseas.", s: "Cuando le describes tu malestar al farmacéutico o al médico.", sEn: "When describing your discomfort to the pharmacist or doctor.", n: "Pronuncia \"stomach\" como \"STÓ-mak\"; la \"ch\" suena como \"k\".", nEn: "Pronounce \"stomach\" as \"STUH-muk\"; the \"ch\" sounds like \"k\"." },
    "loc-med12": { e: "I have a fever and I've been feeling cold all day.", t: "Tengo fiebre y he tenido frío todo el día.", s: "Cuando explicas tus síntomas en la farmacia o al pedir ayuda.", sEn: "When explaining your symptoms at the pharmacy or asking for help.", n: "Se dice \"I have a fever\", no \"I am fever\"; usa siempre \"have\".", nEn: "Say \"I have a fever\", never \"I am fever\"; always use \"have\"." },
    "loc-med13": { e: "Do you have something for pain that I don't need a prescription for?", t: "¿Tiene algo para el dolor que no necesite receta?", s: "Cuando pides un analgésico de venta libre en la farmacia.", sEn: "When asking for an over-the-counter painkiller at the pharmacy.", n: "Puedes ser específico: \"something for a headache / a toothache / back pain\".", nEn: "You can be specific: \"something for a headache / a toothache / back pain\"." },
    "loc-med14": { e: "I'm not feeling well; I just need to rest for a while.", t: "No me siento bien; solo necesito descansar un rato.", s: "Cuando le avisas a alguien que necesitas parar y recuperarte.", sEn: "When telling someone you need to stop and recover.", n: "\"Rest\" es descansar; \"relax\" es relajarse, no significan exactamente lo mismo.", nEn: "\"Rest\" means to recover; \"relax\" means to unwind, they aren't quite the same." },
    // ===================== Bank & money (dinero-en) =====================
    "loc-din01": { e: "Excuse me, where is an ATM around here?", t: "Disculpe, ¿dónde hay un cajero por aquí?", s: "Cuando necesitas sacar efectivo y preguntas por un cajero automático.", sEn: "When you need cash and ask where to find an ATM.", n: "Di las letras \"A-T-M\" por separado; en inglés británico también es \"cashpoint\".", nEn: "Say the letters \"A-T-M\" separately; in British English it's also a \"cashpoint\"." },
    "loc-din02": { e: "Before I withdraw, is there a fee for using this ATM?", t: "Antes de retirar, ¿cobran comisión por usar este cajero?", s: "Cuando vas a sacar dinero y quieres saber si hay cargo extra.", sEn: "When you're about to take out money and want to know about extra charges.", n: "\"Fee\" es el cargo; \"commission\" suena más a inversiones, evítalo aquí.", nEn: "\"Fee\" means the charge; \"commission\" sounds more like investments, so avoid it here." },
    "loc-din03": { e: "Hi, I want to exchange dollars for local currency, please.", t: "Hola, quiero cambiar dólares a moneda local, por favor.", s: "En una casa de cambio, cuando pides cambiar tu dinero.", sEn: "At a currency exchange, when you ask to change your money.", n: "\"Exchange\" se pronuncia \"iks-CHEINCH\"; usa \"change money\" si te sale más natural.", nEn: "\"Exchange\" is said \"iks-CHAYNJ\"; use \"change money\" if it feels more natural." },
    "loc-din04": { e: "What's the exchange rate for dollars today?", t: "¿Cuál es la tasa de cambio del dólar hoy?", s: "Cuando quieres cambiar dinero y preguntas a cuánto está la moneda.", sEn: "When you want to change money and ask what the rate is.", n: "Puedes añadir \"...and is the fee included?\" para evitar sorpresas.", nEn: "You can add \"...and is the fee included?\" to avoid surprises." },
    "loc-din05": { e: "Can I pay in cash, or do you only take card?", t: "¿Puedo pagar en efectivo, o solo aceptan tarjeta?", s: "Al pagar, cuando preguntas si aceptan efectivo.", sEn: "When paying, asking whether they accept cash.", n: "\"In cash\" lleva \"in\"; no digas \"pay cash\" sin la preposición en preguntas formales.", nEn: "Use \"in cash\" with \"in\"; don't drop the preposition in more formal questions." },
    "loc-din06": { e: "I'm sorry, the card was declined. Would you like to try another?", t: "Lo siento, la tarjeta fue rechazada. ¿Quiere probar con otra?", s: "Cuando atiendes a un cliente y su tarjeta no pasa el pago.", sEn: "When you serve a customer and their card doesn't go through.", n: "\"Declined\" suena más amable que \"rejected\" al hablar con el cliente.", nEn: "\"Declined\" sounds gentler than \"rejected\" when speaking to a customer." },
    "loc-din07": { e: "Can I have a receipt, please? I need it for work.", t: "¿Me da un recibo, por favor? Lo necesito para el trabajo.", s: "Después de pagar, cuando pides el comprobante.", sEn: "After paying, when you ask for proof of purchase.", n: "\"Receipt\" se pronuncia \"ri-SIIT\"; la p es muda.", nEn: "\"Receipt\" is pronounced \"ri-SEET\"; the p is silent." },
    "loc-din08": { e: "Here you go, keep the change.", t: "Aquí tiene, quédese con el cambio.", s: "Cuando pagas a un taxista o mesero y le dejas la diferencia de propina.", sEn: "When you pay a taxi driver or waiter and leave the difference as a tip.", n: "\"Change\" aquí es el vuelto, no \"return\"; suena generoso y natural.", nEn: "\"Change\" here means the leftover money, not \"return\"; it sounds generous and natural." },
    "loc-din09": { e: "I need an invoice with my company's name on it.", t: "Necesito una factura con el nombre de mi empresa.", s: "Cuando pides una factura formal para gastos de la empresa.", sEn: "When you ask for a formal invoice for company expenses.", n: "\"Invoice\" es la factura formal; \"receipt\" es el simple comprobante.", nEn: "\"Invoice\" is the formal bill; a \"receipt\" is the simple proof of payment." },
    "loc-din10": { e: "Can I pay with my phone? I have Apple Pay.", t: "¿Puedo pagar con el teléfono? Tengo Apple Pay.", s: "Al pagar, cuando preguntas si aceptan pago sin contacto desde el celular.", sEn: "When paying, asking if they accept contactless payment from your phone.", n: "También puedes decir \"Do you take contactless?\" para pagos sin contacto.", nEn: "You can also say \"Do you take contactless?\" for tap-to-pay." },
    "loc-din11": { e: "This ATM is out of cash; let's try the one across the street.", t: "Este cajero no tiene billetes; probemos el de enfrente.", s: "Cuando el cajero no entrega dinero y le explicas la situación al cliente.", sEn: "When the ATM has no money and you explain the situation to a customer.", n: "\"ATM\" se pronuncia letra por letra: \"ei-ti-em\".", nEn: "\"ATM\" is pronounced letter by letter: \"ay-tee-em\"." },
    "loc-din12": { e: "Can I split the payment between two cards?", t: "¿Puedo dividir el pago entre dos tarjetas?", s: "Cuando quieres pagar una cuenta usando más de un método o tarjeta.", sEn: "When you want to pay a bill using more than one method or card.", n: "Para repartir la cuenta entre amigos se dice \"split the bill\".", nEn: "To divide a bill among friends, say \"split the bill\"." },
    "loc-din13": { e: "Do you exchange currency here, or only at the bank?", t: "¿Hacen cambio de moneda aquí, o solo en el banco?", s: "Cuando un turista pregunta dónde puede cambiar su dinero.", sEn: "When a tourist asks where they can change their money.", n: "\"Currency\" se pronuncia \"KÉR-ren-si\"; cuidado con la doble r suave.", nEn: "\"Currency\" is pronounced \"KUR-ren-see\"; mind the soft double r." },
    "loc-din14": { e: "I need to withdraw cash before the shops close.", t: "Necesito sacar efectivo antes de que cierren las tiendas.", s: "Cuando explicas que vas a un cajero a retirar dinero.", sEn: "When explaining that you're going to an ATM to take out money.", n: "\"Withdraw\" es retirar del cajero; \"take out cash\" es una forma más informal.", nEn: "\"Withdraw\" is to take money from an ATM; \"take out cash\" is a more casual version." },
    // ===================== Customer service (cliente-en) =====================
    "loc-cli01": { e: "Good afternoon, how may I help you today?", t: "Buenas tardes, ¿en qué le puedo ayudar hoy?", s: "Al recibir a un cliente en recepción, tienda o por teléfono.", sEn: "When greeting a customer at a desk, store, or on the phone.", n: "\"How may I help you?\" es más formal que \"How can I help you?\".", nEn: "\"How may I help you?\" is more formal than \"How can I help you?\"." },
    "loc-cli02": { e: "Let me check that for you, one moment please.", t: "Permítame revisarlo, un momento por favor.", s: "Cuando un cliente pregunta algo y necesitas verificar la información.", sEn: "When a customer asks something and you need to verify the information.", n: "Añadir \"for you\" suena más atento y profesional.", nEn: "Adding \"for you\" sounds more attentive and professional." },
    "loc-cli03": { e: "I'm so sorry for the inconvenience, let me sort this out for you right now.", t: "Lamento mucho el inconveniente, permítame resolverlo de inmediato.", s: "Cuando un cliente tuvo un problema y quieres disculparte antes de solucionarlo.", sEn: "When a customer had a problem and you want to apologize before fixing it.", n: "Suena mas calido decir 'I'm sorry for the inconvenience' que un seco 'sorry'.", nEn: "Saying 'I'm sorry for the inconvenience' sounds warmer than a flat 'sorry'." },
    "loc-cli04": { e: "Can I have your order number so I can look into this for you?", t: "¿Me da su número de pedido para poder revisarlo?", s: "Cuando necesitas buscar el pedido de un cliente en el sistema.", sEn: "When you need to find a customer's order in the system.", n: "Mas formal: 'Could I have your order number, please?' suena aun mas cortes.", nEn: "More formal: 'Could I have your order number, please?' sounds even politer." },
    "loc-cli05": { e: "I'll send you the information by email in just a few minutes.", t: "Le envío la información por correo en unos minutos.", s: "Cuando prometes mandarle datos o detalles a un cliente.", sEn: "When you promise to send a customer details or data.", n: "Especifica el medio: 'by email' o 'by text' para que quede claro.", nEn: "Specify the channel: 'by email' or 'by text' so it's clear." },
    "loc-cli06": { e: "Is there anything else I can help with before we finish?", t: "¿Hay algo más en lo que pueda ayudarle antes de terminar?", s: "Al cerrar una atención, para asegurarte de que el cliente quedó conforme.", sEn: "When wrapping up, to make sure the customer is fully satisfied.", n: "Tambien se dice 'anything else I can do for you?', muy comun en servicio.", nEn: "You can also say 'anything else I can do for you?', very common in service." },
    "loc-cli07": { e: "Thank you for your patience while I checked that for you.", t: "Gracias por su paciencia mientras lo revisaba.", s: "Cuando un cliente esperó en línea o en el mostrador mientras resolvías algo.", sEn: "When a customer waited on the line or at the counter while you sorted something out.", n: "Pronuncia 'patience' como 'PEY-shens', no 'pa-TIENS'.", nEn: "Pronounce 'patience' like 'PAY-shuns', not 'pa-TIENS'." },
    "loc-cli08": { e: "Thanks for calling, and have a great day!", t: "Gracias por llamar, ¡que tenga un buen día!", s: "Para despedirte cordialmente de un cliente al final de la atención.", sEn: "To say a warm goodbye to a customer at the end of the interaction.", n: "Por la tarde di 'have a great evening' para sonar mas natural.", nEn: "In the evening say 'have a great evening' to sound more natural." },
    "loc-cli09": { e: "I'll transfer your call to the right department now, please stay on the line.", t: "Voy a transferir su llamada al área correcta, por favor no cuelgue.", s: "Cuando otra persona o área debe atender la llamada del cliente.", sEn: "When another person or department needs to handle the customer's call.", n: "En el Reino Unido se dice 'put you through' en lugar de 'transfer'.", nEn: "In the UK people say 'put you through' instead of 'transfer'." },
    "loc-cli10": { e: "Good news, your case has been resolved and everything is back to normal.", t: "Buenas noticias, su caso quedó resuelto y todo está en orden.", s: "Cuando le confirmas a un cliente que su problema ya está solucionado.", sEn: "When you confirm to a customer that their problem is now fixed.", n: "Pronuncia 'resolved' como 'ri-ZOLVD', con la z sonora.", nEn: "Pronounce 'resolved' as 'ri-ZOLVD', with a voiced z." },
    "loc-cli11": { e: "I apologize for the mistake, let me fix it right away.", t: "Le pido una disculpa por el error, permítame corregirlo enseguida.", s: "Cuando hubo un error de tu parte y te disculpas con el cliente.", sEn: "When there was a mistake on your side and you apologize to the customer.", n: "\"I apologize\" es más formal que \"I'm sorry\"; ideal para atención al cliente.", nEn: "\"I apologize\" is more formal than \"I'm sorry\"; great for customer service." },
    "loc-cli12": { e: "Give me one moment while I look that up for you.", t: "Permítame un momento mientras le busco eso.", s: "Cuando necesitas una pausa breve para revisar algo para el cliente.", sEn: "When you need a short pause to check something for the customer.", n: "Más cortés: \"Could you give me one moment, please?\"", nEn: "More polite: \"Could you give me one moment, please?\"" },
    "loc-cli13": { e: "I'll follow up with you by email once the order ships.", t: "Le haré seguimiento por correo en cuanto se despache el pedido.", s: "Cuando un cliente deja un asunto pendiente y quieres asegurarle que lo retomarás.", sEn: "When a customer has an open issue and you want to assure them you'll get back to them.", n: "Suena más profesional decir 'follow up with you' que 'call you again'; el 'follow' se pronuncia 'fólou', sin sonido de 'w' fuerte.", nEn: "'Follow up with you' sounds more professional than 'call you again'; 'follow' is said 'FOL-oh', with a soft ending." },
    "loc-cli14": { e: "I'm here if you need anything, just give me a call.", t: "Quedo a sus órdenes, solo llámeme.", s: "Al cerrar una atención, para que el cliente sepa que puede volver a contactarte.", sEn: "When wrapping up service, to let the customer know they can reach you again.", n: "Variante un poco más formal: 'Please let me know if you need anything else.'", nEn: "A slightly more formal variant: 'Please let me know if you need anything else.'" },
    // ===================== Numbers & dates (numeros-en) =====================
    "loc-num01": { e: "Let's count them together: one, two, three, and there's your change.", t: "Contémoslos juntos: uno, dos, tres, y ahí está su vuelto.", s: "Cuando cuentas en voz alta billetes, artículos o personas frente al cliente.", sEn: "When you count bills, items, or people out loud in front of a customer.", n: "La 'th' de 'three' va con la lengua entre los dientes, no como 't'.", nEn: "The 'th' in 'three' uses the tongue between the teeth, not a plain 't'." },
    "loc-num02": { e: "That'll be ten dollars, please.", t: "Son diez dólares, por favor.", s: "Al decir un precio redondo de diez al cobrar.", sEn: "When stating a round price of ten while charging.", n: "No confundas 'ten' (diez) con 'tan'; la 'e' es corta y clara.", nEn: "Don't mix up 'ten' with 'tan'; the 'e' is short and clear." },
    "loc-num03": { e: "The bus leaves in twenty minutes, so we have a little time.", t: "El bus sale en veinte minutos, así que tenemos un poco de tiempo.", s: "Al indicar una cantidad o un tiempo de veinte a un cliente.", sEn: "When telling a customer a quantity or a time of twenty.", n: "Muchos dicen 'twenny'; tu di 'TWEN-ty' marcando ambas sílabas.", nEn: "Many say 'twenny'; you say 'TWEN-ty' marking both syllables." },
    "loc-num04": { e: "The entrance fee is one hundred per person.", t: "La entrada cuesta cien por persona.", s: "Al dar un precio o número de cien a un cliente o turista.", sEn: "When giving a customer or tourist a price or number of one hundred.", n: "Puedes decir solo 'a hundred'; suena natural y mas relajado.", nEn: "You can just say 'a hundred'; it sounds natural and more relaxed." },
    "loc-num05": { e: "The room is one thousand a night, breakfast included.", t: "La habitación cuesta mil por noche, con desayuno incluido.", s: "Al decir un precio de mil, por ejemplo una tarifa o total.", sEn: "When stating a price of one thousand, like a rate or total.", n: "Cuidado: 'thousand' lleva 'th'; no lo digas como 'tausan'.", nEn: "Careful: 'thousand' has a 'th'; don't say it like 'tausan'." },
    "loc-num06": { e: "Your room is the first one on the right.", t: "Su habitación es la primera a la derecha.", s: "Al señalar cuál es el primero en una fila, lista o ubicación.", sEn: "When pointing out which is the first in a row, list, or location.", n: "Para fechas se dice 'the first of May'; 'first' también es '1st'.", nEn: "For dates say 'the first of May'; 'first' is also written '1st'." },
    "loc-num07": { e: "We're closed on Sundays, but we open again on Monday.", t: "Cerramos los domingos, pero abrimos de nuevo el lunes.", s: "Al indicar un día de la semana, como horarios o citas.", sEn: "When stating a day of the week, like hours or appointments.", n: "En inglés los días siempre van con mayúscula: 'Monday'.", nEn: "In English the days are always capitalized: 'Monday'." },
    "loc-num08": { e: "Sorry, what's the date today? I need it for the form.", t: "Disculpe, ¿qué fecha es hoy? La necesito para el formulario.", s: "Cuando necesitas saber o confirmar la fecha actual, por ejemplo al registrar.", sEn: "When you need to know or confirm today's date, for example when checking in.", n: "También puedes preguntar 'what's today's date?', igual de común.", nEn: "You can also ask 'what's today's date?', just as common." },
    "loc-num09": { e: "You can pay half now and half when you check out.", t: "Puede pagar la mitad ahora y la mitad al hacer el check-out.", s: "Al hablar de dividir un pago, una porción o una cantidad por la mitad.", sEn: "When talking about splitting a payment, a portion, or an amount in half.", n: "La 'l' de 'half' es muda: se dice 'haf', no 'jalf'.", nEn: "The 'l' in 'half' is silent: say 'haf', not 'half' with the l." },
    "loc-num10": { e: "How much is it in total, including the drinks?", t: "¿Cuánto es en total, incluyendo las bebidas?", s: "Al preguntar o confirmar la suma final de una cuenta.", sEn: "When asking or confirming the final sum of a bill.", n: "También se usa 'how much is it altogether?', muy natural.", nEn: "You can also use 'how much is it altogether?', very natural." },
    "loc-num11": { e: "That'll be fifty pesos for the two coffees.", t: "Son cincuenta pesos por los dos cafés.", s: "Cuando le dices a un cliente cuánto debe pagar y la cifra incluye el número cincuenta.", sEn: "When you tell a customer the total and the amount involves the number fifty.", n: "Cuidado: \"fifty\" (50) suena distinto a \"fifteen\" (15); en fifty el acento va al inicio (FIF-ty).", nEn: "Careful: \"fifty\" (50) sounds different from \"fifteen\" (15); in fifty the stress is at the start (FIF-ty)." },
    "loc-num12": { e: "The room is on the second floor, room two hundred and four.", t: "La habitación está en el segundo piso, cuarto doscientos cuatro.", s: "Cuando indicas a un huésped el número de su habitación o una cantidad alrededor de doscientos.", sEn: "When you give a guest their room number or an amount around two hundred.", n: "En inglés americano puedes decir \"two hundred four\", pero \"two hundred and four\" también es correcto y común.", nEn: "In American English you can say \"two hundred four\", but \"two hundred and four\" is also correct and common." },
    "loc-num13": { e: "Your taxi will pick you up at half past three.", t: "Su taxi lo recogerá a las tres y media.", s: "Cuando confirmas una hora exacta para un servicio, tour o reserva.", sEn: "When you confirm an exact time for a service, tour, or booking.", n: "También es muy común decir \"three thirty\", que suena más casual y rápido.", nEn: "It's also very common to say \"three thirty\", which sounds more casual and quick." },
    "loc-num14": { e: "Your reservation is for May fifteenth, is that right?", t: "Su reserva es para el quince de mayo, ¿es correcto?", s: "Cuando confirmas una fecha de reserva, viaje o cita con un cliente.", sEn: "When you confirm a booking, trip, or appointment date with a customer.", n: "En inglés se dice el mes antes del día: \"May fifteenth\", no \"fifteen May\".", nEn: "In English you say the month before the day: \"May fifteenth\", not \"fifteen May\"." },
    // ===================== At the beach (playa-en) =====================
    "loc-pla01": { e: "Would you like to rent a chair for the afternoon? It's very comfortable.", t: "¿Le gustaría rentar una silla por la tarde? Es muy cómoda.", s: "Cuando ofreces sillas de playa a un turista que llega a la orilla.", sEn: "When you offer beach chairs to a tourist arriving at the shore.", n: "En inglés británico es más común 'hire' que 'rent' para alquilar.", nEn: "In British English 'hire' is more common than 'rent' for renting." },
    "loc-pla02": { e: "Would you like an umbrella? The sun is really strong right now.", t: "¿Quiere una sombrilla? El sol está muy fuerte ahorita.", s: "Cuando ofreces una sombrilla a un cliente bajo el sol en la playa.", sEn: "When you offer an umbrella to a customer under the sun at the beach.", n: "Pronuncia 'umbrella' como 'um-BREH-la', con el acento en el medio.", nEn: "Pronounce 'umbrella' as 'um-BREL-uh', with the stress in the middle." },
    "loc-pla03": { e: "Watch out for the waves, they can knock you over near the rocks.", t: "Cuidado con las olas, lo pueden tumbar cerca de las rocas.", s: "Cuando un turista entra al mar y quieres advertirle que el oleaje está fuerte.", sEn: "When a tourist walks into the sea and you want to warn them the surf is strong.", n: "Tambien puedes decir \"Be careful with the waves\", pero \"watch out\" suena mas natural como aviso rapido.", nEn: "You can also say \"Be careful with the waves\", but \"watch out\" sounds more natural as a quick warning." },
    "loc-pla04": { e: "The sun is strong today, so don't forget to put on sunscreen.", t: "El sol está fuerte hoy, así que no olvides ponerte protector solar.", s: "Cuando un cliente está en la playa al mediodía y quieres recomendarle protegerse.", sEn: "When a guest is at the beach at midday and you want to suggest they protect themselves.", n: "Di \"strong\" con la 'r' suave y la 'o' corta, casi como \"strong\", no \"estrong\" con e inicial.", nEn: "Say \"strong\" without adding an 'e' at the start that Spanish speakers tend to put before s+consonant." },
    "loc-pla05": { e: "Can I offer you a massage right here under the umbrella?", t: "¿Le puedo ofrecer un masaje aquí mismo bajo la sombrilla?", s: "Cuando vendes servicios en la playa y te acercas a ofrecer un masaje a un turista que descansa.", sEn: "When you sell beach services and approach a resting tourist to offer a massage.", n: "\"Can I offer you...?\" es muy cortés para vender sin presionar; evita \"Do you want a massage?\" que suena brusco.", nEn: "\"Can I offer you...?\" is polite for selling without pressure; avoid the blunt \"Do you want a massage?\"" },
    "loc-pla06": { e: "A cold coconut? It's really refreshing in this heat.", t: "¿Un coco frío? Es muy refrescante con este calor.", s: "Cuando vendes cocos en la playa y le ofreces uno a alguien que pasa caminando.", sEn: "When you sell coconuts on the beach and offer one to someone walking by.", n: "Pronuncia \"coconut\" como \"CO-co-nut\", con el acento en la primera sílaba.", nEn: "Stress \"coconut\" on the first syllable: \"CO-co-nut\"." },
    "loc-pla07": { e: "Please don't leave your things unattended; the beach gets busy.", t: "Por favor no deje sus cosas solas; la playa se llena mucho.", s: "Cuando avisas a un turista que va a meterse al mar y deja sus pertenencias en la arena.", sEn: "When you warn a tourist heading into the water who is leaving belongings on the sand.", n: "\"Unattended\" es la palabra exacta para \"sin vigilancia\"; agregar \"please\" lo hace más amable.", nEn: "\"Unattended\" is the precise word for \"with no one watching\"; adding \"please\" softens it." },
    "loc-pla08": { e: "The boat leaves in ten minutes, so please make your way to the dock.", t: "El bote sale en diez minutos, así que por favor diríjanse al muelle.", s: "Cuando avisas a los pasajeros que el bote del tour está por zarpar.", sEn: "When you let passengers know the tour boat is about to depart.", n: "\"Leaves\" en presente simple sirve para horarios fijos; tambien vale \"is leaving\" para algo inminente.", nEn: "Use \"leaves\" (simple present) for schedules; \"is leaving\" also works for something imminent." },
    "loc-pla09": { e: "Shall I watch your things while you go for a swim?", t: "¿Le cuido sus cosas mientras se da un chapuzón?", s: "Cuando un cliente en la playa quiere meterse al mar y deja sus pertenencias en la silla.", sEn: "When a beach customer wants to go in the water and is leaving their belongings on the chair.", n: "\"Shall I\" suena más formal y educado que \"Should I\" para ofrecer un servicio.", nEn: "\"Shall I\" sounds more formal and polite than \"Should I\" when offering a service." },
    "loc-pla10": { e: "Sunscreen helps a lot, especially around noon when the sun is strongest.", t: "El protector solar ayuda mucho, sobre todo al mediodía cuando el sol está más fuerte.", s: "Cuando aconsejas a un turista que se está poniendo rojo bajo el sol.", sEn: "When you advise a tourist who is getting sunburned in the sun.", n: "\"Sunscreen\" y \"sunblock\" son intercambiables; evita decir \"solar protector\" (calco del español).", nEn: "\"Sunscreen\" and \"sunblock\" are interchangeable; avoid saying \"solar protector\" (a Spanish calque)." },
    "loc-pla11": { e: "Would you like coconut water? It's nice and cold.", t: "¿Quiere agua de coco? Está bien fría.", s: "Cuando ofreces bebidas a los clientes que toman sol en la playa.", sEn: "When you offer drinks to customers sunbathing on the beach.", n: "\"Would you like...?\" es la forma más cortés de ofrecer algo, mejor que \"Do you want...?\".", nEn: "\"Would you like...?\" is the most polite way to offer something, better than \"Do you want...?\"." },
    "loc-pla12": { e: "The tide is coming in, so let's move your chairs back a bit.", t: "La marea está subiendo, así que movamos sus sillas un poco hacia atrás.", s: "Cuando el mar empieza a acercarse y avisas a los clientes en la orilla.", sEn: "When the sea starts moving up and you warn customers near the shore.", n: "Lo contrario es \"the tide is going out\" (la marea está bajando).", nEn: "The opposite is \"the tide is going out\" (la marea está bajando)." },
    "loc-pla13": { e: "I offer fresh fruit if you'd like a snack on the beach.", t: "Ofrezco frutas frescas por si quiere algo para picar en la playa.", s: "Cuando eres vendedor ambulante y ofreces fruta a la gente en la arena.", sEn: "When you're a beach vendor offering fruit to people on the sand.", n: "\"Fruit\" suele ser incontable: di \"fresh fruit\", no \"fresh fruits\".", nEn: "\"Fruit\" is usually uncountable: say \"fresh fruit,\" not \"fresh fruits.\"" },
    "loc-pla14": { e: "Here's your change, and thank you so much.", t: "Aquí tiene su vuelto, y muchas gracias.", s: "Cuando le devuelves el dinero sobrante a un cliente después de un pago.", sEn: "When you give back the leftover money to a customer after a payment.", n: "En inglés \"change\" es incontable; nunca digas \"a change\" para referirte al vuelto.", nEn: "In English \"change\" is uncountable; never say \"a change\" to mean the money returned." },
    // ===================== Public transport (transporte-en) =====================
    "loc-tra01": { e: "Excuse me, does this bus go downtown?", t: "Disculpe, ¿este bus va al centro?", s: "Cuando estás en la parada y le preguntas al conductor si el bus llega al centro.", sEn: "When you are at the stop and ask the driver if the bus reaches the center.", n: "En inglés \"downtown\" es \"el centro\"; agregar \"Excuse me\" al inicio suena más educado.", nEn: "\"Downtown\" means the city center; starting with \"Excuse me\" sounds more polite." },
    "loc-tra02": { e: "How much is the fare to the city center?", t: "¿Cuánto cuesta el pasaje al centro de la ciudad?", s: "Cuando subes al bus o taxi y quieres saber el precio del pasaje.", sEn: "When you board a bus or taxi and want to know the ticket price.", n: "\"Fare\" es el precio del transporte; no confundas con \"fee\" (cargo) ni \"fair\" (justo/feria).", nEn: "\"Fare\" is the transport price; don't confuse it with \"fee\" or \"fair\"." },
    "loc-tra03": { e: "Could you tell me where I get off for the museum?", t: "¿Me podría decir dónde me bajo para el museo?", s: "Cuando vas en el bus y no sabes en qué parada bajarte para tu destino.", sEn: "When you are on the bus and don't know which stop to get off at.", n: "\"Get off\" es bajarse de un bus o tren; para un carro pequeño se usa \"get out\".", nEn: "\"Get off\" is for buses and trains; for a small car you say \"get out\"." },
    "loc-tra04": { e: "Next stop, please, I'm getting off here.", t: "La próxima parada, por favor, me bajo aquí.", s: "Cuando le avisas al conductor que quieres bajarte en la siguiente parada.", sEn: "When you signal the driver that you want off at the next stop.", n: "Un \"please\" al final lo hace cortés; tambien puedes decir \"This is my stop\".", nEn: "Adding \"please\" keeps it polite; you can also say \"This is my stop\"." },
    "loc-tra05": { e: "I just missed it, what time is the next one?", t: "Acabo de perderlo, ¿a qué hora sale el próximo?", s: "Cuando se te fue el bus o el tren y preguntas cuándo viene el siguiente.", sEn: "When you missed the bus or train and ask when the next comes.", n: "\"The next one\" evita repetir \"bus\"; \"one\" reemplaza el sustantivo ya mencionado.", nEn: "\"The next one\" avoids repeating \"bus\"; \"one\" stands in for the noun already mentioned." },
    "loc-tra06": { e: "Do you have change for a twenty? I only have a big bill.", t: "¿Tiene cambio de veinte? Solo tengo un billete grande.", s: "Cuando vas a pagar el pasaje y necesitas que te cambien un billete grande.", sEn: "When you pay the fare and need a big bill broken into smaller money.", n: "\"Change\" aquí significa sencillo o vuelto; no lleva 's' aunque sean varias monedas.", nEn: "\"Change\" means coins or smaller money here, and never takes an 's'." },
    "loc-tra07": { e: "I'm going to the airport, could you take me there?", t: "Voy al aeropuerto, ¿me podría llevar?", s: "Cuando paras un taxi o subes al bus y dices tu destino.", sEn: "When you flag a taxi or board a bus and state your destination.", n: "\"I'm going to\" es para planes en curso; di \"airport\" con el acento en \"AIR\".", nEn: "Use \"I'm going to\" for current plans; stress \"airport\" on \"AIR\"." },
    "loc-tra08": { e: "Is it far on foot, or should I take a taxi?", t: "¿Está muy lejos a pie, o mejor tomo un taxi?", s: "Cuando preguntas si conviene caminar al lugar o tomar transporte.", sEn: "When you ask whether to walk to the place or take a ride.", n: "\"On foot\" significa caminando; no digas \"by foot\", que es un error común.", nEn: "\"On foot\" means walking; avoid the common mistake \"by foot\"." },
    "loc-tra09": { e: "How often does the bus come on Sundays?", t: "¿Cada cuánto pasa el bus los domingos?", s: "Cuando esperas en la parada y quieres saber la frecuencia del bus.", sEn: "When you're waiting at the stop and want to know how often the bus runs.", n: "Para horarios fijos puedes decir \"What time does the bus come?\" en vez de \"how often\".", nEn: "For a fixed timetable, ask \"What time does the bus come?\" instead of \"how often\"." },
    "loc-tra10": { e: "Excuse me, does it stop at the market?", t: "Disculpe, ¿para en el mercado?", s: "Cuando subes a un bus y quieres confirmar que pasa por tu parada.", sEn: "When you get on a bus and want to confirm it goes to your stop.", n: "El \"stop\" suena \"stáp\"; no agregues una \"e\" al inicio como en español.", nEn: "\"Stop\" sounds like \"stahp\"; don't add an \"e\" sound at the start." },
    "loc-tra11": { e: "I need a taxi to the airport, my flight is at noon.", t: "Necesito un taxi al aeropuerto, mi vuelo es al mediodía.", s: "Cuando pides en recepción o por teléfono un taxi para llegar al aeropuerto.", sEn: "When you ask at reception or by phone for a taxi to the airport.", n: "Más cortés: \"Could I get a taxi to the airport, please?\"", nEn: "More polite: \"Could I get a taxi to the airport, please?\"" },
    "loc-tra12": { e: "Excuse me, where is the station? I think I'm lost.", t: "Disculpe, ¿dónde está la estación? Creo que estoy perdido.", s: "Cuando le preguntas a alguien en la calle cómo llegar a la estación.", sEn: "When you ask someone on the street how to get to the station.", n: "Especifica si hace falta: \"the bus station\" o \"the train station\".", nEn: "Specify if needed: \"the bus station\" or \"the train station\"." },
    "loc-tra13": { e: "The metro is faster than the bus at this hour.", t: "El metro es más rápido que el bus a esta hora.", s: "Cuando le recomiendas a alguien la mejor forma de moverse por la ciudad.", sEn: "When you suggest the best way to get around the city.", n: "En inglés británico se dice \"the underground\" o \"the tube\" en vez de \"the metro\".", nEn: "In British English people say \"the underground\" or \"the tube\" instead of \"the metro\"." },
    "loc-tra14": { e: "I bought a ticket online, do I still need to validate it?", t: "Compré un tiquete en línea, ¿igual tengo que validarlo?", s: "Cuando ya tienes tu boleto y preguntas qué hacer al subir.", sEn: "When you already have your ticket and ask what to do when boarding.", n: "\"Bought\" suena \"bot\"; la \"gh\" es muda en esta palabra.", nEn: "\"Bought\" sounds like \"bot\"; the \"gh\" is silent here." },
    // ===================== In the meeting (reunion-en) =====================
    "loc-reu01": { e: "Okay everyone, let's get started, we have a lot to cover.", t: "Bien a todos, empecemos, tenemos mucho que ver.", s: "Cuando abres una reunión y quieres que el equipo arranque.", sEn: "When you open a meeting and want the team to begin.", n: "\"Let's get started\" es más cálido que \"Let's start\"; perfecto para reuniones.", nEn: "\"Let's get started\" sounds warmer than \"Let's start\"; great for meetings." },
    "loc-reu02": { e: "Can you see my screen, or should I share it again?", t: "¿Pueden ver mi pantalla, o la comparto de nuevo?", s: "Cuando compartes pantalla en una videollamada y quieres confirmar que se ve.", sEn: "When you share your screen on a call and want to confirm it's visible.", n: "En llamadas se dice \"share my screen\"; \"screen\" rima con \"green\", con e larga.", nEn: "On calls say \"share my screen\"; \"screen\" rhymes with \"green\", long e sound." },
    "loc-reu03": { e: "Sorry, you cut out for a second, could you say that again?", t: "Perdón, se cortó un momento, ¿podría repetir eso?", s: "Cuando en una videollamada el audio del otro se entrecortó y no entendiste.", sEn: "When someone's audio froze on a video call and you missed it.", n: "\"You cut out\" es la frase exacta para audio entrecortado; no digas \"you cut\".", nEn: "\"You cut out\" is the set phrase for choppy audio; \"you cut\" doesn't mean this." },
    "loc-reu04": { e: "Could you repeat that? I didn't quite catch the last part.", t: "¿Podría repetir eso? No alcancé a entender la última parte.", s: "Cuando no entendiste algo en la reunión y pides que lo repitan.", sEn: "When you missed something in the meeting and ask for a repeat.", n: "\"Could you\" es más cortés que \"Can you\"; agregar el motivo suena natural y amable.", nEn: "\"Could you\" is more polite than \"Can you\"; adding the reason sounds natural and kind." },
    "loc-reu05": { e: "I agree with that, I think it's the best option for the team.", t: "Estoy de acuerdo con eso, creo que es la mejor opción para el equipo.", s: "Cuando apoyas una idea o propuesta que alguien acaba de plantear en la reunión.", sEn: "When you support an idea someone just raised in the meeting.", n: "\"Agree\" ya es el verbo; no digas \"I am agree\", eso es un error muy común.", nEn: "\"Agree\" is already the verb; never say \"I am agree\", a very common mistake." },
    "loc-reu06": { e: "Let's leave it for later and move on to the budget.", t: "Dejémoslo para después y pasemos al presupuesto.", s: "Cuando un tema se está alargando y prefieres posponerlo en la reunión.", sEn: "When a topic is dragging and you choose to postpone it in the meeting.", n: "Una variante común es \"Let's table that for now\" en reuniones formales.", nEn: "A common variant in formal meetings is \"Let's table that for now\"." },
    "loc-reu07": { e: "That covers the agenda. Any questions before we wrap up?", t: "Con eso cubrimos la agenda. ¿Alguna pregunta antes de terminar?", s: "Cuando terminas de explicar algo en una reunión y quieres dar espacio para dudas.", sEn: "When you finish explaining something in a meeting and want to open the floor for doubts.", n: "Suena más cálido decir \"Any questions so far?\" para invitar a participar.", nEn: "It sounds warmer to say \"Any questions so far?\" to invite people in." },
    "loc-reu08": { e: "That's all from me. Thanks, everyone, and have a great rest of your day.", t: "Eso es todo de mi parte. Gracias a todos, y que tengan un buen resto del día.", s: "Al cerrar una reunión o llamada para despedirte del grupo.", sEn: "When closing a meeting or call to say goodbye to the group.", n: "Evita \"thanks to everyone\"; lo natural es solo \"thanks, everyone\".", nEn: "Avoid \"thanks to everyone\"; the natural form is just \"thanks, everyone.\"" },
    "loc-reu09": { e: "Can you hear me okay, or should I move closer to the mic?", t: "¿Pueden escucharme bien, o me acerco al micrófono?", s: "Al inicio de una videollamada, para confirmar que tu audio funciona.", sEn: "At the start of a video call, to confirm your audio is working.", n: "No confundas 'hear' (oír) con 'listen' (escuchar con atención); aquí siempre se usa 'hear'.", nEn: "Don't confuse 'hear' (perceive sound) with 'listen' (pay attention); use 'hear' here." },
    "loc-reu10": { e: "I'm sharing my screen now, let me know when you can see it.", t: "Estoy compartiendo la pantalla, avísenme cuando la vean.", s: "En una reunión virtual, justo antes de mostrar un documento o presentación.", sEn: "In a virtual meeting, right before showing a document or slides.", n: "Se dice 'share my screen', no 'share the screen of me'; 'screen' suena 'skriin'.", nEn: "Say 'share my screen', not 'share the screen of me'; 'screen' sounds like 'skreen'." },
    "loc-reu11": { e: "Give me a second, I'm pulling up the file.", t: "Permítanme un segundo, estoy abriendo el archivo.", s: "Cuando necesitas una breve pausa para buscar algo durante la reunión.", sEn: "When you need a brief pause to find something during the meeting.", n: "'Give me a second' es informal y amable; en contextos muy formales usa 'One moment, please.'", nEn: "'Give me a second' is casual and friendly; in very formal settings use 'One moment, please.'" },
    "loc-reu12": { e: "Let's move to the next point on the agenda.", t: "Pasemos al siguiente punto de la agenda.", s: "Cuando terminan un tema y quieres avanzar la reunión.", sEn: "When you finish one topic and want to move the meeting forward.", n: "También puedes decir 'Let's move on to...'; ambas son naturales.", nEn: "You can also say 'Let's move on to...'; both are natural." },
    "loc-reu13": { e: "Is that clear, or would you like me to go over it again?", t: "¿Quedó claro, o quieren que lo repase de nuevo?", s: "Después de explicar algo, para comprobar que todos entendieron.", sEn: "After explaining something, to check that everyone understood.", n: "Suena más amable agregar 'or do you have any questions?' al final.", nEn: "It sounds friendlier to add 'or do you have any questions?' at the end." },
    "loc-reu14": { e: "I'll send the summary later today so everyone has the notes.", t: "Les envío el resumen más tarde para que todos tengan las notas.", s: "Al cerrar la reunión, prometiendo enviar un resumen por escrito.", sEn: "When closing the meeting, promising to send a written summary.", n: "Cuida la 'r' de 'summary'; se dice 'SÁ-ma-ri', no 'su-MA-ri'.", nEn: "Mind the stress in 'summary'; it's 'SUM-uh-ree', not 'su-MA-ree'." },
    // ===================== Useful connectors (conectores-en) =====================
    "loc-con01": { e: "I'd love to help, but the kitchen is already closed.", t: "Me encantaría ayudar, pero la cocina ya está cerrada.", s: "Cuando quieres decir que sí pero hay un obstáculo o una excepción.", sEn: "When you want to agree but add an obstacle or exception.", n: "En inglés se pone una coma antes de \"but\" cuando une dos ideas completas.", nEn: "In English you put a comma before \"but\" when it joins two full ideas." },
    "loc-con02": { e: "We're a little behind because the order was very large.", t: "Estamos un poco atrasados porque el pedido era muy grande.", s: "Cuando das la razón o el motivo de algo.", sEn: "When you give the reason or cause for something.", n: "\"Because\" explica el porqué; \"so\" explica el resultado, no los confundas.", nEn: "\"Because\" gives the reason; \"so\" gives the result, don't mix them up." },
    "loc-con03": { e: "We have rooms with a sea view, and we also offer airport pickup.", t: "Tenemos habitaciones con vista al mar, y también ofrecemos traslado al aeropuerto.", s: "Cuando agregas otra cosa más a lo que acabas de decir.", sEn: "When you add one more thing to what you just said.", n: "\"Also\" suele ir antes del verbo principal: \"we also offer\", no \"we offer also\".", nEn: "\"Also\" usually goes before the main verb: \"we also offer,\" not \"we offer also.\"" },
    "loc-con04": { e: "We have many local dishes, for example the ceviche and the arepa.", t: "Tenemos muchos platos típicos, por ejemplo el ceviche y la arepa.", s: "Cuando das un caso concreto para aclarar lo que dices.", sEn: "When you give a concrete case to make your point clear.", n: "En conversación puedes decir \"like\" en vez de \"for example\" para sonar más casual.", nEn: "In conversation you can say \"like\" instead of \"for example\" to sound more casual." },
    "loc-con05": { e: "The bus was late, so we'll start the tour ten minutes later.", t: "El bus llegó tarde, entonces empezaremos el tour diez minutos más tarde.", s: "Cuando explicas el resultado o la consecuencia de algo.", sEn: "When you state the result or consequence of something.", n: "Aquí \"so\" significa \"por eso\"; al inicio de frase \"So,...\" sirve para retomar el tema.", nEn: "Here \"so\" means \"therefore\"; at the start, \"So,...\" works to resume the topic." },
    "loc-con06": { e: "The price includes breakfast; besides, the wifi is completely free.", t: "El precio incluye desayuno; además, el wifi es completamente gratis.", s: "Cuando añades un punto extra que refuerza lo que dijiste.", sEn: "When you add an extra point that reinforces what you said.", n: "No confundas \"besides\" (además) con \"beside\" (al lado de), son distintos.", nEn: "Don't confuse \"besides\" (in addition) with \"beside\" (next to); they differ." },
    "loc-con07": { e: "The room is small; however, it has a beautiful view of the city.", t: "La habitación es pequeña; sin embargo, tiene una vista hermosa de la ciudad.", s: "Cuando das un contraste o algo positivo que compensa lo negativo.", sEn: "When you give a contrast or a positive that offsets the negative.", n: "\"However\" suele llevar coma después: \"However, ...\"; es más formal que \"but\".", nEn: "\"However\" usually takes a comma after it; it's more formal than \"but.\"" },
    "loc-con08": { e: "We had a few delays, but in the end the guests were very happy.", t: "Tuvimos algunos retrasos, pero al final los huéspedes quedaron muy contentos.", s: "Cuando resumes cómo resultó algo después de varios pasos.", sEn: "When you sum up how something turned out after several steps.", n: "\"In the end\" es el resultado final; \"at the end\" es un lugar o momento, no los mezcles.", nEn: "\"In the end\" is the final outcome; \"at the end\" is a place or moment, don't mix them." },
    "loc-con09": { e: "Your room has a bed and a private bathroom.", t: "Su habitación tiene una cama y un baño privado.", s: "Cuando enlazas dos cosas en una frase para describir o explicar algo.", sEn: "When you link two things in a sentence to describe or explain something.", n: "En habla rápida \"and\" suena casi como \"an\"; no hace falta pronunciar fuerte la d.", nEn: "In fast speech \"and\" sounds almost like \"an\"; you don't need to pronounce the d strongly." },
    "loc-con10": { e: "Would you like still or sparkling water?", t: "¿Quiere agua sin gas o con gas?", s: "Cuando ofreces dos opciones al cliente para que elija una.", sEn: "When you offer the customer two options to choose from.", n: "Para una sola pregunta de dos opciones, sube la voz en la primera y bájala en la segunda.", nEn: "For a single two-option question, raise your voice on the first and lower it on the second." },
    "loc-con11": { e: "First, I'll take your order, then I'll bring some bread.", t: "Primero tomo su orden, luego le traigo pan.", s: "Cuando explicas el orden de los pasos de un proceso o servicio.", sEn: "When you explain the order of steps in a process or service.", n: "\"First\" al inicio de la frase organiza tus ideas y suena profesional; sepárala con una pausa.", nEn: "\"First\" at the start of a sentence organizes your ideas and sounds professional; set it off with a pause." },
    "loc-con12": { e: "We'll visit the museum, and then we'll have lunch.", t: "Visitaremos el museo y luego almorzaremos.", s: "Cuando, como guía o anfitrión, anuncias lo que sigue después de algo.", sEn: "When, as a guide or host, you announce what comes after something.", n: "No confundas \"then\" (luego) con \"than\" (que, en comparaciones); se escriben casi igual.", nEn: "Don't confuse \"then\" (luego) with \"than\" (used in comparisons); they look almost the same." },
    "loc-con13": { e: "The tour is great, although it can get a little hot at noon.", t: "El tour es genial, aunque puede hacer un poco de calor al mediodía.", s: "Cuando admites algo positivo pero agregas una pequeña salvedad o advertencia.", sEn: "When you admit something positive but add a small caveat or warning.", n: "En conversación informal puedes usar \"though\" al final: \"It's great, it gets hot though.\"", nEn: "In casual conversation you can use \"though\" at the end: \"It's great, it gets hot though.\"" },
    "loc-con14": { e: "It's a sweet drink, kind of like lemonade.", t: "Es una bebida dulce, algo así como limonada.", s: "Cuando comparas algo desconocido para el cliente con algo que sí conoce.", sEn: "When you compare something unfamiliar to the customer with something they know.", n: "\"Like\" para comparar es muy útil al describir comida local: \"It tastes like...\".", nEn: "\"Like\" for comparing is very useful when describing local food: \"It tastes like...\"." },
    // ===================== Complaints & apologies (quejas-en) =====================
    "loc-que01": { e: "I'm very sorry about the wait; let me bring your food right now.", t: "Lamento mucho la espera; permítame traerle su comida ahora mismo.", s: "Cuando te disculpas con un cliente por un error o una molestia.", sEn: "When you apologize to a customer for a mistake or inconvenience.", n: "Di \"I'm sorry about\" + el problema; \"I'm sorry for\" + lo que tú hiciste.", nEn: "Say \"I'm sorry about\" + the problem; \"I'm sorry for\" + what you did." },
    "loc-que02": { e: "Don't worry, I'll fix it right away and bring you a new plate.", t: "No se preocupe, lo soluciono enseguida y le traigo un plato nuevo.", s: "Cuando un cliente reporta un problema y le aseguras una solución inmediata.", sEn: "When a customer reports a problem and you promise an immediate fix.", n: "\"Right away\" suena más natural que \"immediately\" en el trato con clientes.", nEn: "\"Right away\" sounds more natural than \"immediately\" when dealing with customers." },
    "loc-que03": { e: "I'm sorry to hear that. What's the problem, exactly?", t: "Lamento escuchar eso. ¿Cuál es el problema, exactamente?", s: "Cuando un cliente se queja y necesitas entender qué pasó.", sEn: "When a customer complains and you need to understand what happened.", n: "Suaviza con \"May I ask what the problem is?\" para sonar más cortés.", nEn: "Soften it with \"May I ask what the problem is?\" to sound more polite." },
    "loc-que04": { e: "This one is cold, isn't it? I'll bring you another one right away.", t: "Este está frío, ¿verdad? Le traigo otro enseguida.", s: "Cuando algo salió mal con un producto o plato y ofreces reemplazarlo.", sEn: "When something is wrong with a product or dish and you offer a replacement.", n: "Para varios, di \"some more\"; para uno solo, \"another one\".", nEn: "For several, say \"some more\"; for just one, \"another one.\"" },
    "loc-que05": { e: "Please don't worry about it, there's no charge for the dessert.", t: "Por favor no se preocupe, no se le cobrará el postre.", s: "Cuando decides no cobrar algo como gesto por una molestia.", sEn: "When you decide not to charge for something as a gesture for the trouble.", n: "También puedes decir \"it's on the house\" para invitar algo gratis.", nEn: "You can also say \"it's on the house\" to offer something for free." },
    "loc-que06": { e: "I understand. Let me call the manager so we can sort this out.", t: "Entiendo. Permítame llamar al gerente para resolver esto.", s: "Cuando un problema necesita a alguien con más autoridad.", sEn: "When a problem needs someone with more authority.", n: "\"Manager\" se pronuncia \"MA-na-yer\", con la G suave como una Y inglesa.", nEn: "\"Manager\" is said \"MA-na-jer,\" with a soft G like an English J." },
    "loc-que07": { e: "Thanks for letting us know; we'll make sure it doesn't happen again.", t: "Gracias por avisarnos; nos aseguraremos de que no vuelva a pasar.", s: "Cuando un cliente reporta algo y agradeces que lo haya comentado.", sEn: "When a customer reports something and you thank them for mentioning it.", n: "Esto convierte una queja en algo positivo; úsalo siempre antes de disculparte.", nEn: "This turns a complaint into something positive; use it right before apologizing." },
    "loc-que08": { e: "I've turned up the air conditioning. Is this better for you?", t: "Subí el aire acondicionado. ¿Está mejor así para usted?", s: "Después de ajustar algo, para confirmar que el cliente quedó satisfecho.", sEn: "After adjusting something, to confirm the customer is now satisfied.", n: "Agregar \"for you\" al final lo hace sonar más atento y personal.", nEn: "Adding \"for you\" at the end makes it sound more attentive and personal." },
    "loc-que09": { e: "I understand your frustration, and I'll do my best to fix this.", t: "Entiendo su molestia, y haré todo lo posible por solucionarlo.", s: "Cuando un cliente está enojado por un error y quieres mostrarle empatía.", sEn: "When a customer is upset about a mistake and you want to show empathy.", n: "Validar primero con \"I understand...\" calma al cliente antes de explicar la solución.", nEn: "Validating first with \"I understand...\" calms the customer before you explain the fix." },
    "loc-que10": { e: "Let me make it right for you right now.", t: "Permítame corregirlo ahora mismo.", s: "Cuando algo salió mal y quieres asegurarle al cliente que lo vas a arreglar.", sEn: "When something went wrong and you want to assure the customer you'll fix it.", n: "\"Make it right\" es una expresión común y cálida; más natural que \"correct it\".", nEn: "\"Make it right\" is a common, warm phrase; more natural than \"correct it.\"" },
    "loc-que11": { e: "I'll offer you a discount for the trouble, it's the least I can do.", t: "Le ofrezco un descuento por las molestias, es lo menos que puedo hacer.", s: "Cuando quieres compensar a un cliente por un problema con su pedido o servicio.", sEn: "When you want to make up to a customer for a problem with their order or service.", n: "\"For the trouble\" o \"for the inconvenience\" son las frases típicas para disculparse.", nEn: "\"For the trouble\" or \"for the inconvenience\" are the typical phrases for apologizing." },
    "loc-que12": { e: "I'm really sorry, it won't happen again.", t: "Lo siento mucho, no volverá a pasar.", s: "Cuando te disculpas con un cliente y prometes que el error no se repetirá.", sEn: "When you apologize to a customer and promise the mistake won't be repeated.", n: "Pronuncia \"won't\" como /wont/, no como \"want\", para no confundir el sentido.", nEn: "Pronounce \"won't\" as /wohnt/, not like \"want,\" so the meaning stays clear." },
    "loc-que13": { e: "How can I make it up to you?", t: "¿Cómo puedo compensarlo?", s: "Cuando preguntas a un cliente molesto qué puedes hacer para resarcir el error.", sEn: "When you ask an upset customer what you can do to make up for the mistake.", n: "\"Make it up to you\" significa compensar; no lo confundas con \"make up\" (maquillaje/inventar).", nEn: "\"Make it up to you\" means to compensate; don't confuse it with \"make up\" (makeup/invent)." },
    "loc-que14": { e: "Thank you for understanding, we really appreciate it.", t: "Gracias por su comprensión, de verdad lo apreciamos.", s: "Cuando un cliente acepta tu disculpa o solución con paciencia.", sEn: "When a customer accepts your apology or solution patiently.", n: "Tras \"for\" usa el gerundio: \"for understanding\", nunca \"for understand\".", nEn: "After \"for\" use the -ing form: \"for understanding,\" never \"for understand.\"" },
    // ===================== Local food (platos-en) =====================
    "loc-pla-t01": { e: "I'd recommend the bandeja paisa; it's a local dish you can't miss.", t: "Le recomiendo la bandeja paisa; es un plato típico que no se puede perder.", s: "Cuando un turista pregunta qué probar de la comida de la región.", sEn: "When a tourist asks what to try from the regional food.", n: "\"Local\" se pronuncia \"LOU-cal\"; evita decir \"typical dish\", suena raro en inglés.", nEn: "\"Local\" is said \"LOH-cul\"; avoid \"typical dish,\" it sounds odd in English." },
    "loc-pla-t02": { e: "It comes with rice and fish, and a small salad on the side.", t: "Viene con arroz y pescado, y una pequeña ensalada al lado.", s: "Cuando describes qué incluye un plato del menú.", sEn: "When you describe what a dish includes.", n: "Usa \"comes with\" para acompañamientos incluidos; \"on the side\" es \"aparte\".", nEn: "Use \"comes with\" for included sides; \"on the side\" means served separately." },
    "loc-pla-t03": { e: "It's a little spicy, but you can ask the kitchen to make it milder.", t: "Es un poco picante, pero puede pedirle a la cocina que lo hagan más suave.", s: "Cuando un cliente pregunta por un plato y quieres advertirle del picante.", sEn: "When a customer asks about a dish and you want to warn them it's hot.", n: "Para algo muy picante di \"It's quite spicy\"; \"a little\" suaviza el aviso.", nEn: "For something very hot say \"It's quite spicy\"; \"a little\" softens the warning." },
    "loc-pla-t04": { e: "The arepa is made of corn, so it's naturally gluten-free.", t: "La arepa es de maíz, así que es naturalmente sin gluten.", s: "Cuando explicas a un turista de qué está hecho un plato típico.", sEn: "When you explain to a tourist what a local dish is made of.", n: "Pronuncia \"corn\" con la o larga (corn), no como \"con\".", nEn: "Pronounce \"corn\" with a long o (corn), not like \"con\"." },
    "loc-pla-t05": { e: "The ceviche has lime, fresh fish, and a bit of onion.", t: "El ceviche lleva limón, pescado fresco y un poco de cebolla.", s: "Cuando describes los ingredientes de un plato a un comensal.", sEn: "When you describe a dish's ingredients to a diner.", n: "En inglés \"lime\" es el limón verde; \"lemon\" es el amarillo.", nEn: "In English \"lime\" is the green one; \"lemon\" is the yellow one." },
    "loc-pla-t06": { e: "Is it vegetarian, or does it have any meat or fish?", t: "¿Es vegetariano, o lleva algo de carne o pescado?", s: "Cuando un cliente quiere saber si un plato no tiene carne.", sEn: "When a customer wants to know if a dish has no meat.", n: "Para algo sin nada de origen animal di \"vegan\" en vez de \"vegetarian\".", nEn: "For something with no animal products say \"vegan\" instead of \"vegetarian\"." },
    "loc-pla-t07": { e: "I recommend it, it's our most popular dish.", t: "Se lo recomiendo, es nuestro plato más popular.", s: "Cuando un cliente duda y quieres sugerirle un plato.", sEn: "When a customer hesitates and you want to suggest a dish.", n: "Suena más cálido si añades por qué: \"I recommend it, it's really fresh.\"", nEn: "It sounds warmer if you add why: \"I recommend it, it's really fresh.\"" },
    "loc-pla-t08": { e: "Here's your food, enjoy your meal!", t: "Aquí tiene su comida, ¡buen provecho!", s: "Cuando sirves el plato en la mesa.", sEn: "When you serve the dish at the table.", n: "En inglés no hay un \"buen provecho\" fijo; \"Enjoy your meal\" o solo \"Enjoy!\" es lo natural.", nEn: "English has no fixed \"buen provecho\"; \"Enjoy your meal\" or just \"Enjoy!\" is natural." },
    "loc-pla-t09": { e: "You eat it with your hands, no fork needed.", t: "Se come con la mano, no hace falta tenedor.", s: "Cuando explicas a un turista cómo se come un plato típico local.", sEn: "When you explain to a tourist how to eat a typical local dish.", n: "En inglés se dice \"with your hands\" (en plural), aunque uses solo una.", nEn: "In English you say \"with your hands\" (plural), even if you use just one." },
    "loc-pla-t10": { e: "It has coconut milk, which gives it a creamy flavor.", t: "Lleva leche de coco, que le da un sabor cremoso.", s: "Cuando describes los ingredientes de un plato a un comensal curioso.", sEn: "When you describe the ingredients of a dish to a curious diner.", n: "\"Coconut milk\" (leche de coco) es distinto de \"coconut water\" (agua de coco).", nEn: "\"Coconut milk\" is different from \"coconut water.\"" },
    "loc-pla-t11": { e: "It's very fresh, we caught the fish this morning.", t: "Es muy fresco, el pescado lo pescamos esta mañana.", s: "Cuando recomiendas un plato y resaltas que los ingredientes son del día.", sEn: "When you recommend a dish and highlight that the ingredients are same-day.", n: "\"Fresh\" se pronuncia /fresh/; no agregues una \"e\" inicial (\"efresh\").", nEn: "\"Fresh\" is pronounced /fresh/; don't add an initial \"e\" sound (\"efresh\")." },
    "loc-pla-t12": { e: "The patacón is fried plantain, and it goes great with everything.", t: "El patacón es plátano frito, y combina muy bien con todo.", s: "Cuando un turista pregunta qué es ese acompañamiento en su plato.", sEn: "When a tourist asks what that side on their plate is.", n: "Plátano para freír es \"plantain\"; \"banana\" es el de comer crudo.", nEn: "Cooking plantain is \"plantain\"; \"banana\" is the kind you eat raw." },
    "loc-pla-t13": { e: "Would you like to try it? It's our most popular dish.", t: "¿Quiere probarlo? Es nuestro plato más popular.", s: "Cuando ofreces a un cliente que pruebe una especialidad de la casa.", sEn: "When you offer a customer to taste a house specialty.", n: "Para comida usa \"try\" (probar de sabor); \"try it on\" es solo para ropa.", nEn: "For food use \"try\" (taste); \"try it on\" is only for clothes." },
    "loc-pla-t14": { e: "It goes well with fresh juice, would you like one?", t: "Va bien con jugo natural, ¿quiere uno?", s: "Cuando sugieres una bebida que combina con el plato que pidió el cliente.", sEn: "When you suggest a drink that pairs with the dish the customer ordered.", n: "Jugo natural en inglés es \"fresh juice\"; \"natural juice\" suena raro a oídos nativos.", nEn: "Fresh-squeezed juice is \"fresh juice\"; \"natural juice\" sounds odd to native ears." },
    // ===================== Emergencies & safety (emergencias-en) =====================
    "loc-eme01": { e: "Are you okay? Do you need me to call someone?", t: "¿Está bien? ¿Necesita que llame a alguien?", s: "Cuando ves a alguien que se cayó o se ve mal y quieres ayudar.", sEn: "When you see someone who fell or looks unwell and want to help.", n: "\"Okay\" suena con dos sílabas (o-key); evita decir solo \"oh-kay\" muy corto.", nEn: "\"Okay\" sounds like two syllables (o-key); don't clip it too short." },
    "loc-eme02": { e: "Call the police, someone just took her bag!", t: "¡Llame a la policía, alguien acaba de quitarle el bolso!", s: "Cuando presencias un robo o un peligro y necesitas ayuda urgente.", sEn: "When you witness a robbery or danger and need urgent help.", n: "\"Police\" lleva el acento en la segunda sílaba: po-LEECE.", nEn: "\"Police\" stresses the second syllable: po-LEECE." },
    "loc-eme03": { e: "I need help, my friend isn't feeling well.", t: "Necesito ayuda, mi amigo no se siente bien.", s: "Cuando pides ayuda a alguien en una emergencia.", sEn: "When you ask someone for help in an emergency.", n: "Para pedir ayuda urgente grita \"Help!\" solo; la frase completa es para explicar.", nEn: "For urgent help just shout \"Help!\"; the full sentence is for explaining." },
    "loc-eme04": { e: "You look pale, should I call an ambulance?", t: "Se ve pálido, ¿llamo a una ambulancia?", s: "Cuando alguien se siente muy mal y ofreces llamar ayuda médica.", sEn: "When someone feels very ill and you offer to call medical help.", n: "\"Ambulance\" se dice AM-byu-lance, sin pronunciar la u como en español.", nEn: "\"Ambulance\" is said AM-byu-lance, not with a Spanish u." },
    "loc-eme05": { e: "Be careful, the floor is wet over there.", t: "Tenga cuidado, el piso está mojado por allá.", s: "Cuando adviertes a alguien de un peligro cercano.", sEn: "When you warn someone about a nearby hazard.", n: "Para un peligro inmediato di \"Watch out!\"; \"Be careful\" es un aviso más general.", nEn: "For an immediate danger say \"Watch out!\"; \"Be careful\" is a more general warning." },
    "loc-eme06": { e: "I lost my passport, where can I report it?", t: "Perdí mi pasaporte, ¿dónde puedo reportarlo?", s: "Cuando se te extravía un documento y buscas ayuda.", sEn: "When you've misplaced a document and are looking for help.", n: "Si te lo robaron, di \"My passport was stolen\", que es más fuerte que \"lost\".", nEn: "If it was stolen, say \"My passport was stolen\", which is stronger than \"lost\"." },
    "loc-eme07": { e: "I was robbed near the market and they took my phone.", t: "Me robaron cerca del mercado y se llevaron mi teléfono.", s: "Cuando reportas un robo a la policía o pides ayuda.", sEn: "When you report a robbery to the police or ask for help.", n: "Usa \"robbed\" cuando te roban a ti; \"stolen\" para la cosa robada: \"My phone was stolen.\"", nEn: "Use \"robbed\" for the person; \"stolen\" for the item: \"My phone was stolen.\"" },
    "loc-eme08": { e: "Stay calm, help is on the way.", t: "Quédese tranquilo, la ayuda está en camino.", s: "Cuando tranquilizas a alguien asustado durante una emergencia.", sEn: "When you reassure a frightened person during an emergency.", n: "\"Stay calm\" y \"Keep calm\" significan lo mismo; ambos funcionan igual.", nEn: "\"Stay calm\" and \"Keep calm\" mean the same thing; both work equally." },
    "loc-eme09": { e: "There's an accident on the main road, please send help.", t: "Hay un accidente en la vía principal, por favor manden ayuda.", s: "Cuando llamas a emergencias o avisas que ocurrió un choque.", sEn: "When you call emergency services or report a crash.", n: "Recuerda contraer: \"There's\" es más natural que \"There is\" al hablar.", nEn: "Remember to contract: \"There's\" sounds more natural than \"There is\" when speaking." },
    "loc-eme10": { e: "Where is the hospital? It's an emergency.", t: "¿Dónde está el hospital? Es una emergencia.", s: "Cuando necesitas atención médica urgente y preguntas la ubicación.", sEn: "When you need urgent medical care and ask for the location.", n: "La \"h\" de \"hospital\" sí se pronuncia, a diferencia del español.", nEn: "The \"h\" in \"hospital\" is pronounced, unlike in Spanish." },
    "loc-eme11": { e: "He feels dizzy and he needs to sit down.", t: "Él se siente mareado y necesita sentarse.", s: "Cuando le explicas a alguien que un compañero o cliente está mal.", sEn: "When you explain to someone that a coworker or guest is unwell.", n: "Para ti mismo di \"I feel dizzy\"; \"dizzy\" suena \"dísi\".", nEn: "For yourself say \"I feel dizzy\"; \"dizzy\" sounds like \"dizz-ee\"." },
    "loc-eme12": { e: "Don't move, help is on the way.", t: "No se mueva, la ayuda viene en camino.", s: "Cuando alguien se cayó o se lastimó y quieres que se quede quieto.", sEn: "When someone has fallen or is hurt and you want them to stay still.", n: "Más suave: \"Try not to move\" suena menos brusco en una emergencia.", nEn: "Softer option: \"Try not to move\" sounds gentler in an emergency." },
    "loc-eme13": { e: "Call the fire department, there's smoke in the kitchen!", t: "¡Llamen a los bomberos, hay humo en la cocina!", s: "Cuando hay un incendio o emergencia y pides que llamen a los bomberos.", sEn: "When there's a fire or emergency and you ask someone to call the firefighters.", n: "En inglés británico se dice \"the fire brigade\" en vez de \"fire department\".", nEn: "In British English people say \"the fire brigade\" instead of \"fire department\"." },
    "loc-eme14": { e: "Please keep calm, everyone, and follow me to the exit.", t: "Por favor mantengan la calma todos, y síganme a la salida.", s: "Cuando guías a un grupo durante una emergencia o evacuación.", sEn: "When you guide a group during an emergency or evacuation.", n: "Variante común: \"Stay calm\" es más corta y se usa igual.", nEn: "Common variant: \"Stay calm\" is shorter and used the same way." },
    // ===================== Reviews & social (resenas-en) =====================
    "loc-res01": { e: "If you enjoyed your visit, could you leave us a review online?", t: "Si disfrutó su visita, ¿nos podría dejar una reseña en internet?", s: "Cuando un cliente satisfecho se va y quieres pedirle una reseña.", sEn: "When a happy customer is leaving and you want to ask for a review.", n: "\"Could you\" es más cortés que \"Can you\" para pedir un favor.", nEn: "\"Could you\" is more polite than \"Can you\" for asking a favor." },
    "loc-res02": { e: "Follow us on Instagram for our daily specials.", t: "Síganos en Instagram para ver nuestras promociones del día.", s: "Cuando invitas a un cliente a seguir el negocio en redes.", sEn: "When you invite a customer to follow the business on social media.", n: "Di el nombre del usuario después: \"Follow us on Instagram, @ourcafe.\"", nEn: "Add the handle after: \"Follow us on Instagram, @ourcafe.\"" },
    "loc-res03": { e: "Tag us in your photos so we can share them too!", t: "Etiquétenos en sus fotos para que también las compartamos.", s: "Cuando animas a los clientes a mencionarte en sus publicaciones.", sEn: "When you encourage customers to mention you in their posts.", n: "\"Tag\" (etiquetar) suena \"tag\"; no lo confundas con \"take\".", nEn: "\"Tag\" sounds like \"tag\"; don't mix it up with \"take\"." },
    "loc-res04": { e: "Thanks for visiting, we hope to see you again soon!", t: "Gracias por su visita, ¡esperamos verlo pronto de nuevo!", s: "Cuando te despides de un cliente que se va.", sEn: "When you say goodbye to a customer who is leaving.", n: "Suena más cálido con \"again soon\" al final que solo \"Thanks for visiting.\"", nEn: "It sounds warmer with \"again soon\" added than just \"Thanks for visiting.\"" },
    "loc-res05": { e: "Did you enjoy the service today? We'd love your feedback.", t: "¿Le gustó el servicio de hoy? Nos encantaría su opinión.", s: "Cuando preguntas a un cliente si quedó satisfecho.", sEn: "When you ask a customer if they were satisfied.", n: "\"Enjoy\" se dice en-JOY, con el acento en la segunda sílaba.", nEn: "\"Enjoy\" is said en-JOY, with the stress on the second syllable." },
    "loc-res06": { e: "If you liked it, share it with your friends!", t: "Si le gustó, ¡compártalo con sus amigos!", s: "Cuando pides al cliente que recomiende el negocio a otros.", sEn: "When you ask the customer to recommend the business to others.", n: "\"Share\" rima con \"care\"; no lo pronuncies como \"shar\".", nEn: "\"Share\" rhymes with \"care\"; don't pronounce it like \"shar\"." },
    "loc-res07": { e: "We're on Google Maps, so just search our name and you'll find directions.", t: "Estamos en Google Maps, así que solo busque nuestro nombre y encontrará cómo llegar.", s: "Cuando un cliente pregunta cómo encontrarlos o llegar al lugar.", sEn: "When a customer asks how to find you or get to the place.", n: "Puedes añadir 'just search our name' para que sea más útil.", nEn: "You can add 'just search our name' to make it more helpful." },
    "loc-res08": { e: "Thanks again for coming, and come back anytime, we'd love to see you.", t: "Gracias de nuevo por venir, y vuelva cuando quiera, nos encantaría verle.", s: "Al despedir a un cliente que se va contento.", sEn: "When saying goodbye to a happy customer who is leaving.", n: "Suena más cálido si añades 'we'd love to see you' al final.", nEn: "It sounds warmer if you add 'we'd love to see you' at the end." },
    "loc-res09": { e: "Your feedback helps us a lot, so thank you for sharing it.", t: "Su opinión nos ayuda mucho, así que gracias por compartirla.", s: "Cuando un cliente te da un comentario sobre el servicio.", sEn: "When a customer gives you a comment about the service.", n: "'Feedback' es incontable: no digas 'feedbacks'; se pronuncia 'FÍD-bak'.", nEn: "'Feedback' is uncountable: never say 'feedbacks'; it's said 'FEED-back'." },
    "loc-res10": { e: "Tell us what you think, we'd love to hear your honest opinion.", t: "Cuéntenos qué le pareció, nos encantaría conocer su opinión sincera.", s: "Invitando al cliente a dejar un comentario o reseña.", sEn: "Inviting the customer to leave a comment or review.", n: "'What you think' va sin 'do' aquí porque es una frase afirmativa incrustada, no una pregunta directa.", nEn: "'What you think' takes no 'do' here because it's an embedded statement, not a direct question." },
    "loc-res11": { e: "If you enjoyed your visit, you can rate us five stars on the app.", t: "Si disfrutó su visita, puede calificarnos con cinco estrellas en la app.", s: "Pidiendo amablemente una buena calificación al despedir al cliente.", sEn: "Politely asking for a good rating as you say goodbye to the customer.", n: "Se dice 'rate us', no 'qualify us'; 'qualify' significa otra cosa en inglés.", nEn: "Say 'rate us', not 'qualify us'; 'qualify' means something different in English." },
    "loc-res12": { e: "Post your photo and tag us, we love seeing your pictures!", t: "Suba su foto y etiquétenos, ¡nos encanta ver sus fotos!", s: "Animando a los clientes a compartir su experiencia en redes sociales.", sEn: "Encouraging customers to share their experience on social media.", n: "En redes se dice 'post' para subir y 'tag' para etiquetar; no uses 'upload' al hablar de redes.", nEn: "On social media use 'post' to upload and 'tag' to mention; avoid 'upload' in that context." },
    "loc-res13": { e: "We'll reply to your comment as soon as we can.", t: "Responderemos su comentario lo antes posible.", s: "Cuando alguien deja una pregunta o reseña en línea y aseguras una respuesta.", sEn: "When someone leaves a question or review online and you promise a response.", n: "Se dice 'reply to your comment', con 'to'; nunca 'reply your comment'.", nEn: "Say 'reply to your comment', with 'to'; never 'reply your comment'." },
    "loc-res14": { e: "Thanks for recommending us to your friends, it means a lot!", t: "¡Gracias por recomendarnos a sus amigos, significa mucho!", s: "Cuando un cliente dice que habló bien de tu negocio a otras personas.", sEn: "When a customer says they spoke well of your business to others.", n: "'Recommend' lleva una sola 'c' y doble 'm'; se pronuncia 're-co-MÉND'.", nEn: "'Recommend' has one 'c' and double 'm'; it's said 're-kuh-MEND'." },
    // ===================== Housekeeping (limpieza) =====================
    "loc-lim01": { e: "Housekeeping, may I come in to clean your room?", t: "Servicio de limpieza, ¿puedo pasar a limpiar su cuarto?", s: "Cuando tocas la puerta de un huésped antes de entrar a hacer el aseo.", sEn: "When you knock on a guest's door before entering to clean.", n: "Toca primero, espera unos segundos y di la frase antes de abrir; nunca entres en silencio.", nEn: "Knock first, wait a few seconds, and say the phrase before opening; never enter silently." },
    "loc-lim02": { e: "Shall I clean your room now, or would you prefer later?", t: "¿Le hago el cuarto ahora o prefiere más tarde?", s: "Cuando le preguntas al huésped el mejor momento para hacer la limpieza.", sEn: "When you ask the guest the best moment to do the cleaning.", n: "\"Shall I...?\" suena muy cortés para ofrecer un servicio; es más amable que \"Do you want...?\".", nEn: "\"Shall I...?\" sounds very polite for offering a service; it's softer than \"Do you want...?\"." },
    "loc-lim03": { e: "I'll bring fresh towels and leave them in the bathroom.", t: "Le traigo toallas limpias y las dejo en el baño.", s: "Cuando avisas al huésped que vas a reponer las toallas.", sEn: "When you tell the guest you're going to replace the towels.", n: "\"Fresh\" aquí significa limpias/nuevas, no frías; es la palabra natural para toallas y sábanas.", nEn: "\"Fresh\" here means clean/new, not cold; it's the natural word for towels and sheets." },
    "loc-lim04": { e: "Do you need more soap or shampoo for the bathroom?", t: "¿Necesita más jabón o champú para el baño?", s: "Cuando ofreces reponer los artículos de aseo del huésped.", sEn: "When you offer to restock the guest's toiletries.", n: "\"Shampoo\" se pronuncia \"sham-PÚ\", con el acento en la segunda sílaba.", nEn: "\"Shampoo\" is pronounced \"sham-POO\", with the stress on the second syllable." },
    "loc-lim05": { e: "I've changed the sheets, so the bed is all fresh for you.", t: "Ya cambié las sábanas, así que la cama quedó fresquita para usted.", s: "Cuando le confirmas al huésped que ya pusiste sábanas limpias.", sEn: "When you confirm to the guest that you've put on clean sheets.", n: "\"I've changed\" (present perfect) indica que ya está hecho; suena mejor que \"I changed\" aquí.", nEn: "\"I've changed\" (present perfect) shows it's already done; it sounds better than \"I changed\" here." },
    "loc-lim06": { e: "What time works best for cleaning, morning or afternoon?", t: "¿A qué hora le viene mejor la limpieza, mañana o tarde?", s: "Cuando coordinas con el huésped un horario que no lo moleste.", sEn: "When you arrange with the guest a time that won't disturb them.", n: "\"Works best\" es una forma natural y amable de decir \"le conviene más\".", nEn: "\"Works best\" is a natural, polite way to say \"is most convenient for you\"." },
    "loc-lim07": { e: "No problem, I'll come back later when it's convenient.", t: "No hay problema, vuelvo más tarde cuando le quede bien.", s: "Cuando el huésped está ocupado o descansando y decides regresar después.", sEn: "When the guest is busy or resting and you decide to return afterward.", n: "Acompáñalo de una sonrisa y \"no problem\" para que no suene como molestia.", nEn: "Pair it with a smile and \"no problem\" so it doesn't sound like an inconvenience." },
    "loc-lim08": { e: "Hang the sign on the door if you don't want to be disturbed.", t: "Cuelgue el letrero en la puerta si no desea que lo molesten.", s: "Cuando le explicas al huésped cómo pedir privacidad con el letrero.", sEn: "When you explain to the guest how to ask for privacy with the sign.", n: "\"Do not disturb\" es el texto exacto del letrero; puedes señalarlo al decirlo.", nEn: "\"Do not disturb\" is the exact wording on the sign; you can point to it as you say it." },
    "loc-lim09": { e: "Here is some toilet paper, I'll leave extra under the sink.", t: "Aquí tiene papel higiénico, le dejo más debajo del lavamanos.", s: "Cuando repones el papel higiénico en el baño del huésped.", sEn: "When you restock the toilet paper in the guest's bathroom.", n: "\"Toilet paper\" es incontable, por eso se dice \"some\" y no \"a toilet paper\".", nEn: "\"Toilet paper\" is uncountable, so you say \"some\" and not \"a toilet paper\"." },
    "loc-lim10": { e: "Shall I restock the minibar while I'm here?", t: "¿Le repongo el minibar ya que estoy aquí?", s: "Cuando ofreces rellenar las bebidas y snacks del minibar durante la limpieza.", sEn: "When you offer to refill the minibar drinks and snacks during cleaning.", n: "\"Restock\" se pronuncia \"ri-STOK\"; significa volver a llenar las existencias.", nEn: "\"Restock\" is pronounced \"ree-STOCK\"; it means to fill the supplies back up." },
    "loc-lim11": { e: "I found this in your room when I was cleaning, is it yours?", t: "Encontré esto en su cuarto cuando estaba limpiando, ¿es suyo?", s: "Cuando, limpiando, encuentras un objeto olvidado por el huésped.", sEn: "When, while cleaning, you find an item the guest left behind.", n: "Suena mas amable si agregas 'I think' al inicio: 'I think I found this in your room.'", nEn: "It sounds gentler if you add 'I think' at the start: 'I think I found this in your room.'" },
    "loc-lim12": { e: "Everything is ready for you, have a good rest.", t: "Todo está listo para usted, que descanse.", s: "Al salir del cuarto después de limpiarlo, te despides del huésped.", sEn: "As you leave the room after cleaning, you say goodbye to the guest.", n: "También puedes decir 'Enjoy your rest' o, de noche, 'Sleep well.'", nEn: "You can also say 'Enjoy your rest' or, at night, 'Sleep well.'" },
    // ===================== Spa & massage (spa-en) =====================
    "loc-spa01": { e: "Welcome, would you like a massage to start your treatment?", t: "Bienvenido, ¿le gustaría un masaje para comenzar su tratamiento?", s: "Al recibir al cliente en el spa y ofrecerle un servicio.", sEn: "When greeting the client at the spa and offering a service.", n: "'Would you like' es más cortés que 'Do you want'; úsalo con clientes.", nEn: "'Would you like' is more polite than 'Do you want'; use it with clients." },
    "loc-spa02": { e: "Before we begin, do you prefer soft or firm pressure?", t: "Antes de empezar, ¿prefiere presión suave o fuerte?", s: "Antes de iniciar el masaje, para ajustarlo al gusto del cliente.", sEn: "Before starting the massage, to tailor it to the client's preference.", n: "'Firm' se usa más que 'strong' para presión de masaje; 'strong' suena a fuerza bruta.", nEn: "'Firm' is more common than 'strong' for massage pressure; 'strong' sounds like brute force." },
    "loc-spa03": { e: "Please lie face down and rest your head in the cradle.", t: "Por favor acuéstese boca abajo y apoye la cabeza en el soporte.", s: "Cuando indicas al cliente cómo posicionarse en la camilla.", sEn: "When you tell the client how to position themselves on the table.", n: "El opuesto es 'face up'; di 'face down' lento, la 'd' final casi no suena.", nEn: "The opposite is 'face up'; say 'face down' slowly, the final 'd' is barely voiced." },
    "loc-spa04": { e: "Just relax and let your shoulders drop.", t: "Solo relájese y deje caer los hombros.", s: "Al empezar el masaje, para que el cliente suelte la tensión.", sEn: "At the start of the massage, to help the client release tension.", n: "Pronuncia 'relax' con acento en la segunda sílaba: re-LAX, no RE-lax.", nEn: "Stress 'relax' on the second syllable: re-LAX, not RE-lax." },
    "loc-spa05": { e: "Let me know if anything bothers you or feels too strong.", t: "Avíseme si le molesta algo o si lo siente muy fuerte.", s: "Durante el masaje, para que el cliente avise sobre incomodidad.", sEn: "During the massage, so the client can flag any discomfort.", n: "'Let me know' es más natural que 'tell me' para invitaciones amables.", nEn: "'Let me know' sounds more natural than 'tell me' for polite invitations." },
    "loc-spa06": { e: "The massage lasts one hour, so we have plenty of time.", t: "El masaje dura una hora, así que tenemos bastante tiempo.", s: "Cuando informas al cliente cuánto durará el servicio.", sEn: "When you tell the client how long the service will take.", n: "Cuidado: 'lasts' no es 'last week'; aquí significa 'dura'.", nEn: "Note: 'lasts' here means 'has a duration of', not 'last week'." },
    "loc-spa07": { e: "Do you have any injuries I should know about before we start?", t: "¿Tiene alguna lesión que deba saber antes de empezar?", s: "En la consulta inicial, para evitar lastimar al cliente.", sEn: "During the initial check, to avoid hurting the client.", n: "'Injury' se dice 'IN-yu-ri'; no confundir con 'pain' (dolor).", nEn: "'Injury' is said 'IN-juh-ree'; don't confuse it with 'pain'." },
    "loc-spa08": { e: "Breathe deeply and slowly, it will help you relax.", t: "Respire profundo y despacio, le ayudará a relajarse.", s: "Durante el masaje, para guiar la relajación del cliente.", sEn: "During the massage, to guide the client into relaxation.", n: "'Breathe' es el verbo; 'breath' (sin e final) es el sustantivo.", nEn: "'Breathe' is the verb; 'breath' (no final e) is the noun." },
    "loc-spa09": { e: "Is the temperature okay, or would you like a blanket?", t: "¿La temperatura está bien, o le gustaría una manta?", s: "Cuando revisas si el cliente está cómodo en la sala.", sEn: "When you check whether the client is comfortable in the room.", n: "'Temperature' se pronuncia 'TEM-pruh-cher', con tres sílabas, no cuatro.", nEn: "'Temperature' is said 'TEM-pruh-cher', in three syllables, not four." },
    "loc-spa10": { e: "There's no rush, take your time getting up.", t: "No hay prisa, tómese su tiempo para levantarse.", s: "Al terminar el masaje, para que el cliente se levante con calma.", sEn: "After the massage, so the client can get up at their own pace.", n: "'Take your time' suena amable; evita 'go slow', que puede sonar tosco.", nEn: "'Take your time' sounds kind; avoid 'go slow', which can sound blunt." },
    "loc-spa11": { e: "I recommend drinking water after the massage to feel refreshed.", t: "Le recomiendo tomar agua después del masaje para sentirse renovado.", s: "Al despedir al cliente, dándole un consejo de cuidado.", sEn: "When seeing the client off, giving an aftercare tip.", n: "Después de 'recommend' usa el verbo en -ing: 'recommend drinking', no 'to drink'.", nEn: "After 'recommend' use the -ing form: 'recommend drinking', not 'to drink'." },
    "loc-spa12": { e: "Thank you for coming, I hope you feel better soon.", t: "Gracias por venir, espero que se sienta mejor pronto.", s: "Al despedir a un cliente que llegó con dolor o tensión.", sEn: "When saying goodbye to a client who came in with pain or tension.", n: "'I hope you feel better' es la frase fija; no digas 'I hope you feel good'.", nEn: "'I hope you feel better' is the set phrase; don't say 'I hope you feel good'." },
    // ===================== Boat & islands (lancha-en) =====================
    "loc-lan01": { e: "Welcome aboard, everyone, please find a seat.", t: "Bienvenidos a bordo, por favor busquen un asiento.", s: "Al recibir a los pasajeros cuando suben al bote.", sEn: "When greeting passengers as they board the boat.", n: "'Aboard' se usa en barcos y aviones; en tierra di 'Welcome' a secas.", nEn: "'Aboard' is for boats and planes; on land just say 'Welcome'." },
    "loc-lan02": { e: "For your safety, please put on your life jacket now.", t: "Por su seguridad, pónganse el chaleco salvavidas ahora.", s: "Antes de zarpar, cuando das las instrucciones de seguridad.", sEn: "Before setting off, when you give the safety instructions.", n: "'Put on' es ponerse; no lo confundas con 'wear', que es ya tenerlo puesto.", nEn: "'Put on' means to don it; don't confuse it with 'wear', which means already having it on." },
    "loc-lan03": { e: "We leave at nine sharp, so please be on time.", t: "Salimos a las nueve en punto, así que por favor sean puntuales.", s: "Cuando informas la hora exacta de salida a los pasajeros.", sEn: "When telling passengers the exact departure time.", n: "'Nine sharp' significa 'nueve en punto, ni un minuto más'; muy útil con turistas.", nEn: "'Nine sharp' means 'nine o'clock exactly, not a minute later'; handy with tourists." },
    "loc-lan04": { e: "Snorkeling is included in the tour, so bring your swimsuit.", t: "El esnórquel está incluido en el tour, así que traigan su traje de baño.", s: "Al explicar qué actividades cubre el paseo en bote.", sEn: "When explaining what activities the boat trip covers.", n: "Se escribe 'snorkeling' y se dice 'SNOR-kuh-ling'; no 'esnorkel'.", nEn: "It's spelled 'snorkeling' and said 'SNOR-kuh-ling'; not 'esnorkel'." },
    "loc-lan05": { e: "The sea is a bit rough today, so please hold on tight.", t: "El mar está un poco picado hoy, así que agárrense bien.", s: "Cuando hay oleaje y debes advertir a los pasajeros.", sEn: "When the water is choppy and you need to warn passengers.", n: "'Rough sea' es mar picado; 'a bit' suaviza y evita asustar a la gente.", nEn: "'Rough sea' means choppy water; 'a bit' softens it so you don't scare people." },
    "loc-lan06": { e: "Please sit down and hold on, we're picking up speed.", t: "Por favor siéntense y agárrense, vamos a acelerar.", s: "Justo antes de que el bote acelere o haya olas.", sEn: "Right before the boat speeds up or hits waves.", n: "'Hold on' solo o 'hold on tight' para enfatizar; ambos suenan naturales.", nEn: "Use 'hold on' alone or 'hold on tight' for emphasis; both sound natural." },
    "loc-lan07": { e: "We return to the dock at three, so please be back at the boat by ten to three.", t: "Volvemos al muelle a las tres, así que por favor estén de vuelta en el bote diez para las tres.", s: "Cuando, como guía o capitán, le dices al grupo a qué hora termina el paseo en lancha.", sEn: "When, as a guide or skipper, you tell the group what time the boat trip ends.", n: "Di 'dock' como 'dok' con la 'o' corta; no lo confundas con 'doc' (doctor).", nEn: "Say 'dock' with a short 'o' like 'dok'; don't confuse it with 'doc' (doctor)." },
    "loc-lan08": { e: "Don't forget your sunscreen, the sun gets really strong out on the water.", t: "No olviden el protector solar, el sol se pone muy fuerte allá en el agua.", s: "Cuando recuerdas a los pasajeros llevar protección solar antes de salir al mar.", sEn: "When you remind passengers to bring sun protection before heading out to sea.", n: "También puedes decir 'sunblock'; 'sunscreen' es lo más común a nivel internacional.", nEn: "You can also say 'sunblock'; 'sunscreen' is the most internationally common word." },
    "loc-lan09": { e: "You can swim here, it's safe, but please stay close to the boat.", t: "Pueden nadar aquí, es seguro, pero por favor quédense cerca del bote.", s: "Cuando das permiso al grupo para meterse al agua en una parada del paseo.", sEn: "When you give the group the go-ahead to get in the water at a stop on the trip.", n: "'Safe' suena 'seif'; evita pronunciar la 'e' final, que es muda.", nEn: "'Safe' sounds like 'seif'; don't pronounce the final 'e', it's silent." },
    "loc-lan10": { e: "Careful getting off the boat, the step is wet and slippery.", t: "Cuidado al bajar del bote, el escalón está mojado y resbaloso.", s: "Cuando ayudas a los pasajeros a descender de la lancha de forma segura.", sEn: "When you help passengers step down from the boat safely.", n: "Para sonar más amable agrega 'please': 'Please be careful getting off the boat'.", nEn: "To sound friendlier add 'please': 'Please be careful getting off the boat'." },
    "loc-lan11": { e: "Lunch is served on the island around noon, and it's already included in the tour.", t: "El almuerzo se sirve en la isla alrededor del mediodía, y ya está incluido en el tour.", s: "Cuando explicas al grupo dónde y cuándo comerán durante el paseo.", sEn: "When you explain to the group where and when they'll eat during the trip.", n: "Usa 'is served' (voz pasiva) para sonar profesional; 'we serve lunch' también vale.", nEn: "Use 'is served' (passive) to sound professional; 'we serve lunch' also works." },
    "loc-lan12": { e: "Everyone aboard? Great, enjoy the ride!", t: "¿Todos a bordo? Perfecto, ¡disfruten el paseo!", s: "Cuando, justo antes de arrancar, animas al grupo a disfrutar el recorrido.", sEn: "When, right before setting off, you tell the group to enjoy the trip.", n: "'Ride' sirve para lancha, bus o cualquier paseo; 'enjoy the trip' es la versión más formal.", nEn: "'Ride' works for a boat, bus, or any trip; 'enjoy the trip' is the more formal version." },
    // ===================== Check-out (checkout-en) =====================
    "loc-cko01": { e: "Good morning! Are you ready to check out?", t: "¡Buenos días! ¿Está listo para hacer el check-out?", s: "Cuando un huésped llega a recepción para dejar el hotel.", sEn: "When a guest comes to the front desk to leave the hotel.", n: "'Check out' como verbo va separado; 'check-out' con guion es el sustantivo.", nEn: "'Check out' as a verb is two words; 'check-out' with a hyphen is the noun." },
    "loc-cko02": { e: "Did you enjoy your stay with us?", t: "¿Disfrutó su estadía con nosotros?", s: "Cuando preguntas al huésped cómo le fue justo antes de que se vaya.", sEn: "When you ask the guest how things went just before they leave.", n: "Agregar 'with us' suena más cálido y personal que solo 'your stay'.", nEn: "Adding 'with us' sounds warmer and more personal than just 'your stay'." },
    "loc-cko03": { e: "Here is your bill, please take a moment to look it over.", t: "Aquí tiene su cuenta, tómese un momento para revisarla.", s: "Cuando entregas la factura al huésped al momento de pagar.", sEn: "When you hand the guest the invoice at the moment of payment.", n: "En hotel/restaurante se usa 'bill'; 'check' es más típico de EE. UU. en restaurantes.", nEn: "In a hotel/restaurant use 'bill'; 'check' is more typical in US restaurants." },
    "loc-cko04": { e: "Did you use anything from the minibar during your stay?", t: "¿Usó algo del minibar durante su estadía?", s: "Cuando verificas consumos antes de cerrar la cuenta del huésped.", sEn: "When you check for charges before closing out the guest's bill.", n: "'Anything' es para preguntas; en afirmativo usarías 'something'.", nEn: "'Anything' is for questions; in a statement you'd use 'something'." },
    "loc-cko05": { e: "How would you like to pay, by card or in cash?", t: "¿Cómo desea pagar, con tarjeta o en efectivo?", s: "Cuando le preguntas al huésped su método de pago al hacer el check-out.", sEn: "When you ask the guest their payment method at check-out.", n: "'Would you like' es más cortés que 'How do you want to pay?'.", nEn: "'Would you like' is more polite than 'How do you want to pay?'." },
    "loc-cko06": { e: "Do you need a taxi to the airport? I can call one for you.", t: "¿Necesita un taxi al aeropuerto? Puedo pedirle uno.", s: "Cuando ofreces ayuda con el transporte después de que el huésped paga.", sEn: "When you offer transport help after the guest has paid.", n: "Ofrecer un extra ('I can call one for you') deja una buena última impresión.", nEn: "Offering an extra ('I can call one for you') leaves a good final impression." },
    "loc-cko07": { e: "Shall I store your luggage until your flight this evening?", t: "¿Le guardo el equipaje hasta su vuelo de esta tarde?", s: "Cuando el huésped ya hizo check-out pero su transporte sale más tarde.", sEn: "When the guest has checked out but their ride leaves later.", n: "'Shall I…?' suena muy profesional para ofrecer un servicio; 'Should I…?' también vale.", nEn: "'Shall I…?' sounds very professional when offering a service; 'Should I…?' also works." },
    "loc-cko08": { e: "Just a reminder, check-out is by noon, but we can hold your bags after that.", t: "Solo un recordatorio, la salida es hasta el mediodía, pero podemos guardar sus maletas después de eso.", s: "Cuando informas al huésped el límite de hora para desocupar la habitación.", sEn: "When you tell the guest the deadline to vacate the room.", n: "'By noon' significa 'a más tardar al mediodía'; no confundir con 'at noon' (exactamente).", nEn: "'By noon' means 'no later than noon'; don't confuse it with 'at noon' (exactly then)." },
    "loc-cko09": { e: "Thank you for staying with us, it was a pleasure having you.", t: "Gracias por hospedarse con nosotros, fue un placer tenerlo aquí.", s: "Cuando te despides del huésped al terminar el check-out.", sEn: "When you say goodbye to the guest as check-out finishes.", n: "Añadir 'it was a pleasure having you' suena cálido y muy hospitalario.", nEn: "Adding 'it was a pleasure having you' sounds warm and very hospitable." },
    "loc-cko10": { e: "Safe travels, and we hope to see you again soon!", t: "Buen viaje, ¡y esperamos verlo de nuevo pronto!", s: "Cuando deseas al huésped un buen regreso y lo invitas a volver.", sEn: "When you wish the guest a good trip back and invite them to return.", n: "'We hope to see you again' es estándar; agregar 'soon' lo hace más cercano.", nEn: "'We hope to see you again' is standard; adding 'soon' makes it warmer." },
    "loc-cko11": { e: "Did you forget anything in the room? I can have someone check for you.", t: "¿Olvidó algo en el cuarto? Puedo pedir que alguien lo revise.", s: "Cuando confirmas que el huésped no dejó pertenencias antes de irse.", sEn: "When you confirm the guest didn't leave belongings before leaving.", n: "'Forget' en pasado es 'forgot'; aquí la pregunta usa 'Did you forget…?'.", nEn: "The past of 'forget' is 'forgot'; here the question uses 'Did you forget…?'." },
    "loc-cko12": { e: "Have a safe trip back, and take care!", t: "Buen viaje de regreso, ¡y que le vaya bien!", s: "Cuando das la despedida final al huésped que sale del hotel.", sEn: "When you give the final goodbye to a guest leaving the hotel.", n: "Una variante muy natural es 'Safe travels back home!'.", nEn: "A very natural variant is 'Safe travels back home!'." },
    // ===================== Hair & barber (peluqueria) =====================
    "loc-pel01": { e: "Have a seat. How would you like your haircut today?", t: "Tome asiento. ¿Cómo desea el corte hoy?", s: "Cuando el cliente se sienta y le preguntas qué estilo de corte quiere.", sEn: "When the client sits down and you ask what style of cut they want.", n: "También puedes decir 'What are we doing today?', muy común en barberías.", nEn: "You can also say 'What are we doing today?', very common in barbershops." },
    "loc-pel02": { e: "A little shorter on the sides? I'll leave the top as it is.", t: "¿Un poco más corto a los lados? Dejo la parte de arriba como está.", s: "Cuando confirmas con el cliente cuánto cortar antes de empezar.", sEn: "When you confirm with the client how much to cut before starting.", n: "'Sides' se dice 'saids'; para arriba di 'the top' y para atrás 'the back'.", nEn: "'Sides' sounds like 'saids'; use 'the top' for the top and 'the back' for the back." },
    "loc-pel03": { e: "Before we start, shall I wash your hair, or would you prefer it dry?", t: "Antes de empezar, ¿le lavo el cabello o lo prefiere seco?", s: "Cuando el cliente se sienta en la silla y quieres saber si lava antes de cortar.", sEn: "When the client sits down and you want to know whether to wash before cutting.", n: "\"Shall I...?\" suena formal y amable para ofrecer un servicio; también puedes decir \"Would you like me to wash your hair?\".", nEn: "\"Shall I...?\" sounds polite and professional for offering a service; you can also say \"Would you like me to wash your hair?\"." },
    "loc-pel04": { e: "Would you like a beard trim while you're here, or just the haircut today?", t: "¿Quiere que le recorte la barba mientras está aquí, o solo el corte hoy?", s: "Cuando ofreces un servicio extra a un cliente que vino por un corte.", sEn: "When you offer an extra service to a client who came in for a haircut.", n: "\"Trim\" se pronuncia con una sola sílaba corta, no \"ti-rim\"; significa recortar, no rapar.", nEn: "\"Trim\" is one short syllable, not \"ti-rim\"; it means to neaten, not to shave off." },
    "loc-pel05": { e: "I've finished the sides, is this okay or would you like it shorter?", t: "Ya terminé los lados, ¿así está bien o lo quiere más corto?", s: "Cuando muestras tu avance y confirmas si al cliente le gusta.", sEn: "When you show your progress and confirm whether the client likes it.", n: "Para sonar más natural puedes decir \"Is this okay for you?\" o, más casual, \"Looks good?\".", nEn: "To sound more natural you can say \"Is this okay for you?\" or, more casually, \"Looks good?\"." },
    "loc-pel06": { e: "Shall I blow-dry your hair, or do you prefer to leave it air-dry?", t: "¿Le seco el cabello, o prefiere dejarlo secar al aire?", s: "Al terminar el corte, cuando ofreces secar el cabello antes de que se vaya.", sEn: "After the cut, when you offer to dry the hair before they leave.", n: "\"Blow-dry\" es el término correcto; evita \"dry with the machine\", que suena raro en inglés.", nEn: "\"Blow-dry\" is the correct term; avoid \"dry with the machine,\" which sounds odd in English." },
    "loc-pel07": { e: "Have a seat, please, and I'll be right with you.", t: "Siéntese, por favor, y en un momento lo atiendo.", s: "Cuando un cliente llega y le indicas dónde sentarse para empezar.", sEn: "When a client arrives and you direct them where to sit to begin.", n: "\"Have a seat\" es más cálido que \"Sit down\", que puede sonar como una orden.", nEn: "\"Have a seat\" is warmer than \"Sit down,\" which can sound like a command." },
    "loc-pel08": { e: "Would you like to see the back before I take the cape off?", t: "¿Quiere ver la parte de atrás antes de que le quite la capa?", s: "Al terminar, cuando le ofreces el espejo para que revise la nuca.", sEn: "When you finish and offer the mirror so they can check the back.", n: "Puedes acompañarlo con un gesto del espejo y añadir \"...in the mirror?\" para que quede claro.", nEn: "You can pair it with the mirror and add \"...in the mirror?\" to make it clear." },
    "loc-pel09": { e: "The haircut is twenty thousand, and a beard trim would be five thousand more.", t: "El corte cuesta veinte mil, y el recorte de barba serían cinco mil más.", s: "Cuando le dices el precio al cliente antes de cobrar.", sEn: "When you tell the client the price before charging.", n: "En inglés se dice \"twenty thousand\" sin \"of pesos\"; el contexto ya indica la moneda.", nEn: "In English say \"twenty thousand\" without \"of pesos\"; context already implies the currency." },
    "loc-pel10": { e: "Do you like the length, or should I take off a bit more?", t: "¿Le gusta el largo, o le quito un poquito más?", s: "Cuando confirmas con el cliente si está conforme con cuánto cortaste.", sEn: "When you confirm with the client whether they're happy with how much you cut.", n: "\"Length\" se pronuncia \"lenkz\", con la 'th' final suave; no lo digas como \"leng\".", nEn: "\"Length\" ends with a soft 'th' sound; don't drop it and say \"leng\"." },
    "loc-pel11": { e: "Please don't move for a second, I'm doing the edges around your ear.", t: "Por favor, no se mueva un segundo, estoy haciendo los bordes alrededor de la oreja.", s: "Cuando haces un detalle delicado y necesitas que el cliente se quede quieto.", sEn: "When you're doing a delicate detail and need the client to stay still.", n: "Añadir \"for a second\" lo hace sonar más amable que un seco \"Don't move\".", nEn: "Adding \"for a second\" sounds friendlier than a blunt \"Don't move\"." },
    "loc-pel12": { e: "Looking sharp! See you in a month for a touch-up?", t: "¡Se ve muy bien! ¿Nos vemos en un mes para un retoque?", s: "Cuando te despides del cliente e invitas a que vuelva pronto.", sEn: "When you say goodbye and invite the client to come back soon.", n: "\"See you in a month?\" suena amistoso; \"touch-up\" es la palabra para un retoque rápido.", nEn: "\"See you in a month?\" sounds friendly; \"touch-up\" is the word for a quick retouch." },
    // ===================== Renting & home (vivienda) =====================
    "loc-viv01": { e: "Welcome to the apartment, let me show you around real quick.", t: "Bienvenido al apartamento, déjeme mostrarle todo rapidito.", s: "Cuando recibes a un inquilino o huésped que llega por primera vez.", sEn: "When you welcome a tenant or guest arriving for the first time.", n: "\"Show you around\" significa enseñar el lugar; es la frase natural para una visita guiada de la casa.", nEn: "\"Show you around\" means to give a tour; it's the natural phrase for walking through the home." },
    "loc-viv02": { e: "Just a reminder: the rent is due on the first of each month.", t: "Solo un recordatorio: el arriendo se paga el día uno de cada mes.", s: "Cuando le explicas al inquilino cuándo debe pagar.", sEn: "When you explain to the tenant when payment is due.", n: "\"Due\" se pronuncia \"diu\" y significa \"que se debe pagar\"; no lo confundas con \"do\".", nEn: "\"Due\" sounds like \"dyoo\" and means \"owed/payable\"; don't confuse it with \"do\"." },
    "loc-viv03": { e: "Here are the keys, this big one is for the front door.", t: "Aquí están las llaves, esta grande es de la puerta principal.", s: "Cuando entregas las llaves y explicas para qué es cada una.", sEn: "When you hand over the keys and explain what each one is for.", n: "\"Keys\" siempre lleva la 's' al final cuando hay más de una; \"key\" es solo una.", nEn: "\"Keys\" needs the final 's' when there's more than one; \"key\" is just one." },
    "loc-viv04": { e: "Good news: wifi and water are included in the rent.", t: "Buena noticia: el wifi y el agua están incluidos en el arriendo.", s: "Cuando aclaras qué servicios no se pagan aparte.", sEn: "When you clarify which utilities aren't paid separately.", n: "\"Included\" lleva el acento en la segunda sílaba: in-CLU-ded.", nEn: "\"Included\" is stressed on the second syllable: in-CLU-ded." },
    "loc-viv05": { e: "The AC controls are here on the wall, just press this button to turn it on.", t: "El aire acondicionado se controla aquí en la pared, solo presione este botón para encenderlo.", s: "Cuando le muestras al inquilino cómo usar el aire acondicionado.", sEn: "When you show the tenant how to use the air conditioning.", n: "\"AC\" es la forma corta y común de \"air conditioning\"; se dice \"ei-si\".", nEn: "\"AC\" is the short, common form of \"air conditioning,\" pronounced \"ay-see\"." },
    "loc-viv06": { e: "Please don't smoke inside, but you're welcome to use the balcony.", t: "Por favor, no fume adentro, pero puede usar el balcón.", s: "Cuando explicas las reglas de la casa a un inquilino o huésped.", sEn: "When you explain the house rules to a tenant or guest.", n: "Ofrecer una alternativa (\"but you're welcome to...\") suaviza la regla y suena más amable.", nEn: "Offering an alternative (\"but you're welcome to...\") softens the rule and sounds friendlier." },
    "loc-viv07": { e: "The trash goes out on Tuesdays, just leave the bag by the gate.", t: "La basura se saca los martes, solo deje la bolsa junto a la reja.", s: "Cuando le explicas al inquilino el día de recolección de basura.", sEn: "When you tell the tenant which day the trash is collected.", n: "\"Trash\" es común en EE.UU. y \"rubbish\" en el Reino Unido, pero ambos te entenderán.", nEn: "\"Trash\" is common in the US and \"rubbish\" in the UK, but both will understand you." },
    "loc-viv08": { e: "If anything breaks, let me know and I'll send someone to fix it.", t: "Si algo se daña, avíseme y mando a alguien a arreglarlo.", s: "Cuando le pides al inquilino que reporte cualquier problema en la casa.", sEn: "When you ask the tenant to report any problem in the home.", n: "\"Let me know\" es la forma natural de decir \"avíseme\"; suena mejor que \"tell me\".", nEn: "\"Let me know\" is the natural way to say \"avíseme\"; it sounds better than \"tell me\"." },
    "loc-viv09": { e: "Sorry about the heat, I'll fix the AC tomorrow morning.", t: "Disculpe el calor, mañana en la mañana arreglo el aire.", s: "Cuando le prometes al inquilino reparar algo al día siguiente.", sEn: "When you promise the tenant to repair something the next day.", n: "\"I'll fix\" usa \"will\" para promesas hechas en el momento; suena seguro y profesional.", nEn: "\"I'll fix\" uses \"will\" for on-the-spot promises; it sounds confident and professional." },
    "loc-viv10": { e: "The deposit is returned at the end if there's no damage.", t: "El depósito se devuelve al final si no hay daños.", s: "Cuando explicas las condiciones para recuperar el depósito.", sEn: "When you explain the conditions for getting the deposit back.", n: "\"Deposit\" lleva el acento en la segunda sílaba: de-PO-sit.", nEn: "\"Deposit\" is stressed on the second syllable: de-PO-sit." },
    "loc-viv11": { e: "Text me if you need anything, day or night.", t: "Escríbame si necesita algo, de día o de noche.", s: "Cuando le entregas el apartamento al inquilino y le dejas tu contacto.", sEn: "When you hand over the apartment to a tenant and give them your contact.", n: "\"Text me\" suena casual; con un cliente formal di \"Just message me\" o \"Feel free to reach out.\"", nEn: "\"Text me\" sounds casual; for a formal guest say \"Just message me\" or \"Feel free to reach out.\"" },
    "loc-viv12": { e: "Please lock the door when you leave, even for a few minutes.", t: "Por favor cierre bien la puerta al salir, aunque sea por unos minutos.", s: "Cuando le explicas al huésped las reglas de seguridad de la vivienda.", sEn: "When you explain the home's safety rules to the guest.", n: "\"Lock\" se pronuncia \"lok\", no confundas con \"look\" (mirar), que suena \"luk\".", nEn: "\"Lock\" sounds like \"lok\"; don't confuse it with \"look\", which sounds like \"luk\"." },
    // ===================== The weather (clima-en) =====================
    "loc-clm01": { e: "It's really hot today, so let me bring you some cold water.", t: "Hace mucho calor hoy, así que déjeme traerle agua fría.", s: "Cuando hace conversación con un cliente mientras lo atiendes en un día caluroso.", sEn: "When you make small talk with a guest while serving them on a hot day.", n: "Para el clima siempre usa \"it's\" (it is), no \"have\" como en español (\"hace calor\").", nEn: "For weather always use \"it's\" (it is), not \"have\" like in Spanish (\"hace calor\")." },
    "loc-clm02": { e: "It's cloudy this morning, but it should clear up by noon.", t: "Está nublado esta mañana, pero debería despejarse al mediodía.", s: "Cuando un turista te pregunta si vale la pena salir y comentas el cielo.", sEn: "When a tourist asks if it's worth going out and you comment on the sky.", n: "\"Cloudy\" termina en sonido \"di\"; otra opción útil es \"overcast\" para un cielo muy gris.", nEn: "\"Cloudy\" ends in a \"dee\" sound; another useful option is \"overcast\" for a very grey sky." },
    "loc-clm03": { e: "It looks like rain, so you might want to take a jacket.", t: "Parece que va a llover, así que quizá quiera llevar una chaqueta.", s: "Cuando aconsejas a un huésped antes de que salga a pasear.", sEn: "When you advise a guest before they head out for a walk.", n: "También puedes decir \"It looks like it's going to rain\"; ambas son naturales.", nEn: "You can also say \"It looks like it's going to rain\"; both sound natural." },
    "loc-clm04": { e: "It's very humid today, so take it easy and stay hydrated.", t: "Hay mucha humedad hoy, así que tómelo con calma y manténgase hidratado.", s: "Cuando un visitante siente el calor pegajoso y le explicas el clima de la zona.", sEn: "When a visitor feels the sticky heat and you explain the area's climate.", n: "\"Humid\" se pronuncia \"HIÚ-mid\", con la h suave; no la dejes muda como en español.", nEn: "\"Humid\" is pronounced \"HYOO-mid\", with a soft h; don't drop it like in Spanish." },
    "loc-clm05": { e: "Take an umbrella just in case, the weather changes fast here.", t: "Lleve un paraguas por si acaso, el clima cambia rápido aquí.", s: "Cuando recomiendas a un turista qué llevar antes de un tour.", sEn: "When you recommend to a tourist what to bring before a tour.", n: "\"Just in case\" es la frase clave para \"por si acaso\"; memorízala como bloque.", nEn: "\"Just in case\" is the key phrase for \"por si acaso\"; memorize it as a chunk." },
    "loc-clm06": { e: "It's cool at night, so you'll want a light sweater.", t: "Hace fresco en la noche, así que va a querer un suéter ligero.", s: "Cuando le adviertes a un huésped sobre el cambio de temperatura en la tarde.", sEn: "When you warn a guest about the temperature drop in the evening.", n: "\"Cool\" es fresco (agradable); \"cold\" es frío de verdad; no los mezcles.", nEn: "\"Cool\" means pleasantly fresh; \"cold\" means truly cold; don't mix them up." },
    "loc-clm07": { e: "The sun rises early here, so the beach is beautiful at dawn.", t: "El sol sale temprano aquí, así que la playa es hermosa al amanecer.", s: "Cuando recomiendas a un turista madrugar para ver el amanecer.", sEn: "When you suggest a tourist get up early to see the sunrise.", n: "Se dice \"the sun rises\" (sale) y \"the sun sets\" (se pone); no uses \"goes out.\"", nEn: "Say \"the sun rises\" and \"the sun sets\"; don't use \"goes out.\"" },
    "loc-clm08": { e: "What a nice day, it's perfect for a walk by the water.", t: "Qué día tan bonito, está perfecto para caminar junto al agua.", s: "Cuando saludas a un cliente y comentas el buen tiempo para romper el hielo.", sEn: "When you greet a guest and comment on the good weather to break the ice.", n: "\"What a nice day!\" lleva \"a\"; nunca digas \"What nice day\" sin el artículo.", nEn: "\"What a nice day!\" needs \"a\"; never say \"What nice day\" without the article." },
    "loc-clm09": { e: "Rain is expected in the afternoon, so let's do the tour this morning.", t: "Se espera lluvia en la tarde, así que hagamos el tour esta mañana.", s: "Cuando reorganizas el plan del día con base en el pronóstico.", sEn: "When you rearrange the day's plan based on the forecast.", n: "\"Rain is expected\" es voz pasiva, ideal para sonar profesional al dar el pronóstico.", nEn: "\"Rain is expected\" is passive voice, ideal to sound professional when giving the forecast." },
    "loc-clm10": { e: "It's windy down by the dock, so hold on to your hat.", t: "Hace viento allá en el muelle, así que sujete su sombrero.", s: "Cuando avisas a los pasajeros del viento antes de subir al bote.", sEn: "When you warn passengers about the wind before boarding the boat.", n: "\"Windy\" se pronuncia \"UÍN-di\"; la w en inglés no suena como \"gu\" del español.", nEn: "\"Windy\" is pronounced \"WIN-dee\"; the English w isn't the Spanish \"gu\" sound." },
    "loc-clm11": { e: "The rainy season starts soon, so prices go down after July.", t: "La temporada de lluvias empieza pronto, así que los precios bajan después de julio.", s: "Cuando le explicas a un turista cuándo conviene viajar a la zona.", sEn: "When you explain to a tourist the best time to visit the area.", n: "Lo opuesto es \"the dry season\"; ambas frases son muy útiles en turismo.", nEn: "The opposite is \"the dry season\"; both phrases are very useful in tourism." },
    "loc-clm12": { e: "It's clear today, so you'll get a great view from the top.", t: "Hoy está despejado, así que tendrá una vista increíble desde la cima.", s: "Cuando animas a un visitante a subir a un mirador por el buen cielo.", sEn: "When you encourage a visitor to go up to a lookout thanks to the clear sky.", n: "\"Clear\" sirve para el cielo y también para \"quedó claro\"; cuida el contexto.", nEn: "\"Clear\" works for the sky and also for \"understood\"; mind the context." },
    // ===================== CV & cover letter (cv-en) =====================
    "loc-cv01": { e: "I'm applying for the position of front desk receptionist.", t: "Me postulo para el puesto de recepcionista.", s: "Cuando escribes la primera línea de tu carta de presentación o correo.", sEn: "When you write the opening line of your cover letter or email.", n: "Di \"apply for\" un puesto, nunca \"apply to\" el puesto; \"to\" se usa con empresas.", nEn: "Say \"apply for\" a position, never \"apply to\" the position; \"to\" is used with companies." },
    "loc-cv02": { e: "I'm attaching my CV and references for your review.", t: "Adjunto mi hoja de vida y referencias para su revisión.", s: "Cuando envías un correo de postulación con tus documentos.", sEn: "When you send a job application email with your documents.", n: "En EE. UU. se usa \"resume\"; \"CV\" es más común en UK y LatAm, ambos se entienden.", nEn: "In the US people say \"resume\"; \"CV\" is more common in the UK and LatAm, both are understood." },
    "loc-cv03": { e: "I have five years of experience in customer service.", t: "Tengo cinco años de experiencia en servicio al cliente.", s: "Cuando resumes tu trayectoria en una entrevista o carta.", sEn: "When you summarize your background in an interview or letter.", n: "Di \"years of experience\", con \"of\"; omitirlo (\"years experience\") suena incorrecto.", nEn: "Say \"years of experience\", with \"of\"; dropping it (\"years experience\") sounds wrong." },
    "loc-cv04": { e: "My strengths are punctuality and organization.", t: "Mis fortalezas son la puntualidad y el orden.", s: "Cuando el entrevistador te pregunta por tus puntos fuertes.", sEn: "When the interviewer asks about your strong points.", n: "\"Strengths\" es difícil; practica el grupo final \"-ngths\" lentamente: streng-ths.", nEn: "\"Strengths\" is hard; practice the final cluster \"-ngths\" slowly: streng-ths." },
    "loc-cv05": { e: "I studied business administration at the university.", t: "Estudié administración de empresas en la universidad.", s: "Cuando hablas de tu formación académica en una entrevista.", sEn: "When you talk about your academic background in an interview.", n: "Solo \"administration\" puede sonar a gobierno; añade \"business\" para que quede claro.", nEn: "Just \"administration\" can sound like government; add \"business\" to make it clear." },
    "loc-cv06": { e: "I speak Spanish and English, and I'm learning a little Portuguese.", t: "Hablo español e inglés, y estoy aprendiendo un poco de portugués.", s: "Cuando mencionas tus idiomas como ventaja para un puesto en turismo.", sEn: "When you mention your languages as an asset for a tourism job.", n: "Los idiomas van con mayúscula en inglés: \"Spanish\", \"English\", siempre.", nEn: "Languages are capitalized in English: \"Spanish\", \"English\", always." },
    "loc-cv07": { e: "I'm looking for a job in the hospitality sector, ideally at a hotel.", t: "Estoy buscando trabajo en el sector de hospitalidad, idealmente en un hotel.", s: "Cuando te presentas en un negocio o le cuentas a alguien que estás en busca de empleo.", sEn: "When you walk into a business or tell someone you're searching for work.", n: "Suena más profesional decir \"I'm currently looking for a job\" que solo \"I want a job\".", nEn: "It sounds more professional to say \"I'm currently looking for a job\" than just \"I want a job\"." },
    "loc-cv08": { e: "I can provide references from my previous managers if you'd like.", t: "Puedo dar referencias de mis jefes anteriores si lo desea.", s: "En una entrevista o al final de tu carta, cuando ofreces respaldo de empleadores pasados.", sEn: "In an interview or at the end of your letter, when you offer backup from past employers.", n: "Di \"references\" (con S al final); en singular \"a reference\" suena raro al ofrecer varias.", nEn: "Say \"references\" with the final S; the singular sounds odd when you're offering several." },
    "loc-cv09": { e: "I'm hardworking and honest, and I always show up on time.", t: "Soy trabajador y honesto, y siempre llego a tiempo.", s: "Cuando describes tus cualidades en una entrevista o carta de presentación.", sEn: "When you describe your qualities in an interview or cover letter.", n: "\"Hardworking\" es una sola palabra; evita \"hard worker\" como adjetivo.", nEn: "\"Hardworking\" is one word as an adjective; don't say \"a hard worker\" in that slot." },
    "loc-cv10": { e: "I'd like to grow with the company and take on more responsibility over time.", t: "Me gustaría crecer en la empresa y asumir más responsabilidades con el tiempo.", s: "Cuando te preguntan sobre tus metas o por qué quieres el puesto.", sEn: "When you're asked about your goals or why you want the position.", n: "\"Grow with the company\" suena más comprometido que \"grow in the company\".", nEn: "\"Grow with the company\" sounds more committed than \"grow in the company\"." },
    "loc-cv11": { e: "Who should I address this to, the hiring manager or HR?", t: "¿A quién debo dirigir esto, al encargado de contratación o a Recursos Humanos?", s: "Cuando vas a escribir una carta o correo y no sabes el nombre del destinatario.", sEn: "When you're about to write a letter or email and don't know the recipient's name.", n: "Si no sabes el nombre, usa \"Dear Hiring Manager\" en la carta.", nEn: "If you don't know the name, use \"Dear Hiring Manager\" in the letter." },
    "loc-cv12": { e: "Thank you for your time. I look forward to hearing from you.", t: "Gracias por su tiempo. Quedo atento a su respuesta.", s: "Para cerrar de forma cortés una carta de presentación o un correo de trabajo.", sEn: "To politely close a cover letter or a job-related email.", n: "Después de \"look forward to\" va verbo en -ing: \"hearing\", nunca \"hear\".", nEn: "After \"look forward to\" use the -ing form: \"hearing\", never \"hear\"." },
    // ===================== Negotiating (negociacion) =====================
    "loc-neg01": { e: "Can we talk about the price? I'm buying a few of these.", t: "¿Podemos hablar del precio? Voy a llevar varios de estos.", s: "En un mercado o tienda, cuando quieres abrir una negociación con educación.", sEn: "At a market or shop, when you want to politely open a negotiation.", n: "Empezar con \"Can we talk about...\" suena más amable que decir directo \"too expensive\".", nEn: "Starting with \"Can we talk about...\" sounds friendlier than bluntly saying \"too expensive\"." },
    "loc-neg02": { e: "I was hoping for a bit more, to be honest.", t: "Esperaba un poco más, la verdad.", s: "Cuando te ofrecen un precio o cantidad por debajo de lo que querías.", sEn: "When you're offered a price or amount below what you wanted.", n: "\"I was hoping\" (pasado) suena más suave y educado que \"I want more\".", nEn: "\"I was hoping\" in the past tense sounds softer and more polite than \"I want more\"." },
    "loc-neg03": { e: "What's your best offer if I pay in cash today?", t: "¿Cuál es su mejor oferta si pago en efectivo hoy?", s: "Cuando quieres que la otra persona baje el precio al máximo.", sEn: "When you want the other person to give you their lowest price.", n: "Añadir \"if I pay in cash\" suele conseguir mejores ofertas.", nEn: "Adding \"if I pay in cash\" often gets you a better offer." },
    "loc-neg04": { e: "I'm sure we can reach an agreement that works for both of us.", t: "Estoy seguro de que podemos llegar a un acuerdo que sirva para ambos.", s: "Cuando quieres mantener un tono positivo en medio de una negociación.", sEn: "When you want to keep a positive tone in the middle of a negotiation.", n: "Es \"reach an agreement\", no \"arrive to an agreement\".", nEn: "It's \"reach an agreement\", not \"arrive to an agreement\"." },
    "loc-neg05": { e: "Let me think about it and I'll come back to you tomorrow.", t: "Déjeme pensarlo y le respondo mañana.", s: "Cuando no quieres decidir en el momento sin parecer descortés.", sEn: "When you don't want to decide on the spot without seeming rude.", n: "\"Let me think about it\" es una forma educada de decir no sin cerrar la puerta.", nEn: "\"Let me think about it\" is a polite way to say no without closing the door." },
    "loc-neg06": { e: "If you buy more, I'll lower the price for you.", t: "Si compra más, le bajo el precio.", s: "Como vendedor, cuando ofreces un descuento por comprar en cantidad.", sEn: "As a seller, when you offer a discount for buying in larger quantity.", n: "\"Lower the price\" suena natural; \"make a discount\" es incorrecto, usa \"give a discount\".", nEn: "\"Lower the price\" sounds natural; \"make a discount\" is wrong, use \"give a discount\"." },
    "loc-neg07": { e: "It's a fair price for handmade work, honestly.", t: "Es un precio justo por un trabajo hecho a mano, de verdad.", s: "Cuando defiendes tu precio porque el cliente regatea demasiado.", sEn: "When you defend your price because the customer is haggling too hard.", n: "\"Fair\" se pronuncia como \"fer\", no separes las dos vocales.", nEn: "\"Fair\" sounds like \"fer\"; don't split it into two vowels." },
    "loc-neg08": { e: "Is there any flexibility on the price?", t: "¿Hay algo de flexibilidad en el precio?", s: "Una forma elegante de preguntar si pueden hacerte rebaja.", sEn: "An elegant way to ask whether they can come down on the price.", n: "Más formal y suave que \"can you go cheaper?\"; ideal en tiendas o tratos serios.", nEn: "More formal and gentle than \"can you go cheaper?\"; great for shops or serious deals." },
    "loc-neg09": { e: "Okay, it's a deal. Let's shake on it.", t: "Listo, trato hecho. Démonos la mano.", s: "Cuando ambos aceptan las condiciones y cierran el acuerdo.", sEn: "When both sides accept the terms and close the agreement.", n: "\"It's a deal\" o solo \"Deal!\" sirven; significan que ya aceptaste.", nEn: "\"It's a deal\" or just \"Deal!\" both work; they mean you've accepted." },
    "loc-neg10": { e: "I need to check with my boss before I can confirm.", t: "Necesito consultarlo con mi jefe antes de confirmar.", s: "Cuando no tienes la autoridad para cerrar el trato tú solo.", sEn: "When you don't have the authority to close the deal on your own.", n: "Es \"check with\" (consultar a una persona), distinto de \"check on\".", nEn: "It's \"check with\" a person, which is different from \"check on\"." },
    "loc-neg11": { e: "Does it include shipping, or is that extra?", t: "¿Incluye el envío, o se cobra aparte?", s: "Antes de cerrar una compra, para saber si el precio cubre el envío.", sEn: "Before finalizing a purchase, to know if the price covers delivery.", n: "En inglés es \"shipping\" o \"delivery\"; no uses \"the send\".", nEn: "In English it's \"shipping\" or \"delivery\"; don't say \"the send\"." },
    "loc-neg12": { e: "Let's close the deal today and I'll throw in free delivery.", t: "Cerremos el negocio hoy y le incluyo el envío gratis.", s: "Cuando quieres animar al cliente a decidir en el momento.", sEn: "When you want to encourage the customer to decide right now.", n: "\"Close the deal\" es la frase fija; evita \"close the business\".", nEn: "\"Close the deal\" is the set phrase; avoid \"close the business\"." },
    // ===================== Verb tenses (tiempos-en) =====================
    "loc-tie01": { e: "I work at the front desk from Monday to Friday.", t: "Yo trabajo en la recepción de lunes a viernes.", s: "Cuando hablas de tu rutina o lo que haces normalmente en tu empleo.", sEn: "When you talk about your routine or what you usually do at your job.", n: "En él/ella se agrega S: \"he works\"; pero con I/you/we es \"work\" sin S.", nEn: "For he/she add an S: \"he works\"; but with I/you/we it's \"work\" with no S." },
    "loc-tie02": { e: "I worked at a beach hotel last summer.", t: "Yo trabajé en un hotel de playa el verano pasado.", s: "Cuando cuentas algo que hiciste en el pasado, en una entrevista o charla.", sEn: "When you describe something you did in the past, in an interview or chat.", n: "\"Worked\" termina en /t/, suena \"workt\", no \"work-ed\" con dos sílabas.", nEn: "\"Worked\" ends in a /t/ sound, like \"workt\", not \"work-ed\" with two syllables." },
    "loc-tie03": { e: "I will work the morning shift tomorrow, so I'll see you early.", t: "Trabajaré el turno de la mañana mañana, así que te veo temprano.", s: "Cuando le cuentas a un compañero o jefe tu horario o plan de trabajo a futuro.", sEn: "When you tell a coworker or boss your future schedule or work plan.", n: "En el habla casual casi siempre se dice \"I'll work\" en vez de \"I will work\".", nEn: "In casual speech people almost always say \"I'll work\" instead of \"I will work\"." },
    "loc-tie04": { e: "Sorry, I can't talk right now, I'm working.", t: "Disculpa, no puedo hablar ahorita, estoy trabajando.", s: "Cuando alguien te interrumpe y quieres decir que estás ocupado en este momento.", sEn: "When someone interrupts you and you want to say you're busy right now.", n: "Usa la forma -ing solo para algo que pasa ahora mismo, no para tu trabajo en general.", nEn: "Use the -ing form only for something happening right now, not for your job in general." },
    "loc-tie05": { e: "I have worked here for two years, so I know the menu well.", t: "He trabajado aquí dos años, así que conozco bien el menú.", s: "En una entrevista o con un cliente, cuando hablas de tu experiencia que sigue hasta hoy.", sEn: "In an interview or with a customer, when you talk about experience that continues today.", n: "Di \"for two years\" (duración) y no \"since two years\"; \"since\" va con un punto de inicio como \"since 2024\".", nEn: "Say \"for two years\" (duration), not \"since two years\"; \"since\" goes with a starting point like \"since 2024\"." },
    "loc-tie06": { e: "Yesterday I went to the market to buy fresh fish for the special.", t: "Ayer fui al mercado a comprar pescado fresco para el plato del día.", s: "Cuando cuentas algo que ya hiciste en un momento pasado terminado.", sEn: "When you tell about something you already did at a finished past time.", n: "\"Went\" es el pasado irregular de \"go\"; nunca digas \"goed\".", nEn: "\"Went\" is the irregular past of \"go\"; never say \"goed\"." },
    "loc-tie07": { e: "Tomorrow I'm going to travel to the coast for a few days.", t: "Mañana voy a viajar a la costa por unos días.", s: "Cuando anuncias un plan que ya decidiste para el futuro cercano.", sEn: "When you announce a plan you've already decided for the near future.", n: "En el habla rápida \"going to\" suena como \"gonna\", pero escríbelo completo.", nEn: "In fast speech \"going to\" sounds like \"gonna\", but write it out in full." },
    "loc-tie08": { e: "I eat lunch at noon, but yesterday I ate at the restaurant.", t: "Almuerzo al mediodía, pero ayer comí en el restaurante.", s: "Cuando comparas algo que haces normalmente con algo que hiciste una vez en el pasado.", sEn: "When you compare something you usually do with something you did once in the past.", n: "\"Ate\" se pronuncia como \"eit\", no como se ve escrito.", nEn: "\"Ate\" is pronounced like \"eit\", not the way it looks written." },
    "loc-tie09": { e: "Have you been here before, or is this your first time?", t: "¿Has estado aquí antes, o es tu primera vez?", s: "Cuando un cliente o turista llega y quieres saber si ya conocía el lugar.", sEn: "When a customer or tourist arrives and you want to know if they already knew the place.", n: "Una variante más suave y común es \"Is this your first visit?\".", nEn: "A softer, common variant is \"Is this your first visit?\"." },
    "loc-tie10": { e: "I go to work by bus, but last week I went by taxi.", t: "Voy al trabajo en bus, pero la semana pasada fui en taxi.", s: "Cuando hablas de un hábito y luego de una vez puntual en el pasado.", sEn: "When you talk about a habit and then a one-time event in the past.", n: "Recuerda el par irregular: presente \"go\", pasado \"went\".", nEn: "Remember the irregular pair: present \"go\", past \"went\"." },
    "loc-tie11": { e: "It was raining hard when the tour group arrived.", t: "Estaba lloviendo fuerte cuando llegó el grupo del tour.", s: "Cuando describes lo que estaba pasando de fondo mientras ocurrió otra cosa.", sEn: "When you describe what was happening in the background while something else occurred.", n: "Usa \"was/were + -ing\" para una acción en progreso en el pasado.", nEn: "Use \"was/were + -ing\" for an action in progress in the past." },
    "loc-tie12": { e: "Don't worry, I'll do it tomorrow first thing in the morning.", t: "No se preocupe, lo haré mañana a primera hora.", s: "Cuando prometes a un cliente o jefe encargarte de algo más tarde.", sEn: "When you promise a customer or boss you'll handle something later.", n: "\"I'll\" suena como \"ail\"; junta bien la \"l\" final para que se entienda.", nEn: "\"I'll\" sounds like \"ail\"; pronounce the final \"l\" clearly so it's understood." },
    // ===================== Prepositions (preposiciones) =====================
    "loc-pre01": { e: "I'll meet you at the airport near the main exit.", t: "Te recojo en el aeropuerto cerca de la salida principal.", s: "Cuando coordinas dónde encontrarte con alguien en una terminal o aeropuerto.", sEn: "When you arrange where to meet someone at a terminal or airport.", n: "Usa \"at the airport\" para el punto; \"in the airport\" suena raro en este caso.", nEn: "Use \"at the airport\" for the location; \"in the airport\" sounds odd here." },
    "loc-pre02": { e: "The tour leaves on Monday at eight in the morning.", t: "El tour sale el lunes a las ocho de la mañana.", s: "Cuando le dices a un cliente el día exacto de una actividad o reserva.", sEn: "When you tell a customer the exact day of an activity or booking.", n: "Con días se usa \"on\": \"on Monday\", \"on Friday\".", nEn: "With days you use \"on\": \"on Monday\", \"on Friday\"." },
    "loc-pre03": { e: "High season starts in July, so book your room early.", t: "La temporada alta empieza en julio, así que reserve su habitación temprano.", s: "Cuando hablas de un mes o una época del año con un cliente.", sEn: "When you talk about a month or time of year with a customer.", n: "Con meses y años se usa \"in\": \"in July\", \"in 2026\".", nEn: "With months and years you use \"in\": \"in July\", \"in 2026\"." },
    "loc-pre04": { e: "Your table is ready at three o'clock, just ask for me.", t: "Su mesa está lista a las tres, solo pregunte por mí.", s: "Cuando confirmas una hora exacta para una reserva o cita.", sEn: "When you confirm an exact time for a reservation or appointment.", n: "Con horas exactas se usa \"at\": \"at three\", \"at noon\".", nEn: "With exact times you use \"at\": \"at three\", \"at noon\"." },
    "loc-pre05": { e: "She isn't here right now, she's at home today.", t: "Ella no está ahora, hoy está en casa.", s: "Cuando explicas que alguien no está en el trabajo porque está en su casa.", sEn: "When you explain that someone isn't at work because they're at home.", n: "Se dice \"at home\" sin \"the\"; \"at the home\" suena mal.", nEn: "Say \"at home\" without \"the\"; \"at the home\" sounds wrong." },
    "loc-pre06": { e: "I left the menu on the table by the window.", t: "Dejé el menú en la mesa junto a la ventana.", s: "Cuando indicas dónde pusiste algo sobre una superficie.", sEn: "When you point out where you put something on a surface.", n: "Usa \"on\" para algo encima de una superficie; \"in the table\" estaría mal.", nEn: "Use \"on\" for something on top of a surface; \"in the table\" would be wrong." },
    "loc-pre07": { e: "Please wait here, your bags are still in the car.", t: "Espere aquí, por favor, sus maletas todavía están en el carro.", s: "Cuando le dices a un cliente dónde están sus cosas dentro del vehículo.", sEn: "When you tell a customer where their things are inside the vehicle.", n: "Con carros y taxis se usa \"in the car\"; con bus o avión se usa \"on\".", nEn: "With cars and taxis you use \"in the car\"; with bus or plane you use \"on\"." },
    "loc-pre08": { e: "The pharmacy is next to the bank, just two minutes away.", t: "La farmacia está al lado del banco, a solo dos minutos.", s: "Cuando das indicaciones y un lugar queda justo a un costado de otro.", sEn: "When you give directions and one place is right beside another.", n: "\"Next to\" siempre lleva \"to\"; no digas solo \"next the bank\".", nEn: "\"Next to\" always keeps \"to\"; don't say just \"next the bank\"." },
    "loc-pre09": { e: "There's a good coffee shop near the hotel entrance.", t: "Hay una buena cafetería cerca de la entrada del hotel.", s: "Cuando recomiendas un lugar que queda a poca distancia de donde están.", sEn: "When you recommend a place that's a short distance from where you are.", n: "\"Near\" no necesita \"to\"; di \"near the hotel\", no \"near to the hotel\".", nEn: "\"Near\" doesn't need \"to\"; say \"near the hotel\", not \"near to the hotel\"." },
    "loc-pre10": { e: "The ATM is between the pharmacy and the supermarket.", t: "El cajero está entre la farmacia y el supermercado.", s: "Cuando ubicas algo que está en medio de otros dos lugares.", sEn: "When you locate something that sits in the middle of two other places.", n: "\"Between\" se usa con dos cosas y normalmente con \"and\": \"between A and B\".", nEn: "\"Between\" is used with two things and usually with \"and\": \"between A and B\"." },
    "loc-pre11": { e: "I saved this table for you, right by the window.", t: "Te guardé esta mesa, justo al lado de la ventana.", s: "Cuando le ofreces algo a un cliente como un detalle o cortesía.", sEn: "When you offer something to a customer as a courtesy.", n: "\"For you\" suena cálido; agrégalo al final para que el cliente se sienta atendido.", nEn: "\"For you\" sounds warm; add it at the end to make the customer feel cared for." },
    "loc-pre12": { e: "I'm here on vacation with my family.", t: "Estoy aquí de vacaciones con mi familia.", s: "Cuando platicas con un huésped o cliente sobre con quién viajas o vives.", sEn: "When chatting with a guest about who you travel or live with.", n: "Se dice \"with my family\", no \"with my familiar\"; \"familiar\" en inglés significa conocido.", nEn: "Say \"with my family,\" not \"familiar,\" which in English means well-known." },
    // ===================== Asking questions (preguntas-en) =====================
    "loc-prg01": { e: "Excuse me, what time is it? My tour starts soon.", t: "Disculpe, ¿qué hora es? Mi tour empieza pronto.", s: "Cuando necesitas saber la hora porque tienes algo programado.", sEn: "When you need the time because you have something scheduled.", n: "Suena casi \"wha-taim-izit\"; las palabras se unen, no las separes demasiado.", nEn: "It sounds like \"wha-taim-izit\"; the words blend, so don't over-separate them." },
    "loc-prg02": { e: "Where do you live? I can recommend a good route home.", t: "¿Dónde vives? Te puedo recomendar una buena ruta a casa.", s: "Cuando conversas con alguien para conocerlo o ubicarlo mejor.", sEn: "When you chat with someone to get to know them or help them.", n: "Es \"live\" (vivir), no \"leave\" (irse); cuida esa diferencia de sonido.", nEn: "It's \"live\" (reside), not \"leave\" (go away); watch that sound difference." },
    "loc-prg03": { e: "How old are you? We have a kids' menu if you'd like.", t: "¿Cuántos años tienes? Tenemos menú infantil si gustas.", s: "Cuando preguntas la edad, por ejemplo de un niño en el restaurante.", sEn: "When you ask someone's age, for example a child at the restaurant.", n: "En inglés se usa \"are\" (be), no \"have\": \"How old are you?\", no \"how old have you\".", nEn: "English uses \"are\" (be), not \"have\": \"How old are you?\"" },
    "loc-prg04": { e: "Why are you here today, just to relax or for the tour?", t: "¿Por qué estás aquí hoy, solo a relajarte o por el tour?", s: "Cuando preguntas el motivo de la visita de un cliente o huésped.", sEn: "When you ask why a customer or guest is visiting.", n: "\"Why are you here?\" puede sonar brusco; suaviza con \"What brings you here?\".", nEn: "\"Why are you here?\" can sound blunt; soften it with \"What brings you here?\"" },
    "loc-prg05": { e: "It's beautiful, but how much does it cost?", t: "Es hermoso, pero ¿cuánto cuesta?", s: "Cuando preguntas el precio de un producto o servicio.", sEn: "When you ask the price of a product or service.", n: "Para una sola cosa di \"How much is it?\"; \"does it cost\" suena más formal.", nEn: "For one item say \"How much is it?\"; \"does it cost\" sounds more formal." },
    "loc-prg06": { e: "When do you open tomorrow? I'd like to come back.", t: "¿A qué hora abren mañana? Me gustaría volver.", s: "Cuando preguntas el horario de apertura de un negocio.", sEn: "When you ask a business's opening hours.", n: "También puedes decir \"What time do you open?\" para preguntar la hora exacta.", nEn: "You can also say \"What time do you open?\" for the exact hour." },
    "loc-prg07": { e: "Someone's at the door, who is it?", t: "Alguien está en la puerta, ¿quién es?", s: "Cuando preguntas quién llama a la puerta o al teléfono.", sEn: "When you ask who is at the door or on the phone.", n: "En el teléfono se prefiere \"Who's calling?\" en vez de \"Who is it?\".", nEn: "On the phone, \"Who's calling?\" is preferred over \"Who is it?\"" },
    "loc-prg08": { e: "We have red and white wine, which one do you prefer?", t: "Tenemos vino tinto y blanco, ¿cuál prefieres?", s: "Cuando le das opciones a un cliente y le pides que elija.", sEn: "When you give a customer options and ask them to choose.", n: "\"Which one\" es para opciones limitadas; \"what\" es más abierto y general.", nEn: "\"Which one\" is for limited options; \"what\" is more open and general." },
    "loc-prg09": { e: "Excuse me, where is the restroom?", t: "Disculpe, ¿dónde está el baño?", s: "Cuando necesitas o te preguntan por el baño en un lugar público.", sEn: "When you need or are asked about the restroom in a public place.", n: "\"Restroom\" es más educado que \"toilet\" en EE.UU.; en el Reino Unido usan \"toilet\".", nEn: "\"Restroom\" is more polite than \"toilet\" in the US; the UK uses \"toilet.\"" },
    "loc-prg10": { e: "Do you speak English? I have a quick question.", t: "¿Hablas inglés? Tengo una pregunta rápida.", s: "Cuando quieres confirmar si la persona te puede entender en inglés.", sEn: "When you want to confirm if the person can understand English.", n: "No olvides el \"Do\" al inicio; \"You speak English?\" suena incompleto.", nEn: "Don't drop the \"Do\" at the start; \"You speak English?\" sounds incomplete." },
    "loc-prg11": { e: "What is this on the plate? It looks delicious.", t: "¿Qué es esto en el plato? Se ve delicioso.", s: "Cuando preguntas qué es un objeto o platillo que no conoces.", sEn: "When you ask what an unfamiliar object or dish is.", n: "Para algo lejos di \"What is that?\"; \"this\" es para algo cercano.", nEn: "For something far away say \"What is that?\"; \"this\" is for something near." },
    "loc-prg12": { e: "What time do you close? I might be a little late.", t: "¿A qué hora cierran? Puede que llegue un poco tarde.", s: "Cuando preguntas la hora de cierre de un negocio.", sEn: "When you ask a business's closing time.", n: "\"Close\" se pronuncia con z suave al final, no \"clós\" con s fuerte.", nEn: "\"Close\" ends with a soft z sound, not a hard s." },
    // ===================== Call center / BPO (bpo-en) =====================
    "loc-bpo01": { e: "Thank you for calling TechSupport, how can I help you today?", t: "Gracias por llamar a TechSupport, ¿en qué puedo ayudarle hoy?", s: "Cuando contestas una llamada entrante en un call center.", sEn: "When you answer an incoming call at a call center.", n: "Agregar \"today\" al final suena natural y profesional en inglés.", nEn: "Adding \"today\" at the end sounds natural and professional in English." },
    "loc-bpo02": { e: "For security, can you confirm your full name, please?", t: "Por seguridad, ¿me confirma su nombre completo, por favor?", s: "Cuando verificas la identidad del cliente al inicio de la llamada.", sEn: "When you verify the customer's identity at the start of the call.", n: "Anteponer \"For security\" explica por qué pides los datos y suena más amable.", nEn: "Starting with \"For security\" explains why you're asking and sounds kinder." },
    "loc-bpo03": { e: "Can I have your account number to pull up your details?", t: "¿Me da su número de cuenta para ver sus datos?", s: "Cuando necesitas el número de cuenta para buscar al cliente en el sistema.", sEn: "When you need the account number to find the customer in the system.", n: "\"Can I have\" es educado; \"Give me\" suena exigente, evítalo con clientes.", nEn: "\"Can I have\" is polite; \"Give me\" sounds demanding, so avoid it with customers." },
    "loc-bpo04": { e: "One moment while I check that for you.", t: "Un momento mientras reviso eso por usted.", s: "Cuando haces una pausa para buscar información durante la llamada.", sEn: "When you pause to look up information during the call.", n: "Cerrar con \"for you\" hace que la espera se sienta como un servicio.", nEn: "Ending with \"for you\" makes the wait feel like a service." },
    "loc-bpo05": { e: "Thank you for holding, I have your information now.", t: "Gracias por esperar, ya tengo su información.", s: "Cuando retomas la llamada después de poner al cliente en espera.", sEn: "When you return to the call after putting the customer on hold.", n: "\"Holding\" aquí significa esperar en línea, no sostener algo.", nEn: "\"Holding\" here means waiting on the line, not gripping something." },
    "loc-bpo06": { e: "Let me put you on hold for just a moment, please.", t: "Permítame ponerlo en espera solo un momento, por favor.", s: "Cuando vas a dejar al cliente en espera para consultar algo.", sEn: "When you're about to put the customer on hold to check something.", n: "Siempre pide permiso antes; agregar \"just a moment\" tranquiliza al cliente.", nEn: "Always ask first; adding \"just a moment\" reassures the customer." },
    "loc-bpo07": { e: "I'll transfer you to the right department, please stay on the line.", t: "Lo transfiero con el área correspondiente, por favor no cuelgue.", s: "Cuando la consulta del cliente no es de tu área y debes pasarlo con otro equipo.", sEn: "When the customer's issue isn't yours to handle and you pass them to another team.", n: "Suena más cálido si agregas 'please stay on the line' o 'one moment, please' antes de transferir.", nEn: "It sounds warmer if you add 'please stay on the line' or 'one moment, please' before transferring." },
    "loc-bpo08": { e: "Let me make sure I understand: you'd like to cancel the order placed yesterday, correct?", t: "Permítame confirmar lo que entendí: usted quiere cancelar el pedido de ayer, ¿correcto?", s: "Cuando repites lo que pidió el cliente para confirmar que entendiste bien.", sEn: "When you repeat the customer's request to confirm you understood correctly.", n: "Cerrar con 'correct?' o 'is that right?' invita al cliente a confirmar y evita errores.", nEn: "Closing with 'correct?' or 'is that right?' invites the customer to confirm and avoids mistakes." },
    "loc-bpo09": { e: "I'm sorry for the trouble; let's get this sorted out for you right now.", t: "Lamento la molestia; vamos a resolverle esto ahora mismo.", s: "Cuando el cliente tuvo un problema y quieres disculparte antes de solucionarlo.", sEn: "When the customer had a problem and you apologize before fixing it.", n: "'Trouble' aquí significa molestia, no peligro; pronúncialo 'tró-bol', no 'trubel'.", nEn: "Here 'trouble' means inconvenience, not danger; say it 'TRUH-buhl', not 'troo-ble'." },
    "loc-bpo10": { e: "Let me verify your information before I make any changes to the account.", t: "Déjeme verificar su información antes de hacer cambios en la cuenta.", s: "Cuando necesitas confirmar los datos del cliente por seguridad antes de actuar.", sEn: "When you need to confirm the customer's details for security before acting.", n: "Más suave: 'Could I just verify your information?' suena menos brusco que ordenarlo.", nEn: "Softer: 'Could I just verify your information?' sounds less abrupt than ordering it." },
    "loc-bpo11": { e: "Are you still there? I just want to make sure we didn't lose the connection.", t: "¿Sigue en la línea? Solo quiero asegurarme de que no se cortó la llamada.", s: "Cuando hay un silencio largo y no sabes si el cliente sigue al teléfono.", sEn: "When there's a long silence and you're not sure the customer is still on the call.", n: "Más formal: 'Are you still on the line?'; 'still there?' es perfecto para tono amable.", nEn: "More formal: 'Are you still on the line?'; 'still there?' is fine for a friendly tone." },
    "loc-bpo12": { e: "Your case has been logged, so the next agent will see everything we discussed.", t: "Su caso quedó registrado, así el próximo agente verá todo lo que hablamos.", s: "Cuando confirmas al cliente que su reclamo o consulta quedó guardado en el sistema.", sEn: "When you confirm to the customer that their complaint or request is saved in the system.", n: "'Logged' viene de 'log' (registrar); también puedes decir 'has been recorded'.", nEn: "'Logged' comes from 'log' (to record); you can also say 'has been recorded'." },
    "loc-bpo13": { e: "I'll give you a reference number so you can follow up on your case anytime.", t: "Le doy su número de referencia para que pueda hacer seguimiento a su caso cuando quiera.", s: "Cuando entregas un código al cliente para que identifique su caso después.", sEn: "When you give the customer a code to identify their case later.", n: "Al dictar el número, di 'double seven' para '77' y deletrea las letras para evitar errores.", nEn: "When reading the number, say 'double seven' for '77' and spell out letters to avoid mistakes." },
    "loc-bpo14": { e: "Can I help you with anything else today, or are you all set?", t: "¿Puedo ayudarle en algo más hoy, o quedó todo resuelto?", s: "Justo antes de cerrar la llamada, para asegurarte de que no falta nada.", sEn: "Right before closing the call, to make sure nothing is left undone.", n: "'Are you all set?' es una forma natural de preguntar '¿ya quedó todo listo?'.", nEn: "'Are you all set?' is a natural way to ask if everything is taken care of." },
    "loc-bpo15": { e: "Thank you for your time, and thanks for your patience while we looked into it.", t: "Gracias por su tiempo, y gracias por su paciencia mientras lo revisábamos.", s: "Al final de la llamada, para agradecer al cliente antes de despedirte.", sEn: "At the end of the call, to thank the customer before saying goodbye.", n: "Combínalo con 'for your patience' cuando la llamada fue larga; suena muy profesional.", nEn: "Pair it with 'for your patience' when the call was long; it sounds very professional." },
    "loc-bpo16": { e: "Have a wonderful day, and don't hesitate to call us back if you need anything.", t: "Que tenga un excelente día, y no dude en volver a llamarnos si necesita algo.", s: "La frase de despedida final cuando cuelgas con el cliente.", sEn: "The final goodbye line when you hang up with the customer.", n: "Varía con 'Have a great day' o 'Take care' para no sonar siempre igual.", nEn: "Vary it with 'Have a great day' or 'Take care' so you don't always sound the same." },
    // ===================== Tech & software (tech-en) =====================
    "loc-tech01": { e: "I'm blocked by a bug in the login flow, so I can't finish the feature yet.", t: "Estoy bloqueado por un error en el flujo de login, así que aún no puedo terminar la función.", s: "En el standup, cuando explicas que un error no te deja avanzar.", sEn: "In standup, when you explain a bug is stopping your progress.", n: "'Bug' es el término normal para un error de software; 'blocked' significa que no puedes seguir.", nEn: "'Bug' is the normal word for a software error; 'blocked' means you can't move forward." },
    "loc-tech02": { e: "I pushed the change, can you review it when you get a minute?", t: "Subí el cambio, ¿lo revisas cuando tengas un momento?", s: "Cuando terminaste tu código y le pides a un compañero que revise el pull request.", sEn: "When you've finished your code and ask a teammate to review the pull request.", n: "'Push' (subir al repositorio) se pronuncia 'push', no 'pus'; agrega 'PR' si quieres ser exacto.", nEn: "'Push' (to the repo) rhymes with 'bush'; add 'PR' if you want to be precise." },
    "loc-tech03": { e: "I'll deploy it to production today once the tests pass.", t: "Lo despliego a producción hoy, una vez que pasen las pruebas.", s: "Cuando avisas al equipo que vas a poner tu cambio en vivo para los usuarios.", sEn: "When you tell the team you'll release your change live for users.", n: "'Production' (o 'prod') es el ambiente real; cuidado, no es lo mismo que 'staging'.", nEn: "'Production' (or 'prod') is the live environment; don't confuse it with 'staging'." },
    "loc-tech04": { e: "I need more time for this; it's more complicated than we expected.", t: "Necesito más tiempo para esto; es más complicado de lo que esperábamos.", s: "Cuando una tarea va a tardar más de lo planeado y debes avisarlo.", sEn: "When a task will take longer than planned and you need to flag it.", n: "Explicar el porqué ('it's more complicated...') hace que pedir más tiempo suene profesional.", nEn: "Adding the reason ('it's more complicated...') makes asking for more time sound professional." },
    "loc-tech05": { e: "In today's standup I'll share where I am and what's blocking me.", t: "En el standup de hoy voy a contar en qué voy y qué me está bloqueando.", s: "Al empezar tu turno en la reunión diaria del equipo.", sEn: "When starting your turn in the team's daily meeting.", n: "El 'standup' es la reunión rápida diaria; di las tres cosas: ayer, hoy y bloqueos.", nEn: "The 'standup' is the quick daily meeting; cover three things: yesterday, today, and blockers." },
    "loc-tech06": { e: "Yesterday I finished the task and opened a pull request for review.", t: "Ayer terminé la tarea y abrí un pull request para revisión.", s: "En el standup, al contar lo que lograste el día anterior.", sEn: "In standup, when reporting what you accomplished the day before.", n: "Con 'yesterday' usa pasado simple: 'finished', no 'I have finished'.", nEn: "With 'yesterday' use the simple past: 'finished', not 'I have finished'." },
    "loc-tech07": { e: "Today I'm working on the login, and I hope to have it done by lunch.", t: "Hoy trabajo en el login, y espero tenerlo listo para el almuerzo.", s: "En el standup, al contar en qué te vas a enfocar hoy.", sEn: "In standup, when saying what you'll focus on today.", n: "Usa 'I'm working on' (presente continuo) para algo que está en curso ahora.", nEn: "Use 'I'm working on' (present continuous) for something in progress right now." },
    "loc-tech08": { e: "Can you merge my branch once the review is approved?", t: "¿Puedes hacer merge de mi rama cuando se apruebe la revisión?", s: "Cuando tu código ya fue revisado y pides combinarlo con la rama principal.", sEn: "When your code has been reviewed and you ask to combine it into the main branch.", n: "'Merge' se pronuncia 'merch'; 'branch' es 'rama' (de código), no de árbol literal.", nEn: "'Merge' sounds like 'merch'; 'branch' here means a code branch, not a tree." },
    "loc-tech09": { e: "I have a meeting at ten, so let's keep this standup short.", t: "Tengo una reunión a las diez, así que hagamos este standup corto.", s: "Cuando avisas que tienes poco tiempo por otro compromiso.", sEn: "When you flag that you're short on time due to another commitment.", n: "Di 'at ten' para la hora; agregar 'a.m.' solo si puede haber confusión.", nEn: "Say 'at ten' for the time; add 'a.m.' only if there could be confusion." },
    "loc-tech10": { e: "The test is failing, so I'm looking into it before I merge anything.", t: "El test está fallando, así que lo estoy revisando antes de hacer merge.", s: "Cuando reportas que una prueba automática no pasa y estás investigando.", sEn: "When you report that an automated test isn't passing and you're investigating.", n: "'Is failing' (continuo) indica que sigue fallando ahora; 'looking into it' = investigando.", nEn: "'Is failing' (continuous) means it's still failing now; 'looking into it' means investigating." },
    "loc-tech11": { e: "Don't worry, I'll fix it and let you know as soon as it's working again.", t: "No te preocupes, lo arreglo y te aviso apenas vuelva a funcionar.", s: "Cuando un compañero reporta un error y tú te haces cargo de resolverlo.", sEn: "When a colleague reports a bug and you take charge of fixing it.", n: "\"Let you know\" suena más natural que \"I will inform you\", que es muy formal.", nEn: "\"Let you know\" sounds more natural than the very formal \"I will inform you\"." },
    "loc-tech12": { e: "Before I start, can you share the documentation so I understand the setup?", t: "Antes de empezar, ¿me compartes la documentación para entender la configuración?", s: "Cuando necesitas las instrucciones o guías técnicas para hacer una tarea.", sEn: "When you need the technical guides or instructions to do a task.", n: "Puedes decir \"share the docs\" de forma informal entre desarrolladores.", nEn: "You can say \"share the docs\" informally among developers." },
    "loc-tech13": { e: "I agree with the plan, but let's add one more day for testing.", t: "Estoy de acuerdo con el plan, pero agreguemos un día más para pruebas.", s: "Cuando aceptas una propuesta en una reunión pero quieres sugerir un ajuste.", sEn: "When you accept a proposal in a meeting but want to suggest a tweak.", n: "\"Agree\" se dice solo (no \"I am agree\"); evita ese error muy común.", nEn: "Say just \"agree\" (not \"I am agree\"); avoid that very common mistake." },
    "loc-tech14": { e: "I need access to the repo before I can push my changes.", t: "Necesito acceso al repositorio para poder subir mis cambios.", s: "Cuando le pides permisos a tu líder para entrar al código del proyecto.", sEn: "When you ask your lead for permission to enter the project's code.", n: "\"Repo\" es la forma corta y normal de decir \"repository\".", nEn: "\"Repo\" is the short, normal way to say \"repository\"." },
    "loc-tech15": { e: "Before we start, what's the priority for this sprint?", t: "Antes de empezar, ¿cuál es la prioridad para este sprint?", s: "Cuando quieres saber qué tarea es la más urgente para enfocarte primero.", sEn: "When you want to know which task is most urgent so you focus on it first.", n: "Pronuncia \"priority\" como \"prai-O-ri-ti\", no \"pri-o-ri-DAD\".", nEn: "Pronounce \"priority\" as \"prai-O-ri-ti\", not Spanish-style." },
    "loc-tech16": { e: "Good job, team, we shipped it on time.", t: "Buen trabajo, equipo, lo entregamos a tiempo.", s: "Cuando felicitas al grupo después de terminar un proyecto o entrega.", sEn: "When you congratulate the group after finishing a project or delivery.", n: "\"Great job\" o \"nice work\" son variantes igual de comunes.", nEn: "\"Great job\" or \"nice work\" are equally common variants." },
    // ===================== Video calls (videocall-en) =====================
    "loc-vc01": { e: "Sorry to interrupt, but you're on mute, we can't hear you.", t: "Perdón por interrumpir, pero tienes el micrófono apagado, no te oímos.", s: "Cuando alguien habla en una videollamada pero su micrófono está silenciado.", sEn: "When someone talks on a video call but their mic is muted.", n: "\"On mute\" es la frase fija; no digas \"your microphone is closed\".", nEn: "\"On mute\" is the fixed phrase; don't say \"your microphone is closed\"." },
    "loc-vc02": { e: "I'm sharing my screen now, let me know when you can see it.", t: "Comparto mi pantalla ahora, avísenme cuando la vean.", s: "Cuando vas a mostrar una presentación o documento en la videollamada.", sEn: "When you're about to show a presentation or document on the video call.", n: "Usa el presente continuo \"I'm sharing\" para algo que pasa justo ahora.", nEn: "Use the present continuous \"I'm sharing\" for something happening right now." },
    "loc-vc03": { e: "Sorry, you're breaking up, could you say that again?", t: "Perdón, se te corta, ¿puedes repetir eso?", s: "Cuando la voz de alguien se escucha entrecortada por mala conexión.", sEn: "When someone's voice sounds choppy because of a bad connection.", n: "\"Breaking up\" es para audio entrecortado; \"dropped\" es cuando se cae del todo.", nEn: "\"Breaking up\" is for choppy audio; \"dropped\" is when it cuts off completely." },
    "loc-vc04": { e: "I think you're muted, we can see you talking but there's no sound.", t: "Creo que estás en silencio, te vemos hablar pero no hay sonido.", s: "Cuando ves a alguien mover la boca pero no se escucha nada.", sEn: "When you see someone's mouth moving but hear nothing.", n: "\"You're muted\" y \"you're on mute\" significan lo mismo.", nEn: "\"You're muted\" and \"you're on mute\" mean the same thing." },
    "loc-vc05": { e: "That's a great point, let's circle back to that after the demo.", t: "Buen punto, lo retomamos luego, después de la demo.", s: "Cuando quieres posponer un tema para tratarlo más adelante en la reunión.", sEn: "When you want to postpone a topic to discuss it later in the meeting.", n: "\"Circle back\" es muy usado en oficinas; \"come back to it\" es más simple.", nEn: "\"Circle back\" is very common in offices; \"come back to it\" is simpler." },
    "loc-vc06": { e: "Turn off your camera if you like, the connection might improve.", t: "Apaga la cámara si quieres, puede mejorar la conexión.", s: "Cuando sugieres apagar el video para que la llamada vaya más fluida.", sEn: "When you suggest turning off video so the call runs smoother.", n: "\"If you like\" suena más amable que dar la orden directa \"turn it off\".", nEn: "\"If you like\" sounds kinder than the direct order \"turn it off\"." },
    "loc-vc07": { e: "Sorry, my connection dropped, what did I miss?", t: "Disculpen, se cayó mi conexión, ¿qué me perdí?", s: "Cuando vuelves a la llamada después de quedarte sin internet.", sEn: "When you rejoin the call after losing your internet.", n: "\"Dropped\" es el verbo natural para una conexión que se cae.", nEn: "\"Dropped\" is the natural verb for a connection that cuts out." },
    "loc-vc08": { e: "I had some issues earlier, can you hear me okay now?", t: "Tuve problemas antes, ¿me oyen bien ahora?", s: "Cuando regresas a la llamada y quieres confirmar que tu audio funciona.", sEn: "When you return to the call and want to confirm your audio works.", n: "\"Okay\" aquí significa \"bien\"; también puedes decir \"can you hear me now?\".", nEn: "\"Okay\" here means \"fine\"; you can also just say \"can you hear me now?\"." },
    "loc-vc09": { e: "To cut the background noise, let's mute when we're not talking.", t: "Para reducir el ruido de fondo, pongámonos en silencio cuando no hablemos.", s: "Cuando hay mucho ruido y propones silenciar los micrófonos.", sEn: "When there's a lot of noise and you suggest muting the mics.", n: "\"Let's\" (let us) sirve para hacer una sugerencia grupal amable.", nEn: "\"Let's\" (let us) is used to make a friendly group suggestion." },
    "loc-vc10": { e: "Please turn up the volume, you sound very quiet on my end.", t: "Sube el volumen, por favor, te escuchas muy bajito de mi lado.", s: "Cuando alguien se oye muy bajo y le pides que suba su micrófono o volumen.", sEn: "When someone is too quiet and you ask them to raise their volume.", n: "Lo contrario es \"turn down the volume\" (bajar el volumen).", nEn: "The opposite is \"turn down the volume\" (lower the volume)." },
    "loc-vc11": { e: "I'll drop the link in the chat so everyone can open it.", t: "Comparto el enlace en el chat para que todos puedan abrirlo.", s: "Cuando pones un enlace en el chat de la videollamada para el grupo.", sEn: "When you put a link in the video call chat for the group.", n: "\"Drop the link\" es informal y muy usado; \"share the link\" es neutral.", nEn: "\"Drop the link\" is informal and very common; \"share the link\" is neutral." },
    "loc-vc12": { e: "Thanks everyone, see you at the next call.", t: "Gracias a todos, nos vemos en la próxima llamada.", s: "Cuando cierras una reunión virtual y te despides del grupo.", sEn: "When you close a virtual meeting and say goodbye to the group.", n: "\"See you\" suena más cálido que un \"goodbye\" seco al terminar.", nEn: "\"See you\" sounds warmer than a flat \"goodbye\" at the end." },
    // ===================== Sales & pitch (ventas-pro) =====================
    "loc-vp01": { e: "Our product saves you time by automating the boring tasks.", t: "Nuestro producto le ahorra tiempo al automatizar las tareas aburridas.", s: "Cuando presentas tu producto y destacas su principal beneficio al cliente.", sEn: "When you pitch your product and highlight its main benefit to the client.", n: "\"Saves you time\" pone al cliente en el centro; suena más persuasivo.", nEn: "\"Saves you time\" puts the client at the center; it sounds more persuasive." },
    "loc-vp02": { e: "Can I show you a demo? It only takes five minutes.", t: "¿Le muestro una demostración? Solo toma cinco minutos.", s: "Cuando ofreces una demostración rápida para convencer a un cliente potencial.", sEn: "When you offer a quick demo to convince a potential client.", n: "\"Demo\" es la forma corta y normal de \"demonstration\" en ventas.", nEn: "\"Demo\" is the short, normal form of \"demonstration\" in sales." },
    "loc-vp03": { e: "I'll follow up tomorrow with a quote and a couple of options.", t: "Le hago seguimiento mañana con una cotización y un par de opciones.", s: "Cuando cierras una llamada de ventas y prometes contactar al cliente al día siguiente.", sEn: "When you end a sales call and promise to contact the customer the next day.", n: "\"Follow up\" se pronuncia \"fólou-ap\" y suena más profesional que \"I'll contact you\".", nEn: "\"Follow up\" sounds more professional than \"I'll contact you.\"" },
    "loc-vp04": { e: "This solves your problem because it cuts your waiting time in half.", t: "Esto resuelve su problema porque reduce a la mitad su tiempo de espera.", s: "Cuando presentas un producto y quieres mostrar el beneficio directo para el cliente.", sEn: "When you present a product and want to show the direct benefit to the customer.", n: "Di \"this solves\" y no \"this resolves\"; en ventas \"solve\" suena más natural.", nEn: "Say \"this solves,\" not \"this resolves\"; \"solve\" sounds more natural in sales." },
    "loc-vp05": { e: "What's your budget so I can recommend the right option for you?", t: "¿Cuál es su presupuesto para poder recomendarle la opción adecuada?", s: "Cuando necesitas saber cuánto puede gastar el cliente antes de ofrecerle algo.", sEn: "When you need to know how much the customer can spend before offering something.", n: "\"Budget\" se dice \"báyet\", con la 'g' suave; para sonar más suave agrega \"if you don't mind me asking\".", nEn: "To soften it, add \"if you don't mind me asking.\"" },
    "loc-vp06": { e: "I'll send you a proposal by email this afternoon.", t: "Le envío una propuesta por correo esta tarde.", s: "Cuando acuerdas con el cliente mandarle una oferta formal por escrito.", sEn: "When you agree to send the customer a formal written offer.", n: "\"Proposal\" lleva el acento en la segunda sílaba: \"pro-PÓU-zal\".", nEn: "\"Proposal\" is stressed on the second syllable: \"pro-POH-zal.\"" },
    "loc-vp07": { e: "We have a special offer this week if you order today.", t: "Tenemos una oferta especial esta semana si ordena hoy.", s: "Cuando quieres animar al cliente a comprar con una promoción por tiempo limitado.", sEn: "When you want to encourage the customer to buy with a limited-time promotion.", n: "\"Offer\" se dice \"ófer\", no \"ofér\"; añadir \"this week\" crea sensación de urgencia.", nEn: "Adding \"this week\" creates a sense of urgency." },
    "loc-vp08": { e: "Would you like to try it for free for a week, no commitment?", t: "¿Le interesa probarlo gratis por una semana, sin compromiso?", s: "Cuando ofreces una prueba gratuita para que el cliente se anime sin riesgo.", sEn: "When you offer a free trial so the customer feels safe to commit.", n: "\"Would you like to try it\" es más cortés que \"Do you want to try it\".", nEn: "\"Would you like to try it\" is more polite than \"Do you want to try it.\"" },
    "loc-vp09": { e: "I'd be happy to explain the plans and help you pick the best one.", t: "Con gusto le explico los planes y le ayudo a elegir el mejor.", s: "Cuando el cliente duda entre varias opciones y te ofreces a aclararlas.", sEn: "When the customer hesitates between options and you offer to clarify them.", n: "\"I'd be happy to\" es la forma cortés estándar; evita el literal \"with pleasure\".", nEn: "\"I'd be happy to\" is the standard polite phrase; avoid the literal \"with pleasure.\"" },
    "loc-vp10": { e: "It's cheaper in the long run because you save on repairs.", t: "Es más barato a largo plazo porque ahorra en reparaciones.", s: "Cuando justificas un precio más alto explicando el ahorro futuro.", sEn: "When you justify a higher price by explaining future savings.", n: "\"In the long run\" es la frase fija; no digas \"in the long term\" en conversación de ventas.", nEn: "\"In the long run\" is the set phrase; \"in the long term\" is stiffer in sales talk." },
    "loc-vp11": { e: "Thank you for your interest; I'll be in touch soon.", t: "Gracias por su interés; estaré en contacto pronto.", s: "Cuando cierras la conversación con un cliente potencial de forma amable.", sEn: "When you politely close a conversation with a potential customer.", n: "\"Interest\" se dice \"ÍN-trest\", con dos sílabas, no tres.", nEn: "\"Interest\" is said \"IN-trest,\" two syllables, not three." },
    "loc-vp12": { e: "Shall we move forward with the contract today?", t: "¿Avanzamos con el contrato hoy?", s: "Cuando el cliente está convencido y quieres cerrar el trato.", sEn: "When the customer is convinced and you want to close the deal.", n: "\"Shall we\" suena formal y profesional; en EE. UU. también sirve \"Should we move forward\".", nEn: "\"Shall we\" sounds professional; in the US \"Should we move forward\" also works." },
    // ===================== Finance & billing (finanzas-en) =====================
    "loc-fin01": { e: "The invoice is due on Friday, so please pay before then.", t: "La factura vence el viernes, así que por favor pague antes.", s: "Cuando le recuerdas a un cliente o colega la fecha de pago de una factura.", sEn: "When you remind a client or colleague of an invoice payment date.", n: "\"Due\" se dice \"diú\"; \"invoice\" es la factura comercial, distinta de \"receipt\" (recibo).", nEn: "\"Invoice\" is the bill you send; \"receipt\" is the proof after payment." },
    "loc-fin02": { e: "The budget is tight this month, so let's keep costs down.", t: "El presupuesto es limitado este mes, así que bajemos los costos.", s: "Cuando explicas en el trabajo que hay poco dinero disponible.", sEn: "When you explain at work that there's little money available.", n: "\"Tight\" (apretado) es lo natural para \"limitado\"; evita el literal \"limited budget\".", nEn: "\"Tight\" is the natural word here; \"limited budget\" sounds stiffer." },
    "loc-fin03": { e: "The payment is still pending, so I'll check with accounting.", t: "El pago aún está pendiente, así que reviso con contabilidad.", s: "Cuando un pago no se ha procesado y avisas que vas a verificarlo.", sEn: "When a payment hasn't gone through and you say you'll verify it.", n: "\"Pending\" se pronuncia \"PEN-ding\"; agregar \"still\" enfatiza que sigue sin resolverse.", nEn: "Adding \"still\" emphasizes that it remains unresolved." },
    "loc-fin04": { e: "I'll send the receipt to your email right away.", t: "Le envío el comprobante a su correo enseguida.", s: "Cuando el cliente ya pagó y le confirmas que recibirá el comprobante.", sEn: "When the customer has paid and you confirm they'll get the receipt.", n: "\"Receipt\" se dice \"ri-SÍIT\"; la 'p' es muda.", nEn: "In \"receipt\" the 'p' is silent: \"ri-SEET.\"" },
    "loc-fin05": { e: "Can we pay by transfer instead of cash?", t: "¿Podemos pagar por transferencia en lugar de efectivo?", s: "Cuando preguntas si se acepta pago por transferencia bancaria.", sEn: "When you ask whether bank transfer payment is accepted.", n: "Se dice \"pay by transfer\", con \"by\", no \"pay for transfer\".", nEn: "Say \"pay by transfer,\" with \"by,\" not \"pay for transfer.\"" },
    "loc-fin06": { e: "I need the invoice with tax included for my company.", t: "Necesito la factura con impuestos incluidos para mi empresa.", s: "Cuando pides una factura formal que detalle los impuestos.", sEn: "When you request a formal invoice that itemizes the tax.", n: "En EE. UU. se dice \"tax\"; en otros países \"VAT\"; \"with tax\" cubre ambos casos.", nEn: "Say \"tax\" in the US or \"VAT\" elsewhere; \"with tax\" works generally." },
    "loc-fin07": { e: "We close the month on the thirtieth, so send your expenses by then.", t: "Cerramos el mes el día treinta, así que manda tus gastos antes.", s: "Cuando informas a colegas hasta qué día se reciben gastos del mes.", sEn: "When you tell colleagues the cutoff day for the month's expenses.", n: "\"Thirtieth\" se dice \"THÉR-ti-eth\"; practica el sonido 'th' para no decir \"tirty\".", nEn: "Practice the 'th' in \"thirtieth\" so it doesn't sound like \"tirty.\"" },
    "loc-fin08": { e: "How much do we owe you for last month?", t: "¿Cuánto le debemos del mes pasado?", s: "Cuando preguntas a un proveedor el monto pendiente por pagar.", sEn: "When you ask a supplier the outstanding amount to pay.", n: "\"Owe\" se pronuncia igual que \"oh\"; la 'w' es muda.", nEn: "\"Owe\" sounds just like \"oh\"; the 'w' is silent." },
    "loc-fin09": { e: "It's within budget, so we can go ahead and order it.", t: "Está dentro del presupuesto, así que podemos seguir y pedirlo.", s: "Cuando confirmas que un gasto cabe en el dinero disponible.", sEn: "When you confirm that a cost fits the available money.", n: "\"Within budget\" es la frase fija; no digas \"inside the budget\".", nEn: "\"Within budget\" is the set phrase; don't say \"inside the budget.\"" },
    "loc-fin10": { e: "Let's review the expenses before we close the report.", t: "Revisemos los gastos antes de cerrar el informe.", s: "Cuando propones a tu equipo revisar juntos los gastos.", sEn: "When you suggest the team go over the expenses together.", n: "\"Expenses\" se dice \"ex-PEN-ses\"; \"let's review\" suena más colaborativo que \"check\".", nEn: "\"Let's review\" sounds more collaborative than \"check.\"" },
    "loc-fin11": { e: "The report is ready, I'll send it over before lunch.", t: "El reporte está listo, te lo envío antes del almuerzo.", s: "Cuando le avisas a tu jefe o cliente que terminaste un informe.", sEn: "When you tell your boss or client that you've finished a report.", n: "Para sonar más formal en correos di \"The report is now ready for your review\".", nEn: "To sound more formal in emails, say \"The report is now ready for your review\"." },
    "loc-fin12": { e: "Good news, the payment was approved, so we can ship right away.", t: "Buenas noticias, el pago fue aprobado, así que podemos enviar de inmediato.", s: "Cuando confirmas que un cobro o transacción pasó sin problema.", sEn: "When you confirm that a charge or transaction went through without issues.", n: "\"Approved\" se pronuncia \"aPRUVD\", con la d final suave, no \"aprobed\".", nEn: "\"Approved\" sounds like \"aPRUVD\", with a soft final d, not \"aprobed\"." },
    // ===================== Logistics & shipping (logistica-en) =====================
    "loc-log01": { e: "Don't worry, the order ships today and you'll have it by Friday.", t: "No se preocupe, el pedido sale hoy y lo tendrá para el viernes.", s: "Cuando le confirmas a un cliente que su pedido se despacha el mismo día.", sEn: "When you confirm to a customer that their order goes out the same day.", n: "También puedes decir \"the order is going out today\" para sonar más natural.", nEn: "You can also say \"the order is going out today\" to sound more natural." },
    "loc-log02": { e: "Here's the tracking number so you can follow your package online.", t: "Aquí está el número de rastreo para que siga su paquete en línea.", s: "Cuando le das al cliente el código para seguir su envío.", sEn: "When you give the customer the code to track their shipment.", n: "\"Tracking\" se dice \"TRA-king\"; evita pronunciar la c como en español.", nEn: "\"Tracking\" is said \"TRA-king\"; avoid pronouncing the c the Spanish way." },
    "loc-log03": { e: "Good news, it cleared customs this morning, so it should arrive soon.", t: "Buenas noticias, pasó por la aduana esta mañana, así que debería llegar pronto.", s: "Cuando informas que un envío internacional ya salió de la aduana.", sEn: "When you report that an international shipment has left customs.", n: "Se dice \"cleared customs\", no \"passed customs\"; \"customs\" siempre va en plural.", nEn: "Say \"cleared customs\", not \"passed customs\"; \"customs\" is always plural." },
    "loc-log04": { e: "Delivery takes three days, but it's usually a bit faster.", t: "La entrega tarda tres días, pero normalmente es un poco más rápido.", s: "Cuando le explicas al cliente cuánto demora recibir su pedido.", sEn: "When you explain to the customer how long their order takes to arrive.", n: "También suena natural \"it takes three days to deliver\".", nEn: "It also sounds natural to say \"it takes three days to deliver\"." },
    "loc-log05": { e: "The package is on its way and should reach you tomorrow.", t: "El paquete está en camino y debería llegarle mañana.", s: "Cuando tranquilizas a un cliente que pregunta dónde está su pedido.", sEn: "When you reassure a customer asking where their order is.", n: "Cuidado: es \"on its way\" (con apóstrofo no), no \"on it's way\".", nEn: "Careful: it's \"on its way\" (no apostrophe), not \"on it's way\"." },
    "loc-log06": { e: "I need the shipping address before I can send this out.", t: "Necesito la dirección de envío antes de poder despachar esto.", s: "Cuando le pides al cliente a dónde debe llegar el paquete.", sEn: "When you ask the customer where the package should be delivered.", n: "Para ser más cortés di \"Could you give me the shipping address?\".", nEn: "To be more polite, say \"Could you give me the shipping address?\"." },
    "loc-log07": { e: "I'm sorry, the shipment was delayed and will arrive a day late.", t: "Lo siento, el embarque se retrasó y llegará un día tarde.", s: "Cuando avisas que un envío llegará más tarde de lo previsto.", sEn: "When you let someone know a shipment will arrive later than planned.", n: "\"Delayed\" se pronuncia \"di-LEID\"; no olvides la d final.", nEn: "\"Delayed\" is said \"di-LEID\"; don't drop the final d." },
    "loc-log08": { e: "Please confirm the quantity so we don't ship the wrong amount.", t: "Confirme la cantidad, por favor, para no enviar la cantidad equivocada.", s: "Cuando necesitas que el cliente verifique cuántas unidades quiere.", sEn: "When you need the customer to verify how many units they want.", n: "\"Quantity\" se dice \"KUAN-ti-ti\"; ojo con no decir \"cuantity\".", nEn: "\"Quantity\" is said \"KUAN-ti-ti\"; don't say \"cuantity\"." },
    "loc-log09": { e: "The container arrives on Monday, so let's plan the unloading.", t: "El contenedor llega el lunes, así que organicemos la descarga.", s: "Cuando coordinas con tu equipo la llegada de un cargamento grande.", sEn: "When you coordinate with your team about a large shipment arriving.", n: "En inglés se usa \"on\" con días: \"on Monday\", no \"the Monday\".", nEn: "In English use \"on\" with days: \"on Monday\", not \"the Monday\"." },
    "loc-log10": { e: "What's the total weight? I need it to calculate the freight cost.", t: "¿Cuál es el peso total? Lo necesito para calcular el costo de flete.", s: "Cuando preguntas cuánto pesa todo el envío para cotizar.", sEn: "When you ask how much the whole shipment weighs in order to quote.", n: "\"Weight\" suena como \"ueit\"; la w no se pronuncia como gu.", nEn: "\"Weight\" sounds like \"ueit\"; the w isn't a hard g sound." },
    "loc-log11": { e: "I'm attaching the shipping invoice for your records.", t: "Adjunto la factura de envío para sus registros.", s: "Cuando mandas por correo la factura del transporte al cliente.", sEn: "When you email the shipping invoice to the customer.", n: "En correos también se usa \"Please find attached the shipping invoice\".", nEn: "In emails you can also use \"Please find attached the shipping invoice\"." },
    "loc-log12": { e: "Shipping is free on all orders over fifty dollars.", t: "El envío es gratis en todos los pedidos de más de cincuenta dólares.", s: "Cuando le dices al cliente que no paga costo de envío.", sEn: "When you tell the customer there's no delivery charge.", n: "También se dice \"free shipping\"; \"gratis\" nunca se dice en inglés formal.", nEn: "You can also say \"free shipping\"; never use \"gratis\" in English." },
    // ===================== HR & feedback (feedback-en) =====================
    "loc-fb01": { e: "Great job this week, the whole team noticed your effort.", t: "Buen trabajo esta semana, todo el equipo notó tu esfuerzo.", s: "Cuando reconoces el buen desempeño de un compañero o empleado.", sEn: "When you acknowledge a coworker's or employee's good performance.", n: "Variantes naturales: \"Nice work\" o \"Well done this week\".", nEn: "Natural variants: \"Nice work\" or \"Well done this week\"." },
    "loc-fb02": { e: "Let's set a goal for next month and check in on it weekly.", t: "Pongámonos una meta para el próximo mes y revisémosla cada semana.", s: "Cuando propones un objetivo en una reunión con tu equipo o jefe.", sEn: "When you propose an objective in a meeting with your team or boss.", n: "\"Goal\" se pronuncia \"goul\", con una sola sílaba.", nEn: "\"Goal\" is pronounced \"goul\", as one syllable." },
    "loc-fb03": { e: "How do you feel about your workload? I want to make sure it's manageable.", t: "¿Cómo te sientes con tu carga de trabajo? Quiero asegurarme de que sea manejable.", s: "Cuando preguntas a un empleado si tiene demasiadas tareas.", sEn: "When you ask an employee whether they have too much on their plate.", n: "\"Workload\" significa carga de trabajo; no la confundas con \"workplace\".", nEn: "\"Workload\" means amount of work; don't confuse it with \"workplace\"." },
    "loc-fb04": { e: "You're doing really well, so keep it up!", t: "Lo estás haciendo muy bien, ¡así que sigue así!", s: "Cuando animas a alguien a mantener su buen rendimiento.", sEn: "When you encourage someone to maintain their good performance.", n: "\"Keep it up\" es informal y cálido; en un correo formal usa \"keep up the good work\".", nEn: "\"Keep it up\" is informal and warm; in a formal email use \"keep up the good work\"." },
    "loc-fb05": { e: "You did great overall, but here's something to improve for next time.", t: "En general lo hiciste muy bien, pero aquí hay algo que mejorar para la próxima.", s: "Cuando das una crítica constructiva sin desmotivar a la persona.", sEn: "When you give constructive criticism without discouraging the person.", n: "Suaviza la crítica empezando con algo positivo antes del \"but\".", nEn: "Soften the criticism by starting with something positive before \"but\"." },
    "loc-fb06": { e: "I appreciate your effort, especially during such a busy week.", t: "Valoro tu esfuerzo, sobre todo en una semana tan ocupada.", s: "Cuando agradeces sinceramente la dedicación de alguien.", sEn: "When you sincerely thank someone for their dedication.", n: "\"Appreciate\" se pronuncia \"a-PRI-shi-eit\"; no digas \"apreciate\".", nEn: "\"Appreciate\" is said \"a-PRI-shi-eit\"; don't say \"apreciate\"." },
    "loc-fb07": { e: "Before we wrap up, do you have any concerns about the new schedule?", t: "Antes de terminar, ¿tienes alguna inquietud sobre el nuevo horario?", s: "Cuando cierras una reunión con un empleado y quieres darle espacio para hablar.", sEn: "When you close a meeting with an employee and want to give them room to speak up.", n: "\"Concerns\" suena más profesional que \"problems\"; usa \"problems\" solo para algo ya roto.", nEn: "\"Concerns\" sounds more professional than \"problems\"; save \"problems\" for things already broken." },
    "loc-fb08": { e: "Let's talk about your goals for the next six months.", t: "Hablemos de tus objetivos para los próximos seis meses.", s: "Al iniciar una evaluación de desempeño con alguien de tu equipo.", sEn: "When starting a performance review with someone on your team.", n: "\"Goals\" se pronuncia \"gols\", con G suave, no como la J española.", nEn: "\"Goals\" is pronounced \"gols\" with a soft G, not like the Spanish J." },
    "loc-fb09": { e: "Thank you for your work this month, the team really noticed it.", t: "Gracias por tu trabajo este mes, el equipo de verdad lo notó.", s: "Cuando reconoces el esfuerzo de un empleado al final de un periodo.", sEn: "When you recognize an employee's effort at the end of a period.", n: "Añadir un detalle concreto (\"this month\") hace que el agradecimiento se sienta sincero.", nEn: "Adding a concrete detail (\"this month\") makes the thanks feel genuine." },
    "loc-fb10": { e: "If anything comes up, just let me know, you have my support.", t: "Si surge cualquier cosa, solo avísame, cuentas con mi apoyo.", s: "Cuando tranquilizas a un miembro del equipo que enfrenta un reto.", sEn: "When reassuring a team member facing a challenge.", n: "También puedes decir \"I've got your back\", más cercano y de uso diario.", nEn: "You can also say \"I've got your back,\" which is warmer and very common." },
    // ===================== Networking (networking-en) =====================
    "loc-net01": { e: "Nice to meet you, what company do you work for?", t: "Mucho gusto, ¿en qué empresa trabajas?", s: "Al conocer a alguien en un evento de negocios y querer saber más.", sEn: "When meeting someone at a business event and wanting to know more.", n: "Di \"work for\", no \"work in\", cuando hablas del nombre de la empresa.", nEn: "Say \"work for,\" not \"work in,\" when naming the company." },
    "loc-net02": { e: "I'd love to stay in touch, let's connect on LinkedIn.", t: "Me encantaría seguir en contacto, conectemos en LinkedIn.", s: "Al despedirte de un contacto profesional que acabas de conocer.", sEn: "When saying goodbye to a professional contact you just met.", n: "\"Connect\" lleva el acento en la segunda sílaba: con-NECT.", nEn: "\"Connect\" is stressed on the second syllable: con-NECT." },
    "loc-net03": { e: "Here's my card, feel free to reach out anytime.", t: "Aquí tienes mi tarjeta, escríbeme cuando quieras.", s: "Al entregar tu tarjeta de presentación tras una buena charla.", sEn: "When handing over your business card after a good chat.", n: "\"Here's my card\" suena natural; evita el literal \"This is my card\".", nEn: "\"Here's my card\" sounds natural; avoid the literal \"This is my card.\"" },
    "loc-net04": { e: "Glad to run into you here, it's been ages!", t: "Me alegra coincidir contigo aquí, ¡hacía mucho!", s: "Cuando te encuentras por casualidad con un conocido en un evento.", sEn: "When you bump into an acquaintance by chance at an event.", n: "\"Run into\" significa encontrarse por casualidad, no correr hacia algo.", nEn: "\"Run into\" means to meet by chance, not to run toward something." },
    "loc-net05": { e: "That sounds interesting, what does your job involve?", t: "Suena interesante, ¿de qué se trata tu trabajo?", s: "Cuando quieres que alguien te explique en qué consiste su puesto.", sEn: "When you want someone to explain what their role actually consists of.", n: "\"What does your job involve?\" es más rica que \"What is your job?\".", nEn: "\"What does your job involve?\" is richer than \"What is your job?\"" },
    "loc-net06": { e: "Do you come to these events often, or is this your first one?", t: "¿Vienes seguido a estos eventos, o es el primero?", s: "Para romper el hielo con alguien en una conferencia o feria.", sEn: "To break the ice with someone at a conference or fair.", n: "\"Often\" se puede pronunciar con la T muda: \"o-fen\".", nEn: "\"Often\" can be pronounced with a silent T: \"o-fen.\"" },
    "loc-net07": { e: "Your project is great, we should work together sometime.", t: "Tu proyecto está genial, deberíamos colaborar algún día.", s: "Cuando ves potencial para una alianza con otro profesional.", sEn: "When you see potential for a partnership with another professional.", n: "Agrega \"sometime\" para que suene a propuesta abierta, no a compromiso firme.", nEn: "Add \"sometime\" so it sounds like an open suggestion, not a firm commitment." },
    "loc-net08": { e: "Great talking with you, I'll message you next week with the details.", t: "Qué bueno hablar contigo, te escribo la próxima semana con los detalles.", s: "Al cerrar una conversación prometiendo dar seguimiento.", sEn: "When closing a conversation by promising to follow up.", n: "Cumple lo que prometes: enviar el mensaje fortalece la red de contactos.", nEn: "Follow through: actually sending the message is what builds your network." },
    "loc-net09": { e: "I loved your talk, especially the part about remote teams.", t: "Me encantó tu presentación, sobre todo la parte de los equipos remotos.", s: "Cuando te acercas a un ponente para felicitarlo después de su charla.", sEn: "When you approach a speaker to congratulate them after their talk.", n: "\"Talk\" aquí significa charla o presentación, no solo \"hablar\".", nEn: "Here \"talk\" means a presentation or speech, not just \"to talk.\"" },
    "loc-net10": { e: "It was great meeting you, let's keep in touch.", t: "Fue un gusto conocerte, mantengámonos en contacto.", s: "Al despedirte de alguien con quien quieres seguir en contacto.", sEn: "When parting from someone you'd like to stay connected with.", n: "Es \"keep in touch\", no \"keep in contact\", aunque ambos se entienden.", nEn: "It's \"keep in touch,\" not \"keep in contact,\" though both are understood." },
    // ===================== Healthcare staff (salud-pro-en) =====================
    "loc-hc01": { e: "Good morning, how are you feeling today?", t: "Buenos días, ¿cómo se siente hoy?", s: "Cuando un enfermero o médico saluda a un paciente al entrar.", sEn: "When a nurse or doctor greets a patient on coming in.", n: "Usa \"feeling\" para la salud; \"How are you?\" es solo un saludo general.", nEn: "Use \"feeling\" for health; \"How are you?\" is just a general greeting." },
    "loc-hc02": { e: "Can you show me where it hurts?", t: "¿Me puede mostrar dónde le duele?", s: "Cuando examinas a un paciente y necesitas ubicar el dolor.", sEn: "When examining a patient and you need to locate the pain.", n: "\"Hurt\" se dimensiona corto: \"hert\", con la R suave americana.", nEn: "\"Hurt\" is short: \"hert,\" with the soft American R." },
    "loc-hc03": { e: "How long have you had these symptoms, a few days or longer?", t: "¿Desde cuándo tiene estos síntomas, unos días o más?", s: "Al hacer la historia clínica de un paciente nuevo.", sEn: "When taking the medical history of a new patient.", n: "\"Symptoms\" tiene la P muda: se dice \"SIM-toms\".", nEn: "\"Symptoms\" has a silent P: say \"SIM-toms.\"" },
    "loc-hc04": { e: "Take a deep breath, please, and hold it for a second.", t: "Respire profundo, por favor, y sosténgalo un segundo.", s: "Cuando auscultas a un paciente con el estetoscopio.", sEn: "When listening to a patient's chest with a stethoscope.", n: "\"Breath\" (sustantivo) suena \"brez\"; \"breathe\" (verbo) suena \"briiv\".", nEn: "\"Breath\" (noun) sounds like \"breth\"; \"breathe\" (verb) sounds like \"breeth.\"" },
    "loc-hc05": { e: "Before I prescribe anything, are you allergic to any medication?", t: "Antes de recetar algo, ¿es alérgico a algún medicamento?", s: "Antes de dar un tratamiento o medicina a un paciente.", sEn: "Before giving a treatment or medicine to a patient.", n: "\"Allergic\" se pronuncia \"a-LER-yik\", con la G suave.", nEn: "\"Allergic\" is pronounced \"a-LER-jik,\" with a soft G." },
    "loc-hc06": { e: "I'm going to take your blood pressure, just relax your arm.", t: "Le voy a tomar la presión, solo relaje el brazo.", s: "Cuando un enfermero coloca el brazalete para medir la presión.", sEn: "When a nurse puts on the cuff to measure blood pressure.", n: "En inglés es \"take your blood pressure\", no \"measure\" en el habla diaria.", nEn: "In English it's \"take your blood pressure,\" not \"measure,\" in everyday speech." },
    "loc-hc07": { e: "You need some blood tests, so please don't eat anything before tomorrow morning.", t: "Necesita unos análisis de sangre, así que por favor no coma nada antes de mañana en la mañana.", s: "Cuando, como personal de salud, le explicas a un paciente que debe hacerse exámenes de laboratorio.", sEn: "When, as healthcare staff, you tell a patient they need lab work done.", n: "Se dice 'blood tests' en plural; pronuncia 'tests' con el sonido final '-ts' claro, no 'tes'.", nEn: "Say 'blood tests' in the plural, and pronounce the final '-ts' clearly, not just 'tes'." },
    "loc-hc08": { e: "Take this medicine twice a day, once in the morning and once at night.", t: "Tome este medicamento dos veces al día, una en la mañana y una en la noche.", s: "Cuando le indicas a un paciente cómo y cuándo debe tomar su tratamiento.", sEn: "When you tell a patient how and when to take their medication.", n: "Para otras frecuencias usa 'once a day' (una vez) o 'three times a day' (tres veces).", nEn: "For other frequencies use 'once a day' or 'three times a day'." },
    "loc-hc09": { e: "Don't worry, it's nothing serious, just a mild infection.", t: "No se preocupe, no es nada grave, solo una infección leve.", s: "Cuando tranquilizas a un paciente preocupado tras revisar su caso.", sEn: "When you reassure a worried patient after looking at their case.", n: "'Serious' aquí significa 'grave', no 'serio/formal'; acompáñalo con 'Don't worry' para calmar.", nEn: "Here 'serious' means 'grave', not 'formal'; pair it with 'Don't worry' to reassure." },
    "loc-hc10": { e: "Do you have health insurance, or will you be paying out of pocket?", t: "¿Tiene seguro médico, o va a pagar de su bolsillo?", s: "Cuando, en recepción o consulta, preguntas cómo se cubrirá la atención.", sEn: "When, at the front desk or in consultation, you ask how the care will be covered.", n: "Es 'health insurance', no 'medical insurance'; 'out of pocket' significa pagar uno mismo.", nEn: "It's 'health insurance', not 'medical insurance'; 'out of pocket' means paying yourself." },
    "loc-hc11": { e: "I'll prescribe an antibiotic, and you should finish the whole course.", t: "Le voy a recetar un antibiótico, y debe terminar todo el tratamiento.", s: "Cuando decides recetar un medicamento y le explicas al paciente.", sEn: "When you decide to prescribe a medication and explain it to the patient.", n: "'Prescribe' (recetar) no es lo mismo que 'subscribe'; 'a course' es el ciclo completo del tratamiento.", nEn: "'Prescribe' is not 'subscribe', and 'a course' means the full treatment cycle." },
    "loc-hc12": { e: "Rest and drink fluids, and you'll feel better in a couple of days.", t: "Descanse y tome líquidos, y se sentirá mejor en un par de días.", s: "Cuando das recomendaciones sencillas para que el paciente se recupere en casa.", sEn: "When you give simple advice so the patient recovers at home.", n: "'Fluids' suena más profesional que 'liquids' al hablar de salud.", nEn: "'Fluids' sounds more professional than 'liquids' when talking about health." },
    "loc-hc13": { e: "If it gets worse, come back right away or go to the emergency room.", t: "Si empeora, vuelva de inmediato o vaya a urgencias.", s: "Cuando, al dar de alta a un paciente, le adviertes qué hacer si su estado empeora.", sEn: "When discharging a patient, you warn them what to do if their condition worsens.", n: "'Gets worse' es el comparativo correcto; evita decir 'gets more bad'.", nEn: "'Gets worse' is the correct comparative; avoid saying 'gets more bad'." },
    "loc-hc14": { e: "Take care of yourself, and get well soon.", t: "Cuídese, y que se mejore pronto.", s: "Cuando te despides de un paciente al final de la consulta.", sEn: "When you say goodbye to a patient at the end of the visit.", n: "'Get well soon' es para alguien que ya está enfermo; suena cálido y se usa mucho en tarjetas.", nEn: "'Get well soon' is for someone already ill; it sounds warm and is common on cards." },
    // ===================== False friends (falsos-amigos) =====================
    "loc-fa01": { e: "Congratulations, I heard your sister is pregnant!", t: "¡Felicidades, escuché que tu hermana está embarazada!", s: "Cuando comentas que alguien va a tener un bebé.", sEn: "When you mention that someone is going to have a baby.", n: "Cuidado: 'pregnant' es 'embarazada'; 'embarrassed' significa 'avergonzado', no lo confundas.", nEn: "Careful: 'pregnant' means 'embarazada'; 'embarrassed' means 'ashamed', don't mix them up." },
    "loc-fa02": { e: "I'm currently working at a hotel downtown.", t: "Actualmente estoy trabajando en un hotel en el centro.", s: "Cuando cuentas en qué trabajas o qué haces en este momento de tu vida.", sEn: "When you say what you do or where you are in life right now.", n: "'Currently' es 'actualmente'; 'actually' significa 'de hecho/en realidad', es un falso amigo clásico.", nEn: "'Currently' means 'actualmente'; 'actually' means 'in fact', a classic false friend." },
    "loc-fa03": { e: "I can't attend the meeting tomorrow, I have a doctor's appointment.", t: "No puedo asistir a la reunión mañana, tengo una cita médica.", s: "Cuando avisas que irás o no podrás ir a un evento o reunión.", sEn: "When you let someone know whether you'll be at an event or meeting.", n: "'Attend' es 'asistir a'; 'assist' significa 'ayudar', no lo uses para decir que vas a un lugar.", nEn: "'Attend' means 'to go to'; 'assist' means 'to help', don't use it for showing up somewhere." },
    "loc-fa04": { e: "There's a great bookstore around the corner if you're looking for a novel.", t: "Hay una librería muy buena a la vuelta de la esquina si busca una novela.", s: "Cuando le indicas a alguien dónde puede comprar libros.", sEn: "When you tell someone where they can buy books.", n: "'Bookstore' es donde compras libros; 'library' es la biblioteca donde los prestan, no los confundas.", nEn: "'Bookstore' is where you buy books; 'library' is where you borrow them, don't confuse them." },
    "loc-fa05": { e: "You can study quietly at the library; it's free and open all day.", t: "Puede estudiar tranquilo en la biblioteca; es gratis y abre todo el día.", s: "Cuando recomiendas un lugar tranquilo para estudiar o leer.", sEn: "When you recommend a quiet place to study or read.", n: "'Library' es la biblioteca; para comprar libros di 'bookstore', no 'library'.", nEn: "'Library' is the place that lends books; to buy books say 'bookstore', not 'library'." },
    "loc-fa06": { e: "Please be gentle, my skin is very sensitive to the sun.", t: "Por favor con cuidado, mi piel es muy sensible al sol.", s: "Cuando explicas que algo te afecta fácilmente, como la piel o las emociones.", sEn: "When you explain that something affects you easily, like your skin or feelings.", n: "'Sensitive' es 'sensible' (que se afecta); 'sensible' en inglés significa 'sensato', cuidado.", nEn: "'Sensitive' means easily affected; English 'sensible' means level-headed, beware." },
    "loc-fa07": { e: "That's a sensible decision; saving a little each month really adds up.", t: "Esa es una decisión sensata; ahorrar un poco cada mes de verdad suma.", s: "Cuando dices que algo o alguien es razonable y práctico.", sEn: "When you say something or someone is reasonable and practical.", n: "'Sensible' en inglés es 'sensato/razonable'; para 'sensible' del español usa 'sensitive'.", nEn: "English 'sensible' means reasonable; for Spanish 'sensible' use 'sensitive'." },
    "loc-fa08": { e: "I saved the report in a folder on the desktop.", t: "Guardé el informe en una carpeta en el escritorio.", s: "Cuando hablas de organizar archivos o documentos en la computadora o físicamente.", sEn: "When you talk about organizing files or documents on the computer or physically.", n: "'Folder' es 'carpeta'; 'carpet' significa 'alfombra', no lo confundas en la oficina.", nEn: "'Folder' means 'carpeta'; 'carpet' means 'alfombra', don't mix them up at the office." },
    "loc-fa09": { e: "Please take off your shoes; we just cleaned the carpet.", t: "Por favor quítese los zapatos; acabamos de limpiar la alfombra.", s: "Cuando hablas de la alfombra del piso, por ejemplo en una casa u hotel.", sEn: "When you talk about the floor carpet, for example in a home or hotel.", n: "'Carpet' es 'alfombra'; para 'carpeta' di 'folder', es un falso amigo muy común.", nEn: "'Carpet' means 'alfombra'; for 'carpeta' say 'folder', a very common false friend." },
    "loc-fa10": { e: "The new tour was a huge success; every spot sold out.", t: "El nuevo tour fue todo un éxito; se agotaron todos los cupos.", s: "Cuando cuentas que algo salió muy bien o tuvo buenos resultados.", sEn: "When you say that something went very well or got great results.", n: "'Success' es 'éxito'; 'exit' significa 'salida', no lo confundas al leer letreros.", nEn: "'Success' means 'éxito'; 'exit' means 'salida', don't confuse them when reading signs." },
    "loc-fa11": { e: "The exit is at the end of the hallway, on your right.", t: "La salida está al final del pasillo, a su derecha.", s: "Cuando le indicas a alguien por dónde salir de un edificio o lugar.", sEn: "When you tell someone how to leave a building or place.", n: "'Exit' es 'salida'; para 'éxito' (logro) di 'success', cuidado con este falso amigo.", nEn: "'Exit' means 'salida'; for 'éxito' (achievement) say 'success', beware this false friend." },
    "loc-fa12": { e: "My uncle works at a coffee factory just outside the city.", t: "Mi tío trabaja en una fábrica de café a las afueras de la ciudad.", s: "Cuando hablas del lugar donde se fabrican o producen productos.", sEn: "When you talk about the place where products are made or produced.", n: "'Factory' es 'fábrica'; 'fabric' significa 'tela', no lo confundas al hablar de manufactura.", nEn: "'Factory' means 'fábrica'; 'fabric' means 'cloth', don't confuse them when talking manufacturing." },
    "loc-fa13": { e: "This bag is made of a really soft fabric.", t: "Este bolso está hecho de una tela muy suave.", s: "Cuando le explicas a un cliente de qué material está hecho un producto.", sEn: "When you tell a customer what material a product is made of.", n: "Cuidado: 'fabric' significa tela, no fábrica; fábrica se dice 'factory'.", nEn: "Careful: 'fabric' means cloth, not a building; a building where things are made is a 'factory'." },
    "loc-fa14": { e: "I'll remember to bring your receipt next time.", t: "Voy a recordar traerle su recibo la próxima vez.", s: "Cuando le aseguras a alguien que no olvidarás algo.", sEn: "When you assure someone you won't forget something.", n: "'Remember' es recordar; no lo confundas con 'record' (grabar) ni con 'remind' (recordarle a otra persona).", nEn: "'Remember' is to recall; don't confuse it with 'record' (to tape) or 'remind' (to make someone else remember)." },
    "loc-fa15": { e: "Sorry to bother you, but could I see your ticket?", t: "Disculpe que lo moleste, pero ¿podría ver su boleto?", s: "Cuando interrumpes a un cliente con educación para pedirle algo.", sEn: "When you politely interrupt a customer to ask for something.", n: "'Bother' es molestar en el sentido de incomodar; nunca uses 'molest', que en inglés significa abuso sexual.", nEn: "'Bother' means to disturb; never say 'molest', which in English means sexual abuse." },
    "loc-fa16": { e: "I can't work today because I have a cold.", t: "Hoy no puedo trabajar porque estoy resfriado.", s: "Cuando avisas que estás resfriado y no te sientes bien.", sEn: "When you let someone know you have a cold and feel unwell.", n: "'Have a cold' es estar resfriado; 'constipated' en inglés significa estreñido, no resfriado.", nEn: "'Have a cold' means to have the sniffles; 'constipated' in English means blocked bowels, not a cold." },
    // ===================== Pronunciation (pronunciacion-en) =====================
    "loc-pron01": { e: "You can see the ship from the dock.", t: "Puede ver el barco desde el muelle.", s: "Cuando le muestras a un turista una embarcación grande en el puerto.", sEn: "When you point out a large vessel at the port to a tourist.", n: "La 'i' de 'ship' es corta, casi como 'shep'; si la alargas suena 'sheep' (oveja).", nEn: "The 'i' in 'ship' is short, almost 'shep'; stretching it turns it into 'sheep'." },
    "loc-pron02": { e: "We saw a sheep on the way up the mountain.", t: "Vimos una oveja subiendo la montaña.", s: "Cuando describes a los visitantes los animales del recorrido.", sEn: "When you describe the animals seen along the tour.", n: "'Sheep' lleva la 'i' larga (shiip); no la cortes o sonará 'ship' (barco).", nEn: "'Sheep' has a long 'ee' (sheep); cut it short and it becomes 'ship'." },
    "loc-pron03": { e: "I live near the beach, just ten minutes away.", t: "Vivo cerca de la playa, a solo diez minutos.", s: "Cuando le cuentas a un cliente dónde vives durante una charla.", sEn: "When you tell a customer where you live during small talk.", n: "'Live' (vivir) lleva 'i' corta; 'leave' (irse) lleva 'i' larga, no las mezcles.", nEn: "'Live' (reside) has a short 'i'; 'leave' (go away) has a long 'ee'; keep them apart." },
    "loc-pron04": { e: "The bus is about to leave, please hurry.", t: "El bus está a punto de salir, por favor apúrese.", s: "Cuando apuras a los pasajeros porque el transporte va a partir.", sEn: "When you rush passengers because the transport is about to depart.", n: "'Leave' suena 'liiv' con 'i' larga; 'live' con 'i' corta significa vivir.", nEn: "'Leave' sounds like 'leev' with a long vowel; short 'live' means to reside." },
    "loc-pron05": { e: "Would you like some chips with your sandwich?", t: "¿Quiere papitas con su sándwich?", s: "Cuando le ofreces un acompañamiento a un cliente en el restaurante.", sEn: "When you offer a customer a side with their meal.", n: "La 'i' de 'chip' es corta; si la alargas suena 'cheap' (barato).", nEn: "The 'i' in 'chip' is short; stretch it and it becomes 'cheap'." },
    "loc-pron06": { e: "The market is cheaper than the shops downtown.", t: "El mercado es más barato que las tiendas del centro.", s: "Cuando le explicas a un turista dónde conviene comprar.", sEn: "When you tell a tourist where the better deals are.", n: "'Cheap' lleva 'i' larga (chiip); con 'i' corta suena 'chip' (papita).", nEn: "'Cheap' has a long 'ee'; with a short 'i' it sounds like 'chip'." },
    "loc-pron07": { e: "It's right here on the table.", t: "Está justo aquí sobre la mesa.", s: "Cuando le indicas a alguien dónde está un objeto.", sEn: "When you point out where an object is.", n: "La 'i' de 'it' es corta; si la alargas suena 'eat' (comer), que es muy distinto.", nEn: "The 'i' in 'it' is short; lengthen it and you say 'eat', which means something quite different." },
    "loc-pron08": { e: "Where would you like to eat tonight?", t: "¿Dónde le gustaría comer esta noche?", s: "Cuando le sugieres planes de comida a un huésped.", sEn: "When you suggest dining plans to a guest.", n: "'Eat' lleva 'i' larga (iit); con 'i' corta suena 'it', que es el pronombre 'lo/ello'.", nEn: "'Eat' has a long 'ee'; with a short 'i' it sounds like 'it', the pronoun." },
    "loc-pron09": { e: "The restaurant is full tonight, sorry.", t: "El restaurante está lleno esta noche, lo siento.", s: "Cuando le dices a un cliente que no hay mesas disponibles.", sEn: "When you tell a customer there are no tables available.", n: "La 'u' de 'full' es corta y relajada (ful); no suena como 'fool' (tonto) con 'u' larga.", nEn: "The 'u' in 'full' is short and relaxed; it doesn't sound like 'fool' with a long 'oo'." },
    "loc-pron10": { e: "Don't be a fool, always wear your seatbelt.", t: "No sea tonto, póngase siempre el cinturón.", s: "Cuando bromeas o aconsejas a alguien sobre seguridad.", sEn: "When you joke or advise someone about safety.", n: "'Fool' lleva 'u' larga (fuul); con 'u' corta suena 'full' (lleno).", nEn: "'Fool' has a long 'oo'; with a short 'u' it sounds like 'full'." },
    "loc-pron11": { e: "The weather is bad today, take an umbrella.", t: "El clima está malo hoy, lleve un paraguas.", s: "Cuando le adviertes a un huésped sobre el mal tiempo.", sEn: "When you warn a guest about poor weather.", n: "La 'a' de 'bad' es abierta y plana; no la pronuncies como 'bed' (cama).", nEn: "The 'a' in 'bad' is open and flat; don't pronounce it like 'bed'." },
    "loc-pron12": { e: "There's an extra bed in the room for the child.", t: "Hay una cama extra en el cuarto para el niño.", s: "Cuando explicas las camas que tiene la habitación.", sEn: "When you explain the beds available in the room.", n: "'Bed' lleva 'e' como en 'mesa'; si la abres demasiado suena 'bad' (malo).", nEn: "'Bed' uses the 'e' sound; open it too much and it sounds like 'bad'." },
    "loc-pron13": { e: "A man at the door is asking for you.", t: "Un hombre en la puerta pregunta por usted.", s: "Cuando avisas a un colega que alguien lo busca.", sEn: "When you tell a coworker that someone is asking for them.", n: "'Man' (singular) lleva 'a' plana; 'men' (plural) lleva 'e', cuida la diferencia.", nEn: "'Man' (singular) uses a flat 'a'; 'men' (plural) uses 'e', so mind the difference." },
    "loc-pron14": { e: "Two men are waiting at the reception desk.", t: "Dos hombres están esperando en recepción.", s: "Cuando reportas que varias personas esperan ser atendidas.", sEn: "When you report that several people are waiting to be served.", n: "'Men' suena con 'e' como 'men' de mentira; 'man' lleva 'a' y es singular.", nEn: "'Men' uses the 'e' sound; 'man' uses 'a' and is singular." },
    // ===================== Present perfect (perfecto-en) =====================
    "loc-perf01": { e: "I have lived here for three years, so I know the area well.", t: "He vivido aquí tres años, así que conozco bien la zona.", s: "Cuando le cuentas a un turista cuánto tiempo llevas viviendo en el lugar.", sEn: "When you tell a tourist how long you have lived in the area.", n: "Usa el present perfect ('have lived') para algo que empezó en el pasado y sigue hasta hoy.", nEn: "Use the present perfect ('have lived') for something that started in the past and continues today." },
    "loc-perf02": { e: "I lived there in 2019, but I moved away after that.", t: "Viví allí en 2019, pero después me mudé.", s: "Cuando hablas de algo que ya terminó en un momento pasado.", sEn: "When you talk about something that finished at a specific past time.", n: "Con una fecha terminada (in 2019) usa el pasado simple 'lived', no 'have lived'.", nEn: "With a finished time marker (in 2019) use the simple past 'lived', not 'have lived'." },
    "loc-perf03": { e: "Have you ever traveled to South America before?", t: "¿Alguna vez has viajado a Sudamérica antes?", s: "Cuando charlas con un huésped o cliente y quieres preguntar sobre su experiencia de vida.", sEn: "When chatting with a guest or customer and you want to ask about their life experience.", n: "Usa 'ever' para preguntar por experiencias en cualquier momento de la vida, no por algo reciente.", nEn: "Use 'ever' to ask about experiences at any point in life, not about something recent." },
    "loc-perf04": { e: "I have never eaten that, but it looks delicious.", t: "Nunca he comido eso, pero se ve delicioso.", s: "Cuando un cliente te ofrece o menciona un plato que no has probado.", sEn: "When a customer offers or mentions a dish you haven't tried.", n: "Con 'never' ya va la negación, así que no digas 'I have never not eaten'.", nEn: "'Never' already makes it negative, so don't add another 'not'." },
    "loc-perf05": { e: "I have finished cleaning the room, it's ready for you.", t: "Ya terminé de limpiar el cuarto, está listo para usted.", s: "Cuando avisas que completaste una tarea y el resultado sigue siendo relevante ahora.", sEn: "When you announce you've completed a task and the result still matters now.", n: "En el día a día también se dice 'I'm finished' o 'I'm done', más informal.", nEn: "In everyday speech you can also say 'I'm finished' or 'I'm done', more casual." },
    "loc-perf06": { e: "I have just arrived, give me a minute to get ready.", t: "Acabo de llegar, deme un minuto para alistarme.", s: "Cuando llegas al trabajo o a un punto de encuentro y avisas que recién llegaste.", sEn: "When you get to work or a meeting point and let someone know you just got there.", n: "'Just' va entre 'have' y el verbo: 'have just arrived', no al final.", nEn: "'Just' goes between 'have' and the verb: 'have just arrived', not at the end." },
    "loc-perf07": { e: "I worked yesterday, so today is my day off.", t: "Trabajé ayer, así que hoy es mi día libre.", s: "Cuando cuentas algo que pasó en un momento pasado y terminado.", sEn: "When you mention something that happened at a finished moment in the past.", n: "Con 'yesterday' usa el pasado simple ('worked'), nunca el present perfect.", nEn: "With 'yesterday' use the simple past ('worked'), never the present perfect." },
    "loc-perf08": { e: "I have worked a lot today, I'm really tired.", t: "He trabajado mucho hoy, estoy muy cansado.", s: "Cuando hablas de tu esfuerzo durante un día que aún no termina.", sEn: "When you talk about your effort during a day that isn't over yet.", n: "Como 'today' aún no acaba, va el present perfect; si ya pasó el día, di 'I worked'.", nEn: "Since 'today' isn't over, use the present perfect; once the day is past, say 'I worked'." },
    "loc-perf09": { e: "Have you eaten yet, or shall I bring the menu?", t: "¿Ya comiste, o te traigo el menú?", s: "Cuando atiendes a un cliente y quieres saber si ya comió.", sEn: "When serving a customer and you want to know if they've eaten already.", n: "'Yet' va al final en preguntas y negaciones; suena como 'iet'.", nEn: "'Yet' goes at the end in questions and negatives; it sounds like 'yet'." },
    "loc-perf10": { e: "I haven't done it yet, but I'll have it ready soon.", t: "Todavía no lo he hecho, pero lo tendré listo pronto.", s: "Cuando un jefe o cliente pregunta por una tarea pendiente.", sEn: "When a boss or customer asks about a task you haven't finished.", n: "Recuerda el irregular: 'do, did, done'; aquí va 'done', no 'did'.", nEn: "Remember the irregular: 'do, did, done'; here it's 'done', not 'did'." },
    "loc-perf11": { e: "I saw her last week at the market.", t: "La vi la semana pasada en el mercado.", s: "Cuando cuentas que viste a alguien en un momento pasado específico.", sEn: "When you mention seeing someone at a specific past moment.", n: "Con 'last week' va el pasado simple 'saw'; el present perfect no acepta tiempos terminados.", nEn: "With 'last week' use the simple past 'saw'; the present perfect can't take finished time markers." },
    "loc-perf12": { e: "I have seen it before, it's a great show.", t: "Lo he visto antes, es un gran espectáculo.", s: "Cuando recomiendas algo que ya conoces sin decir cuándo exactamente.", sEn: "When recommending something you already know, without saying exactly when.", n: "Usa 'seen' (no 'saw') después de 'have'; es el irregular 'see, saw, seen'.", nEn: "Use 'seen' (not 'saw') after 'have'; it's the irregular 'see, saw, seen'." },
    // ===================== Articles a/an/the (articulos-en) =====================
    "loc-art01": { e: "I am a teacher at a local school.", t: "Soy profesor en una escuela de la zona.", s: "Cuando te presentas y dices a qué te dedicas.", sEn: "When you introduce yourself and say what you do.", n: "En inglés siempre va 'a' antes de la profesión: 'a teacher', no solo 'teacher'.", nEn: "In English you always need 'a' before a job: 'a teacher', not just 'teacher'." },
    "loc-art02": { e: "She is a doctor at the hospital downtown.", t: "Ella es médica en el hospital del centro.", s: "Cuando hablas del trabajo de otra persona.", sEn: "When you talk about someone else's job.", n: "Igual que con tu profesión, di 'a doctor'; el artículo nunca se omite.", nEn: "Just like with your own job, say 'a doctor'; the article is never dropped." },
    "loc-art03": { e: "The tour starts in an hour, so we have time for coffee.", t: "El tour empieza en una hora, así que hay tiempo para un café.", s: "Cuando informas cuánto falta para una actividad.", sEn: "When you tell someone how long until an activity starts.", n: "Se usa 'an hour' porque la 'h' es muda y suena como vocal ('an our').", nEn: "Use 'an hour' because the 'h' is silent and it sounds like a vowel ('an our')." },
    "loc-art04": { e: "She studies at a university in the capital.", t: "Ella estudia en una universidad de la capital.", s: "Cuando mencionas dónde estudia alguien.", sEn: "When you mention where someone studies.", n: "Es 'a university' porque empieza con sonido 'yu', como consonante, no 'an'.", nEn: "It's 'a university' because it starts with a 'yu' sound, treated as a consonant, not 'an'." },
    "loc-art05": { e: "The sun is strong today, don't forget your sunscreen.", t: "El sol está fuerte hoy, no olvide su protector solar.", s: "Cuando le adviertes a un cliente sobre el clima en la playa o el tour.", sEn: "When you warn a customer about the weather at the beach or on a tour.", n: "Cosas únicas llevan 'the': 'the sun', 'the moon', 'the sky'.", nEn: "Unique things take 'the': 'the sun', 'the moon', 'the sky'." },
    "loc-art06": { e: "I like coffee, especially in the morning.", t: "Me gusta el café, sobre todo en la mañana.", s: "Cuando hablas de algo en general, como tus gustos.", sEn: "When you talk about something in general, like your preferences.", n: "Para gustos generales NO uses 'the': 'I like coffee', no 'I like the coffee'.", nEn: "For general likes don't use 'the': 'I like coffee', not 'I like the coffee'." },
    "loc-art07": { e: "I play the guitar at the bar on weekends.", t: "Toco la guitarra en el bar los fines de semana.", s: "Cuando cuentas un pasatiempo o talento musical.", sEn: "When you mention a hobby or musical talent.", n: "Los instrumentos llevan 'the': 'play the guitar', 'play the piano'.", nEn: "Instruments take 'the': 'play the guitar', 'play the piano'." },
    "loc-art08": { e: "I go to school in the morning and work in the afternoon.", t: "Voy a la escuela en la mañana y trabajo en la tarde.", s: "Cuando hablas de tu rutina diaria de estudio.", sEn: "When you talk about your daily study routine.", n: "Con su propósito normal NO va 'the': 'go to school', 'go to work'.", nEn: "For its usual purpose, drop 'the': 'go to school', 'go to work'." },
    "loc-art09": { e: "Would you like an egg with your breakfast?", t: "¿Desea un huevo con su desayuno?", s: "Cuando ofreces comida a un huésped en el desayuno.", sEn: "When you offer food to a guest at breakfast.", n: "Va 'an egg' porque empieza con sonido de vocal; usa 'an' antes de a, e, i, o, u.", nEn: "It's 'an egg' because it starts with a vowel sound; use 'an' before a, e, i, o, u sounds." },
    "loc-art10": { e: "This is the best restaurant in town, you have to try it.", t: "Este es el mejor restaurante del pueblo, tiene que probarlo.", s: "Cuando recomiendas un lugar y lo destacas como el número uno.", sEn: "When you recommend a place and highlight it as number one.", n: "Los superlativos siempre llevan 'the': 'the best', 'the biggest', 'the cheapest'.", nEn: "Superlatives always take 'the': 'the best', 'the biggest', 'the cheapest'." },
    "loc-art11": { e: "I have a dog at home, so I always have a smile when I get there.", t: "Tengo un perro en casa, así que siempre llego con una sonrisa.", s: "Cuando hablas de algo tuyo en una charla casual con un cliente o compañero.", sEn: "When you mention something you own in casual chat with a guest or coworker.", n: "Usa \"a\" antes de sustantivo contable singular: \"a dog\", no \"a dogs\".", nEn: "Use \"a\" before a singular countable noun: \"a dog\", not \"a dogs\"." },
    "loc-art12": { e: "Cats are cute, but they don't like the noise here in the lobby.", t: "Los gatos son lindos, pero no les gusta el ruido aquí en el lobby.", s: "Cuando hablas de algo en general, sin artículo, en una conversación.", sEn: "When you talk about something in general, with no article, in conversation.", n: "Para hablar en general usa el plural sin \"the\": \"Cats are cute\", no \"The cats are cute\".", nEn: "To speak in general use the plural without \"the\": \"Cats are cute\", not \"The cats are cute\"." },
    // ===================== Quantities (cantidades-en) =====================
    "loc-cant01": { e: "How much money do you have on you, just in cash?", t: "¿Cuánto dinero traes contigo, solo en efectivo?", s: "Cuando preguntas por una cantidad de algo incontable, como dinero.", sEn: "When you ask about an amount of something uncountable, like money.", n: "Usa \"how much\" con incontables (money, water) y \"how many\" con contables (coins).", nEn: "Use \"how much\" with uncountables (money, water) and \"how many\" with countables (coins)." },
    "loc-cant02": { e: "How many people are in your group today?", t: "¿Cuántas personas hay en su grupo hoy?", s: "Cuando preguntas el número de personas para una mesa, tour o reserva.", sEn: "When you ask the number of people for a table, tour, or booking.", n: "\"People\" ya es plural; di \"how many people\", nunca \"how many peoples\".", nEn: "\"People\" is already plural; say \"how many people\", never \"how many peoples\"." },
    "loc-cant03": { e: "Would you like some water while you look at the menu?", t: "¿Le gustaría algo de agua mientras mira el menú?", s: "Cuando ofreces una cantidad indefinida de algo a un cliente.", sEn: "When you offer an indefinite amount of something to a guest.", n: "En ofertas y preguntas amables se usa \"some\", no \"any\": \"Would you like some water?\".", nEn: "In polite offers and questions use \"some\", not \"any\": \"Would you like some water?\"." },
    "loc-cant04": { e: "Are there any questions before we start the tour?", t: "¿Hay alguna pregunta antes de empezar el tour?", s: "Cuando preguntas si existe algo, esperando que pueda no haber nada.", sEn: "When you ask whether something exists, open to the answer being none.", n: "\"Any\" se usa en preguntas y frases negativas; en afirmaciones usa \"some\".", nEn: "\"Any\" is used in questions and negatives; in positive statements use \"some\"." },
    "loc-cant05": { e: "There's a lot of work today, so let's split the tables.", t: "Hay mucho trabajo hoy, así que dividamos las mesas.", s: "Cuando comentas que hay gran cantidad de algo, en el trabajo.", sEn: "When you note there's a large amount of something at work.", n: "\"A lot of\" sirve para contables e incontables; es más natural que \"much\" en frases afirmativas.", nEn: "\"A lot of\" works for both countable and uncountable, and is more natural than \"much\" in positive sentences." },
    "loc-cant06": { e: "We have few options left in your size, sorry.", t: "Nos quedan pocas opciones en su talla, lo siento.", s: "Cuando avisas a un cliente que casi no hay disponibilidad.", sEn: "When you tell a customer there's almost nothing available.", n: "\"Few\" suena negativo (casi nada); \"a few\" suena positivo (algunos disponibles).", nEn: "\"Few\" sounds negative (almost none); \"a few\" sounds positive (some available)." },
    "loc-cant07": { e: "Would you like a little sugar in your coffee?", t: "¿Le gustaría un poco de azúcar en el café?", s: "Cuando ofreces una pequeña cantidad de algo incontable.", sEn: "When you offer a small amount of something uncountable.", n: "Usa \"a little\" con incontables (sugar, milk) y \"a few\" con contables (cookies).", nEn: "Use \"a little\" with uncountables (sugar, milk) and \"a few\" with countables (cookies)." },
    "loc-cant08": { e: "I'll send you all the information by email this afternoon.", t: "Le enviaré toda la información por correo esta tarde.", s: "Cuando hablas de datos o detalles que vas a compartir.", sEn: "When you talk about details you're going to share.", n: "\"Information\" es incontable: nunca \"informations\", y di \"some information\".", nEn: "\"Information\" is uncountable: never \"informations\", and say \"some information\"." },
    "loc-cant09": { e: "Many tourists come here in July, so we get really busy.", t: "Muchos turistas vienen aquí en julio, así que nos llenamos.", s: "Cuando comentas que hay gran número de personas o cosas contables.", sEn: "When you mention a large number of people or countable things.", n: "\"Many\" va con contables en plural; con incontables usa \"much\" o \"a lot of\".", nEn: "\"Many\" goes with plural countables; with uncountables use \"much\" or \"a lot of\"." },
    "loc-cant10": { e: "Sorry, there's too much noise here. Let me find you a quieter table.", t: "Disculpe, hay demasiado ruido aquí. Le busco una mesa más tranquila.", s: "Cuando reconoces que algo molesto es excesivo y ofreces solución.", sEn: "When you acknowledge something bothersome is excessive and offer a fix.", n: "\"Too much\" tiene tono negativo (más de lo bueno); no es lo mismo que \"a lot of\".", nEn: "\"Too much\" has a negative tone (more than is good); it's not the same as \"a lot of\"." },
    "loc-cant11": { e: "Take your time, we have enough time before the bus leaves.", t: "Tómese su tiempo, tenemos suficiente tiempo antes de que salga el bus.", s: "Cuando tranquilizas a alguien diciendo que no hay prisa.", sEn: "When you reassure someone there's no rush.", n: "\"Enough\" va antes del sustantivo: \"enough time\", no \"time enough\".", nEn: "\"Enough\" comes before the noun: \"enough time\", not \"time enough\"." },
    "loc-cant12": { e: "I'm sorry, we're out of the red ones. I don't have any right now.", t: "Lo siento, se nos acabaron los rojos. No tengo ninguno ahora.", s: "Cuando le dices a un cliente que no queda nada de lo que pidió.", sEn: "When you tell a customer there's none left of what they asked for.", n: "En negativas usa \"any\": \"I don't have any\", no \"I don't have no\".", nEn: "In negatives use \"any\": \"I don't have any\", not \"I don't have no\"." },
    // ===================== Modal verbs (modales-en) =====================
    "loc-mod01": { e: "Excuse me, could you help me carry these bags upstairs?", t: "Disculpe, ¿podría ayudarme a subir estas maletas?", s: "Cuando pides un favor de forma educada a un cliente o compañero.", sEn: "When you politely ask a guest or coworker for a favor.", n: "\"Could you\" es más cortés que \"can you\" para pedir favores.", nEn: "\"Could you\" is more polite than \"can you\" for asking favors." },
    "loc-mod02": { e: "You should rest a bit; you look really tired today.", t: "Deberías descansar un poco; te ves muy cansado hoy.", s: "Cuando das un consejo amable a un compañero o cliente.", sEn: "When you give friendly advice to a coworker or guest.", n: "\"Should\" es un consejo, no una orden; el verbo va sin \"to\": \"should rest\".", nEn: "\"Should\" is advice, not an order; the verb has no \"to\": \"should rest\"." },
    "loc-mod03": { e: "I'm sorry, I must go now, but my colleague will help you.", t: "Lo siento, debo irme ahora, pero mi compañero le ayudará.", s: "Cuando te despides porque tienes una obligación que cumplir.", sEn: "When you excuse yourself because you have an obligation.", n: "\"Must\" suena fuerte; para algo menos formal di \"I have to go\".", nEn: "\"Must\" sounds strong; for something softer say \"I have to go\"." },
    "loc-mod04": { e: "May I come in? I have your fresh towels.", t: "¿Puedo pasar? Le traigo toallas limpias.", s: "Cuando pides permiso para entrar a la habitación de un huésped.", sEn: "When you ask permission to enter a guest's room.", n: "\"May I\" es la forma más educada de pedir permiso; \"Can I\" es más informal.", nEn: "\"May I\" is the most polite way to ask permission; \"Can I\" is more informal." },
    "loc-mod05": { e: "Can I borrow your phone for a second to call the office?", t: "¿Me prestas tu teléfono un segundo para llamar a la oficina?", s: "Cuando pides usar algo de alguien por un momento.", sEn: "When you ask to use something of someone's for a moment.", n: "\"Borrow\" es recibir prestado; \"lend\" es dar prestado, no los confundas.", nEn: "\"Borrow\" is to receive on loan; \"lend\" is to give on loan, don't mix them up." },
    "loc-mod06": { e: "We could try the other route if there's too much traffic.", t: "Podríamos intentar la otra ruta si hay demasiado tráfico.", s: "Cuando sugieres una opción con suavidad, sin imponerla.", sEn: "When you gently suggest an option without imposing it.", n: "\"Could\" suaviza la sugerencia; suena menos directo que \"we will try\".", nEn: "\"Could\" softens the suggestion; it sounds less direct than \"we will try\"." },
    "loc-mod07": { e: "You shouldn't worry, your room will be ready in a few minutes.", t: "No deberías preocuparte, tu habitación estará lista en unos minutos.", s: "Cuando tranquilizas a un cliente que está ansioso por algo.", sEn: "When you reassure a customer who is anxious about something.", n: "\"Shouldn't\" suena como \"shudnt\", sin pronunciar la L; para mas formal di \"there's no need to worry\".", nEn: "\"Shouldn't\" sounds like \"shudnt\" with a silent L; for something more formal say \"there's no need to worry\"." },
    "loc-mod08": { e: "Would you mind waiting a moment while I check the availability?", t: "¿Te importaría esperar un momento mientras reviso la disponibilidad?", s: "Cuando necesitas que el cliente espere y quieres pedirlo con cortesia.", sEn: "When you need the customer to wait and want to ask politely.", n: "Ojo: la respuesta amable a \"Would you mind?\" es \"No, not at all\" (no, no importa), aunque suene raro en espanol.", nEn: "Note: the polite answer to \"Would you mind?\" is \"No, not at all,\" even though it sounds odd in Spanish." },
    "loc-mod09": { e: "You have to sign here at the bottom and write today's date.", t: "Tienes que firmar aquí abajo y escribir la fecha de hoy.", s: "Cuando le indicas a un cliente dónde firmar un formulario o registro.", sEn: "When you tell a customer where to sign a form or register.", n: "\"Have to\" expresa obligación; para suavizarlo usa \"I'll just need you to sign here\".", nEn: "\"Have to\" expresses obligation; to soften it use \"I'll just need you to sign here\"." },
    "loc-mod10": { e: "It might rain this afternoon, so I'd bring an umbrella for the tour.", t: "Quizás llueva esta tarde, así que yo llevaría un paraguas para el tour.", s: "Cuando adviertes sobre el clima a turistas antes de salir.", sEn: "When you warn tourists about the weather before heading out.", n: "\"Might\" y \"may\" son casi iguales para posibilidad; \"might\" suena un poco más informal.", nEn: "\"Might\" and \"may\" are nearly the same for possibility; \"might\" sounds slightly more casual." },
    "loc-mod11": { e: "Can I help you find something on the menu?", t: "¿Puedo ayudarte a encontrar algo en el menú?", s: "Cuando te acercas a un cliente que parece indeciso o perdido.", sEn: "When you approach a customer who looks unsure or lost.", n: "Para sonar más formal con clientes usa \"May I help you?\" en lugar de \"Can I help?\".", nEn: "To sound more formal with customers, use \"May I help you?\" instead of \"Can I help?\"." },
    "loc-mod12": { e: "We should go now if we want to catch the boat on time.", t: "Deberíamos irnos ya si queremos alcanzar el bote a tiempo.", s: "Cuando, como guía, apuras amablemente al grupo para no llegar tarde.", sEn: "When, as a guide, you gently rush the group so you won't be late.", n: "\"Should\" da una sugerencia, no una orden; para más urgencia di \"we really need to go now\".", nEn: "\"Should\" gives a suggestion, not an order; for more urgency say \"we really need to go now\"." },
    // ===================== Phrasal verbs (phrasal-en) =====================
    "loc-phr01": { e: "You can check in any time after three this afternoon.", t: "Puede registrarse a cualquier hora después de las tres de la tarde.", s: "Cuando le explicas a un huésped a qué hora puede hacer el registro.", sEn: "When you explain to a guest what time they can check in.", n: "El verbo va separado (\"check in\"), pero el sustantivo va junto: \"check-in is at three\".", nEn: "The verb is two words (\"check in\"), but the noun is hyphenated: \"check-in is at three\"." },
    "loc-phr02": { e: "What time would you like to check out tomorrow?", t: "¿A qué hora le gustaría salir mañana?", s: "Cuando coordinas con el huésped la hora de salida del hotel.", sEn: "When you arrange the guest's hotel departure time.", n: "\"Check out\" también significa \"echar un vistazo\": \"check out our menu\" (mira nuestro menú).", nEn: "\"Check out\" also means \"take a look\": \"check out our menu\"." },
    "loc-phr03": { e: "Let me turn on the air conditioning for you.", t: "Déjeme encenderle el aire acondicionado.", s: "Cuando enciendes un aparato para la comodidad del cliente.", sEn: "When you switch on a device for the customer's comfort.", n: "Puedes separarlo con el objeto: \"turn the lights on\" o \"turn on the lights\", ambos correctos.", nEn: "You can split it with the object: \"turn the lights on\" or \"turn on the lights,\" both correct." },
    "loc-phr04": { e: "Please remember to turn off the lights when you leave the room.", t: "Por favor recuerde apagar las luces cuando salga de la habitación.", s: "Cuando le pides a un huésped que apague algo al salir.", sEn: "When you ask a guest to switch something off when leaving.", n: "Lo opuesto de \"turn off\" es \"turn on\"; con el pronombre va siempre en medio: \"turn it off\".", nEn: "The opposite of \"turn off\" is \"turn on\"; with a pronoun it always goes in the middle: \"turn it off\"." },
    "loc-phr05": { e: "I can pick you up at the airport at eight if you'd like.", t: "Puedo recogerlo en el aeropuerto a las ocho si gusta.", s: "Cuando ofreces transporte y vas a buscar al cliente en un lugar.", sEn: "When you offer transport and will collect the customer somewhere.", n: "\"Pick up\" también sirve para objetos: \"pick up your order\" (recoger tu pedido).", nEn: "\"Pick up\" also works for objects: \"pick up your order\"." },
    "loc-phr06": { e: "Sorry, the elevator broke down, so please use the stairs for now.", t: "Disculpe, el ascensor se averió, así que use las escaleras por ahora.", s: "Cuando avisas que una máquina o vehículo dejó de funcionar.", sEn: "When you warn that a machine or vehicle has stopped working.", n: "\"Break down\" es para máquinas o vehículos; para una persona que llora, también significa derrumbarse emocionalmente.", nEn: "\"Break down\" is for machines or vehicles; for a person it can also mean to break down emotionally." },
    "loc-phr07": { e: "Let me look up the bus schedule for you on my phone.", t: "Déjeme buscarle el horario del bus en mi teléfono.", s: "Cuando buscas información para un cliente en internet o una lista.", sEn: "When you look up information for a customer online or in a list.", n: "\"Look up\" es buscar un dato; \"look for\" es buscar algo físico que perdiste, no los confundas.", nEn: "\"Look up\" is to find information; \"look for\" is to search for a lost object, don't mix them up." },
    "loc-phr08": { e: "I usually get up at five to open the bakery before sunrise.", t: "Normalmente me levanto a las cinco para abrir la panadería antes del amanecer.", s: "Cuando hablas de tu rutina diaria o tus horarios de trabajo.", sEn: "When you talk about your daily routine or work schedule.", n: "\"Get up\" es salir de la cama; \"wake up\" es despertarse, aunque sigas acostado.", nEn: "\"Get up\" is to leave the bed; \"wake up\" is to stop sleeping, even while still lying down." },
    "loc-phr09": { e: "Please go on, I'm listening to everything you're telling me.", t: "Continúe, por favor, estoy escuchando todo lo que me dice.", s: "Cuando animas a un cliente a seguir hablando o explicando.", sEn: "When you encourage a customer to keep talking or explaining.", n: "\"Go on\" también puede significar suceder: \"What's going on?\" es \"¿Qué está pasando?\".", nEn: "\"Go on\" can also mean to happen: \"What's going on?\" means \"What's happening?\"." },
    "loc-phr10": { e: "Could you fill out this form with your name and contact details?", t: "¿Podría rellenar este formulario con su nombre y datos de contacto?", s: "Cuando le pides a un cliente que complete un formulario.", sEn: "When you ask a customer to complete a form.", n: "\"Fill out\" (US) y \"fill in\" (UK) significan lo mismo; ambos se entienden en cualquier lado.", nEn: "\"Fill out\" (US) and \"fill in\" (UK) mean the same thing; both are understood everywhere." },
    "loc-phr11": { e: "Hold on a second, I'll connect you with my manager.", t: "Espere un segundo, lo comunico con mi gerente.", s: "Cuando, por teléfono, le pides al cliente que espere en línea.", sEn: "When, on the phone, you ask the customer to wait on the line.", n: "\"Hold on\" también significa agarrarse fuerte: \"hold on tight\" en un bote o bus.", nEn: "\"Hold on\" also means to grip tightly: \"hold on tight\" on a boat or bus." },
    "loc-phr12": { e: "We need to hurry up or we'll miss the start of the tour.", t: "Tenemos que darnos prisa o nos perderemos el inicio del tour.", s: "Cuando apuras a alguien porque van con el tiempo justo.", sEn: "When you rush someone because time is running short.", n: "Para sonar amable con clientes, suaviza con \"if you don't mind, we should hurry a little\".", nEn: "To sound polite with customers, soften it with \"if you don't mind, we should hurry a little\"." },
    "loc-phr13": { e: "Please give back the key card at reception before you leave.", t: "Por favor devuelva la tarjeta llave en recepción antes de irse.", s: "Cuando pides que te regresen algo prestado, como una llave.", sEn: "When you ask for something borrowed to be returned, like a key.", n: "Con pronombre, separa el verbo: \"give it back\", nunca \"give back it\".", nEn: "With a pronoun, split the verb: \"give it back,\" never \"give back it\"." },
    "loc-phr14": { e: "You'll need to put on your life jacket before we leave the dock.", t: "Tendrá que ponerse el chaleco salvavidas antes de salir del muelle.", s: "Cuando indicas que se pongan una prenda por seguridad o normas.", sEn: "When you tell someone to put on a garment for safety or rules.", n: "\"Put on\" es la acción de ponerse algo; \"wear\" es tenerlo puesto, no los confundas.", nEn: "\"Put on\" is the action of dressing; \"wear\" is having it on, don't confuse them." },
    // ===================== Comparatives (comparar-en) =====================
    "loc-comp01": { e: "This room is bigger and has a nice view of the sea.", t: "Esta habitación es más grande y tiene una linda vista al mar.", s: "Cuando ofreces una opción mejor a un huésped o cliente comparando tamaños.", sEn: "When you offer a guest or customer a better option by comparing sizes.", n: "Usa 'bigger', no 'more big'; los adjetivos cortos llevan '-er'.", nEn: "Say 'bigger', not 'more big'; short adjectives take '-er'." },
    "loc-comp02": { e: "If you'd like, I can bring you a smaller portion.", t: "Si quiere, le puedo traer una porción más pequeña.", s: "Cuando le ofreces al cliente una versión más chica de algo.", sEn: "When you offer the customer a smaller version of something.", n: "La 'a' de 'smaller' suena como 'eihl-er', no como en español.", nEn: "The 'a' in 'smaller' sounds like 'aw', not the Spanish 'a'." },
    "loc-comp03": { e: "Our ceviche is the best dish on the menu, I promise.", t: "Nuestro ceviche es el mejor plato del menú, se lo aseguro.", s: "Cuando recomiendas con seguridad lo más destacado de tu negocio.", sEn: "When you confidently recommend the standout of your business.", n: "Siempre 'the best', nunca 'the most good'.", nEn: "Always 'the best', never 'the most good'." },
    "loc-comp04": { e: "Monday traffic is the worst, so let's leave a bit earlier.", t: "El tráfico del lunes es el peor, así que salgamos un poco antes.", s: "Cuando explicas por qué algo conviene evitar o adelantar.", sEn: "When you explain why something is best avoided or done earlier.", n: "'Worst' rima con 'first'; no lo confundas con 'worse' (peor que).", nEn: "'Worst' rhymes with 'first'; don't mix it up with 'worse' (worse than)." },
    "loc-comp05": { e: "This handmade bag is as expensive as the leather one, but it lasts longer.", t: "Este bolso hecho a mano es tan caro como el de cuero, pero dura más.", s: "Cuando comparas dos productos que cuestan parecido para vender.", sEn: "When you compare two similarly priced products to make a sale.", n: "La estructura es 'as ... as'; no olvides el segundo 'as'.", nEn: "The structure is 'as ... as'; don't drop the second 'as'." },
    "loc-comp06": { e: "The market is cheaper than the mall if you want souvenirs.", t: "El mercado es más barato que el centro comercial si quiere recuerdos.", s: "Cuando le aconsejas a un turista dónde ahorrar dinero.", sEn: "When you advise a tourist where to save money.", n: "'Cheaper' está bien, pero 'a better deal' suena más positivo al vender.", nEn: "'Cheaper' is fine, but 'a better deal' sounds more positive when selling." },
    "loc-comp07": { e: "The metro is faster than the bus at this time of day.", t: "El metro es más rápido que el bus a esta hora del día.", s: "Cuando recomiendas la mejor forma de moverse por la ciudad.", sEn: "When you recommend the best way to get around the city.", n: "Pronuncia 'faster' con 'a' abierta; no digas 'fas-ter' cortado.", nEn: "Pronounce 'faster' with an open 'a'; don't clip it." },
    "loc-comp08": { e: "The fresh juice is better than the soda, and it's local.", t: "El jugo natural es mejor que la gaseosa, y es de la región.", s: "Cuando sugieres una opción más sana o de mayor calidad.", sEn: "When you suggest a healthier or higher-quality option.", n: "Recuerda 'better than', no 'more better'.", nEn: "Remember 'better than', not 'more better'." },
    "loc-comp09": { e: "This is the prettiest beach on the whole tour.", t: "Esta es la playa más bonita de todo el tour.", s: "Cuando como guía destacas el lugar más lindo del recorrido.", sEn: "When, as a guide, you highlight the most beautiful spot of the tour.", n: "Adjetivos que terminan en 'y' cambian a '-iest': pretty, prettiest.", nEn: "Adjectives ending in 'y' become '-iest': pretty, prettiest." },
    "loc-comp10": { e: "Taking the elevator is easier with all that luggage.", t: "Tomar el ascensor es más fácil con todo ese equipaje.", s: "Cuando le sugieres al huésped la opción más cómoda.", sEn: "When you suggest the more convenient option to a guest.", n: "'Easier' se dice 'II-zi-er'; la primera sílaba es larga.", nEn: "'Easier' is said 'EE-zee-er'; the first syllable is long." },
    // ===================== Diving & snorkel (buceo-en) =====================
    "loc-buc01": { e: "Before we get in, put on your mask and fins and let me check the strap.", t: "Antes de entrar, pónganse la máscara y las aletas y déjenme revisar la correa.", s: "Cuando preparas al grupo justo antes de entrar al agua.", sEn: "When you get the group ready right before entering the water.", n: "'Put on' lleva el objeto en medio: 'put it on'.", nEn: "'Put on' takes the object in the middle: 'put it on'." },
    "loc-buc02": { e: "While snorkeling, don't hold your breath, just relax and breathe.", t: "Mientras hacen esnórquel, no contengan la respiración, solo relájense y respiren.", s: "Cuando das una regla de seguridad clave antes de bucear.", sEn: "When you give a key safety rule before diving.", n: "'Breath' (sustantivo) suena distinto a 'breathe' (verbo, con 'th' suave).", nEn: "'Breath' (noun) sounds different from 'breathe' (verb, with soft 'th')." },
    "loc-buc03": { e: "Stay calm and breathe slowly, there's no rush down here.", t: "Mantengan la calma y respiren despacio, no hay prisa aquí abajo.", s: "Cuando tranquilizas a un cliente nervioso bajo el agua.", sEn: "When you reassure a nervous customer underwater.", n: "'Slowly' es adverbio; di 'breathe slowly', no 'breathe slow'.", nEn: "'Slowly' is an adverb; say 'breathe slowly', not 'breathe slow'." },
    "loc-buc04": { e: "Follow me and stay close so I can keep an eye on everyone.", t: "Síganme y manténganse cerca para que pueda cuidar a todos.", s: "Cuando guías al grupo en el agua y quieres mantenerlos unidos.", sEn: "When you lead the group in the water and want to keep them together.", n: "'Stay close' es más natural que 'stay near' en este contexto.", nEn: "'Stay close' sounds more natural than 'stay near' here." },
    "loc-buc05": { e: "As we go down, equalize your ears by pinching your nose and blowing gently.", t: "Mientras bajamos, igualen la presión de sus oídos tapándose la nariz y soplando suave.", s: "Cuando explicas cómo evitar el dolor de oídos al descender.", sEn: "When you explain how to avoid ear pain while descending.", n: "'Equalize' lleva el acento al inicio: 'II-kwa-laiz'.", nEn: "'Equalize' is stressed on the first syllable: 'EE-kwa-lize'." },
    "loc-buc06": { e: "Please don't touch the coral, it's very fragile and protected.", t: "Por favor no toquen el coral, es muy frágil y está protegido.", s: "Cuando proteges el arrecife y pides cuidado al grupo.", sEn: "When you protect the reef and ask the group to be careful.", n: "Agregar 'please' suaviza la orden y suena más amable.", nEn: "Adding 'please' softens the command and sounds friendlier." },
    "loc-buc07": { e: "Have you dived before, or is this your first time?", t: "¿Han buceado antes, o es su primera vez?", s: "Cuando preguntas la experiencia del cliente antes de empezar.", sEn: "When you ask about a customer's experience before starting.", n: "El participio es 'dived' o 'dove'; ambos se usan, 'dived' es más seguro.", nEn: "The past participle is 'dived' or 'dove'; both work, 'dived' is safest." },
    "loc-buc08": { e: "This is the signal to go up, a thumbs-up means we surface.", t: "Esta es la señal de subir; el pulgar arriba significa que salimos.", s: "Cuando enseñas las señas de mano antes de la inmersión.", sEn: "When you teach the hand signals before the dive.", n: "'Go up' es subir; 'surface' es un verbo más técnico para salir a flote.", nEn: "'Go up' means ascend; 'surface' is a more technical verb for coming up." },
    "loc-buc09": { e: "Stay with your buddy at all times and never swim off alone.", t: "Quédense con su compañero en todo momento y nunca naden solos.", s: "Cuando recuerdas la regla del compañero de buceo por seguridad.", sEn: "When you remind divers of the buddy rule for safety.", n: "'Buddy' es el término estándar de buceo para 'compañero'.", nEn: "'Buddy' is the standard diving term for your partner." },
    "loc-buc10": { e: "You're lucky, visibility is good today, you'll see lots of fish.", t: "Tienen suerte, la visibilidad es buena hoy, verán muchos peces.", s: "Cuando animas al grupo comentando lo bien que se ve el agua.", sEn: "When you excite the group by noting how clear the water is.", n: "'Visibility' tiene el acento en 'bil': 'vi-zi-BI-li-ti'.", nEn: "'Visibility' is stressed on 'bil': 'vi-zi-BI-li-ty'." },
    "loc-buc11": { e: "Tell me if something is wrong with your mask or you feel uncomfortable underwater.", t: "Avísenme si algo está mal con su máscara o si se sienten incómodos bajo el agua.", s: "Cuando das instrucciones de seguridad a los buzos antes de entrar al agua.", sEn: "When you give safety instructions to divers before they go in the water.", n: "Un toque mas amable: 'Just let me know if something's wrong' suena menos brusco.", nEn: "A softer touch: 'Just let me know if something's wrong' sounds less abrupt." },
    "loc-buc12": { e: "We saw a turtle right next to the reef on our last dive!", t: "¡Vimos una tortuga justo al lado del arrecife en nuestro último buceo!", s: "Cuando comentas con emoción lo que vieron durante la inmersión.", sEn: "When you excitedly share what the group saw during the dive.", n: "Cuidado: 'turtle' se dice 'TUR-tl', no 'tur-TEL'; la L final es suave.", nEn: "Careful: 'turtle' is said 'TUR-tl', not 'tur-TEL'; the final L is soft." },
    // ===================== Trekking (trekking-en) =====================
    "loc-trk01": { e: "Drink water, we're at altitude and it's easy to get dehydrated up here.", t: "Tomen agua, estamos en altura y es fácil deshidratarse aquí arriba.", s: "Cuando recuerdas al grupo hidratarse durante una caminata en zona alta.", sEn: "When you remind the group to stay hydrated on a high-altitude hike.", n: "Variante natural: 'Keep drinking water' funciona bien como recordatorio constante.", nEn: "Natural variant: 'Keep drinking water' works well as an ongoing reminder." },
    "loc-trk02": { e: "Let's take it slow on this part, there's no rush to reach the top.", t: "Vamos despacio en esta parte, no hay prisa por llegar a la cima.", s: "Cuando el grupo va cansado y propones bajar el ritmo.", sEn: "When the group is tired and you suggest slowing the pace.", n: "'Take it slow' es muy idiomático; 'Let's go slow' tambien sirve y es mas simple.", nEn: "'Take it slow' is very idiomatic; 'Let's go slow' also works and is simpler." },
    "loc-trk03": { e: "Did you bring a rain jacket? The weather can change fast in the mountains.", t: "¿Trajeron impermeable? El clima puede cambiar rápido en la montaña.", s: "Cuando revisas que los caminantes vayan preparados antes de empezar.", sEn: "When you check that hikers are prepared before setting off.", n: "'Rain jacket' es lo comun; 'raincoat' tambien se entiende perfectamente.", nEn: "'Rain jacket' is the common term; 'raincoat' is also perfectly understood." },
    "loc-trk04": { e: "Careful, the trail is slippery here after the rain, so watch your step.", t: "Cuidado, el camino está resbaloso aquí después de la lluvia, miren dónde pisan.", s: "Cuando adviertes de un tramo peligroso en el sendero.", sEn: "When you warn about a dangerous stretch of the trail.", n: "'Slippery' lleva doble P; pronuncia 'SLI-pe-ri', no olvides la R suave.", nEn: "'Slippery' has a double P; say 'SLI-puh-ree' with a soft R." },
    "loc-trk05": { e: "We'll rest in ten minutes once we reach the lookout point.", t: "Descansamos en diez minutos cuando lleguemos al mirador.", s: "Cuando avisas al grupo que pronto habrá una pausa.", sEn: "When you let the group know a break is coming soon.", n: "'We'll' es contracción de 'we will'; suena mas natural que decir 'we will rest'.", nEn: "'We'll' is short for 'we will'; it sounds more natural than 'we will rest'." },
    "loc-trk06": { e: "Wear comfortable shoes, we'll be walking on uneven ground all day.", t: "Usen calzado cómodo, vamos a caminar sobre terreno irregular todo el día.", s: "Cuando das recomendaciones antes de iniciar la caminata.", sEn: "When you give recommendations before starting the hike.", n: "Para senderos duros di 'hiking boots'; 'shoes' sirve para caminatas faciles.", nEn: "For tough trails say 'hiking boots'; 'shoes' is fine for easy walks." },
    "loc-trk07": { e: "The hike takes four hours, so we'll be back by early afternoon.", t: "La caminata dura cuatro horas, así que estaremos de vuelta a primera hora de la tarde.", s: "Cuando explicas cuánto tiempo durará la actividad.", sEn: "When you explain how long the activity will last.", n: "Usa 'takes' para duración de una actividad; 'lasts' tambien vale: 'The hike lasts four hours'.", nEn: "Use 'takes' for an activity's duration; 'lasts' also works: 'The hike lasts four hours'." },
    "loc-trk08": { e: "How are you feeling? Let me know if anyone needs to slow down.", t: "¿Cómo se sienten? Avísenme si alguien necesita ir más despacio.", s: "Cuando revisas el estado del grupo a mitad del recorrido.", sEn: "When you check on the group's condition midway through.", n: "'How are you feeling?' pregunta por el estado físico ahora; 'How are you?' es solo un saludo.", nEn: "'How are you feeling?' asks about physical state now; 'How are you?' is just a greeting." },
    "loc-trk09": { e: "Watch the edge over here, the drop is steep so stay close to the wall.", t: "Cuidado con el borde por aquí, la caída es muy inclinada, pegúense a la pared.", s: "Cuando adviertes de un precipicio cerca del sendero.", sEn: "When you warn about a cliff edge near the trail.", n: "'Watch the edge' es una orden corta y clara; 'Be careful near the edge' suena mas suave.", nEn: "'Watch the edge' is a short, clear command; 'Be careful near the edge' sounds gentler." },
    "loc-trk10": { e: "We're almost at the top, just a few more minutes and the view is worth it.", t: "Casi llegamos a la cima, solo unos minutos más y la vista vale la pena.", s: "Cuando animas al grupo en el último tramo de subida.", sEn: "When you encourage the group on the final stretch up.", n: "'Almost at the top' anima; evita 'we arrive soon', mejor 'we're almost there'.", nEn: "'Almost at the top' is encouraging; avoid 'we arrive soon', use 'we're almost there'." },
    "loc-trk11": { e: "Protect yourselves from the sun, the rays are stronger at this altitude.", t: "Protéjanse del sol, los rayos son más fuertes a esta altura.", s: "Cuando recomiendas usar gorra y protector solar en la montaña.", sEn: "When you recommend hats and sunscreen on the mountain.", n: "Mas natural en grupo: 'Make sure you protect yourself from the sun'.", nEn: "More natural with a group: 'Make sure you protect yourself from the sun'." },
    "loc-trk12": { e: "What an amazing view! Take all the photos you want, we have time.", t: "¡Qué vista tan increíble! Tomen todas las fotos que quieran, tenemos tiempo.", s: "Cuando llegan a un mirador con un paisaje espectacular.", sEn: "When you reach a lookout with a spectacular landscape.", n: "'What a + adjetivo + sustantivo' expresa asombro; tambien 'What a view!' a secas.", nEn: "'What a + adjective + noun' expresses awe; you can also just say 'What a view!'" },
    // ===================== Airport (aeropuerto-en) =====================
    "loc-air01": { e: "How many bags are you checking today, or is it just carry-on?", t: "¿Cuántas maletas registra hoy, o solo lleva equipaje de mano?", s: "Cuando atiendes a un pasajero en el mostrador de la aerolínea.", sEn: "When you assist a passenger at the airline check-in counter.", n: "'Check a bag' es facturar; 'carry-on' es el equipaje de mano que va a la cabina.", nEn: "'Check a bag' means to send it in the hold; 'carry-on' is the bag you take onboard." },
    "loc-air02": { e: "Your flight leaves from gate twelve, which is just past security on the left.", t: "Su vuelo sale por la puerta doce, que está justo pasando seguridad a la izquierda.", s: "Cuando le indicas al pasajero por dónde abordar.", sEn: "When you tell the passenger where to board.", n: "'Gate' es la puerta de embarque; 'door' seria la puerta de una casa, no la confundas.", nEn: "'Gate' is the boarding gate; 'door' is a house door, don't mix them up." },
    "loc-air03": { e: "Window or aisle? We still have a few window seats left for this flight.", t: "¿Ventana o pasillo? Todavía nos quedan algunos asientos de ventana para este vuelo.", s: "Cuando asignas asiento a un pasajero en el check-in.", sEn: "When you assign a seat to a passenger at check-in.", n: "'Aisle' suena 'AIL', la S es muda; rima con 'mile', no la pronuncies como 'a-isle'.", nEn: "'Aisle' sounds like 'AIL', the S is silent; it rhymes with 'mile'." },
    "loc-air04": { e: "I'm sorry, the flight is delayed by about an hour due to weather.", t: "Lo siento, el vuelo está retrasado alrededor de una hora por el clima.", s: "Cuando informas a un pasajero que su vuelo saldrá tarde.", sEn: "When you inform a passenger their flight will leave late.", n: "'Delayed' es retrasado; si se cancela del todo es 'cancelled', no lo mezcles.", nEn: "'Delayed' means late; if it's called off entirely it's 'cancelled', don't mix them." },
    "loc-air05": { e: "I'm afraid your bag is overweight, so there will be an extra charge.", t: "Me temo que su maleta excede el peso, así que habrá un cargo adicional.", s: "Cuando la maleta del pasajero pasa el límite permitido en la báscula.", sEn: "When the passenger's bag is over the weight limit on the scale.", n: "'I'm afraid' antes de una mala noticia suena cortés y profesional.", nEn: "'I'm afraid' before bad news sounds polite and professional." },
    "loc-air06": { e: "Here's your boarding pass, and boarding starts about thirty minutes before departure.", t: "Aquí tiene su pase de abordar, y el embarque comienza unos treinta minutos antes de la salida.", s: "Cuando entregas el pase de abordar tras hacer el check-in.", sEn: "When you hand over the boarding pass after check-in.", n: "'Here's' es 'here is'; suena mas natural al entregar algo que 'here is your...'.", nEn: "'Here's' is 'here is'; it sounds more natural when handing something over." },
    "loc-air07": { e: "Boarding starts at two, so please be at the gate by one forty-five.", t: "El embarque empieza a las dos, así que por favor esté en la puerta a la una y cuarenta y cinco.", s: "Cuando le informas a un pasajero a qué hora comienza a abordar su vuelo.", sEn: "When you tell a passenger what time their flight starts boarding.", n: "Di \"boarding\" como \"BOR-ding\", sin pronunciar la \"a\" extra que tiene en español.", nEn: "Say \"boarding\" as \"BOR-ding\", without adding the extra vowel Spanish speakers tend to insert." },
    "loc-air08": { e: "Have your passport ready, the agent will check it at the gate.", t: "Tenga su pasaporte listo, el agente lo revisará en la puerta.", s: "Cuando le pides a un pasajero que prepare su pasaporte antes de un control.", sEn: "When you ask a passenger to get their passport out before a checkpoint.", n: "\"Have it ready\" es más natural y amable que \"prepare it\" en este contexto.", nEn: "\"Have it ready\" sounds more natural and friendly than \"prepare it\" here." },
    "loc-air09": { e: "Your connection is in Bogotá, and you'll have about two hours between flights.", t: "Su conexión es en Bogotá, y tendrá unas dos horas entre vuelos.", s: "Cuando le explicas a un pasajero dónde hace escala para tomar su siguiente vuelo.", sEn: "When you explain to a passenger where they change planes for their next flight.", n: "\"Connection\" es la escala; no la confundas con \"layover\", que es el tiempo de espera.", nEn: "\"Connection\" is the transfer; don't confuse it with \"layover\", which is the waiting time." },
    "loc-air10": { e: "Please proceed to security; the line is just to your right.", t: "Pase a seguridad, por favor; la fila está justo a su derecha.", s: "Cuando diriges a un pasajero hacia el control de seguridad del aeropuerto.", sEn: "When you direct a passenger toward the airport security checkpoint.", n: "\"Proceed to\" suena formal y educado; en el día a día también puedes decir \"go ahead to security\".", nEn: "\"Proceed to\" sounds formal and polite; casually you can also say \"go ahead to security\"." },
    "loc-air11": { e: "I'm sorry, but you can't bring liquids over 100 milliliters through security.", t: "Lo siento, pero no puede llevar líquidos de más de 100 mililitros por seguridad.", s: "Cuando le informas a un pasajero que un líquido no está permitido en el control.", sEn: "When you tell a passenger that a liquid isn't allowed through the checkpoint.", n: "\"Can't\" se pronuncia corto; cuida no decir \"can\" porque cambia totalmente el sentido.", nEn: "\"Can't\" is pronounced short; be careful not to say \"can\", which flips the meaning." },
    "loc-air12": { e: "Here's your boarding pass, have a good flight!", t: "Aquí tiene su pase de abordar, ¡buen vuelo!", s: "Cuando te despides de un pasajero justo antes de que aborde su avión.", sEn: "When you say goodbye to a passenger right before they board their plane.", n: "También puedes decir \"safe flight\" o \"enjoy your flight\" para variar.", nEn: "You can also say \"safe flight\" or \"enjoy your flight\" for variety." },
    // ===================== Car rental (alquiler-auto-en) =====================
    "loc-aut01": { e: "How many days do you need it for? Our weekly rate is cheaper.", t: "¿Por cuántos días lo necesita? Nuestra tarifa semanal sale más barata.", s: "Cuando un cliente quiere rentar un auto y le preguntas la duración.", sEn: "When a customer wants to rent a car and you ask how long for.", n: "Es más natural agregar \"for\" al final: \"How many days do you need it for?\".", nEn: "It sounds more natural to add \"for\" at the end: \"How many days do you need it for?\"." },
    "loc-aut02": { e: "Does it include insurance, or is that an extra charge?", t: "¿Incluye seguro, o es un cargo adicional?", s: "Cuando un cliente pregunta si el seguro viene incluido en el precio del alquiler.", sEn: "When a customer asks whether insurance is included in the rental price.", n: "\"Insurance\" se acentúa en la segunda sílaba: in-SUR-ance.", nEn: "\"Insurance\" is stressed on the second syllable: in-SUR-ance." },
    "loc-aut03": { e: "Please return it with a full tank, or we'll charge you for the fuel.", t: "Por favor devuélvalo con el tanque lleno, o le cobraremos el combustible.", s: "Cuando le explicas al cliente la política de combustible al devolver el auto.", sEn: "When you explain the fuel policy to a customer returning the car.", n: "\"Full tank\" es la frase fija; \"tank full\" suena incorrecto en inglés.", nEn: "\"Full tank\" is the fixed phrase; \"tank full\" sounds wrong in English." },
    "loc-aut04": { e: "Everything looks good, just sign here, please.", t: "Todo se ve bien, solo firme aquí, por favor.", s: "Cuando le pides al cliente que firme el contrato de alquiler.", sEn: "When you ask the customer to sign the rental contract.", n: "\"Sign\" se pronuncia \"sain\", con la g muda.", nEn: "\"Sign\" is pronounced \"sain\", with a silent g." },
    "loc-aut05": { e: "I need your driver's license and a credit card to complete the rental.", t: "Necesito su licencia de conducir y una tarjeta de crédito para completar el alquiler.", s: "Cuando le pides al cliente los documentos requeridos para rentar.", sEn: "When you ask the customer for the documents required to rent.", n: "Nota el apóstrofo: \"driver's license\", no \"drivers license\".", nEn: "Note the apostrophe: \"driver's license\", not \"drivers license\"." },
    "loc-aut06": { e: "Don't worry, the car is automatic, so you won't need to shift gears.", t: "No se preocupe, el auto es automático, así que no tendrá que cambiar marchas.", s: "Cuando tranquilizas a un cliente diciéndole que el auto no es manual.", sEn: "When you reassure a customer that the car isn't a manual.", n: "En EE. UU. un auto manual se llama \"stick shift\"; útil saberlo si preguntan.", nEn: "In the US a manual car is called a \"stick shift\"; handy to know if they ask." },
    "loc-aut07": { e: "There's a security deposit of two hundred dollars, refunded when you return the car.", t: "Hay un depósito de garantía de doscientos dólares, que se devuelve al regresar el auto.", s: "Cuando le explicas al cliente que debe dejar un depósito reembolsable.", sEn: "When you explain to the customer that there's a refundable deposit.", n: "\"Deposit\" se acentúa en la segunda sílaba: de-PO-sit.", nEn: "\"Deposit\" is stressed on the second syllable: de-PO-sit." },
    "loc-aut08": { e: "Before you drive off, check the car for any damage and let me know.", t: "Antes de salir, revise el auto por si hay daños y avíseme.", s: "Cuando le pides al cliente que inspeccione el auto antes de llevarlo.", sEn: "When you ask the customer to inspect the car before taking it.", n: "\"Damage\" es incontable: no digas \"damages\" para los golpes del auto.", nEn: "\"Damage\" is uncountable: don't say \"damages\" for dents on the car." },
    "loc-aut09": { e: "Drop-off is at the airport branch, and it's open until midnight.", t: "La devolución es en la sucursal del aeropuerto, y abre hasta la medianoche.", s: "Cuando le indicas al cliente dónde debe entregar el auto al final.", sEn: "When you tell the customer where to return the car at the end.", n: "\"Drop-off\" es el sustantivo; el verbo es \"to drop off\" (the car).", nEn: "\"Drop-off\" is the noun; the verb is \"to drop off\" (the car)." },
    "loc-aut10": { e: "Here are your keys, enjoy the trip and drive safely!", t: "Aquí tiene sus llaves, ¡disfrute el viaje y maneje con cuidado!", s: "Cuando te despides del cliente justo después de entregarle el auto.", sEn: "When you say goodbye to the customer right after handing over the car.", n: "\"Drive safely\" (adverbio) es lo correcto; \"drive safe\" se oye informal pero menos cuidado.", nEn: "\"Drive safely\" (adverb) is correct; \"drive safe\" is casual but less polished." },
    // ===================== Museum & tickets (museo-en) =====================
    "loc-mus01": { e: "Admission is twenty thousand, but it's free for children under six.", t: "La entrada cuesta veinte mil, pero es gratis para niños menores de seis.", s: "Cuando le dices a un visitante cuánto cuesta entrar al museo.", sEn: "When you tell a visitor how much it costs to enter the museum.", n: "\"Admission\" es la entrada al lugar; \"ticket\" es el papel que compras.", nEn: "\"Admission\" is entry to the place; \"ticket\" is the paper you buy." },
    "loc-mus02": { e: "You're welcome to take pictures, but no flash photography, please.", t: "Puede tomar fotos, pero no fotos con flash, por favor.", s: "Cuando le recuerdas a un visitante que no use el flash dentro del museo.", sEn: "When you remind a visitor not to use flash inside the museum.", n: "\"Photography\" se acentúa en la segunda sílaba: pho-TO-gra-phy.", nEn: "\"Photography\" is stressed on the second syllable: pho-TO-gra-phy." },
    "loc-mus03": { e: "Just so you know, the museum closes at five, so you have about an hour.", t: "Para que sepa, el museo cierra a las cinco, así que tiene como una hora.", s: "Cuando le informas a un visitante el horario de cierre del museo.", sEn: "When you tell a visitor what time the museum closes.", n: "\"Closes at\" lleva \"at\" para horas exactas; recuérdalo: at five, at noon.", nEn: "\"Closes at\" uses \"at\" for exact times; remember: at five, at noon." },
    "loc-mus04": { e: "The guided tour starts now, please follow me to the main hall.", t: "La visita guiada empieza ahora, por favor síganme a la sala principal.", s: "Cuando anuncias a un grupo que el recorrido con guía va a comenzar.", sEn: "When you announce to a group that the guided tour is about to begin.", n: "También puedes decir \"is starting now\" para sonar un poco más natural.", nEn: "You can also say \"is starting now\" to sound a touch more natural." },
    "loc-mus05": { e: "Please don't touch the artwork, but feel free to take photos without flash.", t: "Por favor, no toque las obras, pero puede tomar fotos sin flash.", s: "Cuando un visitante se acerca demasiado a una pintura o escultura en el museo.", sEn: "When a visitor gets too close to a painting or sculpture in the museum.", n: "Suena más amable si agregas 'please' al inicio y ofreces una alternativa, como tomar fotos.", nEn: "It sounds friendlier if you add 'please' at the start and offer an alternative, like taking photos." },
    "loc-mus06": { e: "The cloakroom is on the left, just past the ticket desk, if you'd like to leave your coat.", t: "El guardarropa está a la izquierda, justo pasando la taquilla, si quiere dejar su abrigo.", s: "Cuando un visitante llega con abrigo, maleta o mochila grande y busca dónde dejarlos.", sEn: "When a visitor arrives with a coat, suitcase, or large backpack and is looking for a place to leave it.", n: "'Cloakroom' se pronuncia 'clouk-rum'; en EE.UU. también puedes decir 'coat check'.", nEn: "'Cloakroom' is pronounced 'klohk-room'; in the US you can also say 'coat check'." },
    "loc-mus07": { e: "There's a student discount, so just show me your ID and you'll pay less.", t: "Hay descuento para estudiantes, así que solo muéstreme su carné y pagará menos.", s: "Cuando un cliente joven pregunta por el precio de la entrada en la taquilla.", sEn: "When a young customer asks about the ticket price at the box office.", n: "Usa 'a student discount' con 'a'; pedir la identificación con 'show me your ID' es lo natural.", nEn: "Use 'a student discount' with 'a'; asking for ID with 'show me your ID' sounds natural." },
    "loc-mus08": { e: "Just follow the arrows on the floor and they'll take you through the whole exhibition.", t: "Solo siga las flechas en el piso y lo llevarán por toda la exposición.", s: "Cuando un visitante no sabe por dónde empezar el recorrido del museo.", sEn: "When a visitor doesn't know where to start the museum route.", n: "'Arrows' se pronuncia 'á-rrous'; no lo confundas con 'arrow' en singular si hay varias.", nEn: "'Arrows' is pronounced 'AIR-ohz'; don't confuse it with singular 'arrow' if there are several." },
    "loc-mus09": { e: "The exhibition is temporary, so it's only here until the end of the month.", t: "La exposición es temporal, así que solo está aquí hasta fin de mes.", s: "Cuando un visitante pregunta si una muestra estará disponible más adelante.", sEn: "When a visitor asks whether a display will still be available later on.", n: "'Temporary' se pronuncia 'tém-po-re-ri'; el opuesto útil es 'permanent' (permanente).", nEn: "'Temporary' is pronounced 'TEM-puh-rair-ee'; the useful opposite is 'permanent'." },
    "loc-mus10": { e: "Here's your ticket and a map. Enjoy your visit!", t: "Aquí tiene su entrada y un mapa. ¡Disfrute su visita!", s: "Cuando entregas la entrada al visitante y se va a recorrer el museo.", sEn: "When you hand the visitor their ticket and they head off to explore the museum.", n: "Dilo con una sonrisa al final; una variante más corta es solo 'Enjoy!'", nEn: "Say it with a smile at the end; a shorter variant is just 'Enjoy!'" },
    // ===================== Deliveries (delivery-en) =====================
    "loc-del01": { e: "Hi, I have your order here from the restaurant.", t: "Hola, tengo su pedido aquí del restaurante.", s: "Cuando llegas a la puerta del cliente para entregar la comida o el paquete.", sEn: "When you arrive at the customer's door to hand over the food or package.", n: "'I have your order' suena más natural que 'I bring your order'; evita 'I bring'.", nEn: "'I have your order' sounds more natural than 'I bring your order'; avoid 'I bring'." },
    "loc-del02": { e: "Can you open the gate? I have a delivery for apartment 3B.", t: "¿Me abre el portón? Traigo una entrega para el apartamento 3B.", s: "Cuando llegas a un edificio cerrado y necesitas que te dejen entrar.", sEn: "When you arrive at a locked building and need someone to let you in.", n: "Para sonar más cortés puedes decir 'Could you open the gate, please?'", nEn: "To sound more polite you can say 'Could you open the gate, please?'" },
    "loc-del03": { e: "Which floor is it? I'll bring it right up.", t: "¿En qué piso es? Se lo subo enseguida.", s: "Cuando entras a un edificio con varios pisos y no sabes a cuál subir.", sEn: "When you enter a multi-floor building and aren't sure which one to go up to.", n: "En EE.UU. el primer piso es 'first floor' (planta baja); en el Reino Unido es 'ground floor'.", nEn: "In the US the first floor is the ground level; in the UK that's the 'ground floor'." },
    "loc-del04": { e: "Here's your food, still hot. Enjoy your meal!", t: "Aquí tiene su comida, todavía caliente. ¡Que lo disfrute!", s: "Cuando entregas un pedido de comida y te despides del cliente.", sEn: "When you hand over a food order and say goodbye to the customer.", n: "'Enjoy your meal' es lo natural en inglés; no se usa 'good profit' por 'buen provecho'.", nEn: "'Enjoy your meal' is the natural choice; English has no real equivalent of 'buen provecho'." },
    "loc-del05": { e: "Can you sign here, please? Just on the screen with your finger.", t: "¿Me firma aquí, por favor? Solo en la pantalla con el dedo.", s: "Cuando el cliente debe firmar para confirmar que recibió el pedido.", sEn: "When the customer needs to sign to confirm they received the order.", n: "Agregar 'please' lo hace más cortés; 'sign' se pronuncia 'sain', la g es muda.", nEn: "Adding 'please' makes it more polite; 'sign' is pronounced 'sine', the g is silent." },
    "loc-del06": { e: "Your order arrives in ten minutes; the driver is on the way.", t: "Su pedido llega en diez minutos; el repartidor va en camino.", s: "Cuando informas al cliente por teléfono o app cuánto falta para la entrega.", sEn: "When you tell the customer by phone or app how long until delivery.", n: "También puedes decir 'will arrive in ten minutes'; 'in' indica tiempo que falta.", nEn: "You can also say 'will arrive in ten minutes'; 'in' marks the time remaining." },
    "loc-del07": { e: "That'll be fifteen dollars. Cash or card?", t: "Son quince dólares. ¿Efectivo o tarjeta?", s: "Cuando el cliente recibe el pedido y debe pagar al repartidor.", sEn: "When the customer receives the order and needs to pay the delivery person.", n: "Es una frase fija y corta; di 'card' (no 'credit card') para ir más rápido.", nEn: "It's a fixed, short phrase; say 'card' (not 'credit card') to keep it quick." },
    "loc-del08": { e: "No problem, I'll leave it at the door and text you.", t: "Sin problema, lo dejo en la puerta y le escribo.", s: "Cuando el cliente pide entrega sin contacto y no quiere abrir la puerta.", sEn: "When the customer asks for contactless delivery and doesn't want to open the door.", n: "'At the door' es lo común; 'text you' significa mandar un mensaje de texto.", nEn: "'At the door' is common; 'text you' means to send a text message." },
    "loc-del09": { e: "I'm downstairs by the entrance whenever you're ready.", t: "Estoy abajo en la entrada cuando esté listo.", s: "Cuando llegas y avisas al cliente que esperas en la planta baja del edificio.", sEn: "When you arrive and let the customer know you're waiting on the ground level.", n: "'Downstairs' es una sola palabra; lo opuesto es 'upstairs' (arriba).", nEn: "'Downstairs' is one word; the opposite is 'upstairs'." },
    "loc-del10": { e: "Thanks for your order, and have a great day!", t: "Gracias por su pedido, ¡y que tenga un buen día!", s: "Cuando terminas la entrega y te despides del cliente.", sEn: "When you finish the delivery and say goodbye to the customer.", n: "Cerrar con 'have a great day' deja buena impresión y suma para una buena reseña.", nEn: "Closing with 'have a great day' leaves a good impression and helps earn a good review." },
    // ===================== Gym & fitness (gym-en) =====================
    "loc-gym01": { e: "Come on, ten more reps and then we'll rest.", t: "Vamos, diez repeticiones más y luego descansamos.", s: "Cuando como entrenador animas a alguien a terminar una serie de ejercicios.", sEn: "When, as a trainer, you push someone to finish a set of exercises.", n: "'Reps' es la forma corta de 'repetitions', muy usada en el gimnasio.", nEn: "'Reps' is the short form of 'repetitions', very common at the gym." },
    "loc-gym02": { e: "Keep your back straight so you don't hurt yourself.", t: "Mantenga la espalda recta para no lastimarse.", s: "Cuando corriges la postura de alguien que levanta peso en el gimnasio.", sEn: "When you correct the posture of someone lifting weights at the gym.", n: "'Straight' se pronuncia 'streit'; no la confundas con 'strait'.", nEn: "'Straight' is pronounced 'strayt'; don't confuse it with 'strait'." },
    "loc-gym03": { e: "Great job, keep it up, you're almost there!", t: "¡Buen trabajo, siga así, ya casi lo logra!", s: "Cuando felicitas a alguien que se está esforzando durante el entrenamiento.", sEn: "When you praise someone who is pushing hard during their workout.", n: "'Keep it up' significa 'siga así'; es muy motivador y se usa mucho en el gimnasio.", nEn: "'Keep it up' means to keep going; it's very motivating and common at the gym." },
    "loc-gym04": { e: "Breathe out as you lift, and breathe in as you go down.", t: "Exhale al subir, e inhale al bajar.", s: "Cuando enseñas la técnica de respiración correcta durante un ejercicio.", sEn: "When you teach the correct breathing technique during an exercise.", n: "'Breathe' (verbo) suena 'briid'; 'breath' (sustantivo) suena 'bréz', son distintos.", nEn: "'Breathe' (verb) sounds like 'breeth'; 'breath' (noun) sounds like 'breth', they differ." },
    "loc-gym05": { e: "Good work, now rest for thirty seconds before the next set.", t: "Buen trabajo, ahora descanse treinta segundos antes de la siguiente serie.", s: "Cuando guías a un cliente entre series y quieres darle una pausa corta.", sEn: "When you coach a client between sets and want to give a short pause.", n: "Puedes decir \"take thirty seconds\" como variante mas casual.", nEn: "You can say \"take thirty seconds\" as a more casual variant." },
    "loc-gym06": { e: "Before you lift anything, don't forget to warm up for five minutes.", t: "Antes de levantar peso, no olvide calentar cinco minutos.", s: "Cuando un cliente quiere empezar a entrenar de inmediato sin preparación.", sEn: "When a client wants to start training right away without preparation.", n: "\"Warm up\" es verbo separado; el sustantivo es \"a warm-up\" con guion.", nEn: "\"Warm up\" is a two-word verb; the noun is \"a warm-up\" with a hyphen." },
    "loc-gym07": { e: "You look tired, drink some water and take a quick break.", t: "Se ve cansado, tome agua y descanse un momento.", s: "Cuando ves a alguien sofocado durante el entrenamiento.", sEn: "When you see someone overheated during a workout.", n: "\"Drink some water\" suena mas natural que \"drink water\" para una sugerencia.", nEn: "\"Drink some water\" sounds more natural than \"drink water\" for a suggestion." },
    "loc-gym08": { e: "Control the movement and lower it slowly, don't drop the weight.", t: "Controle el movimiento y baje despacio, no suelte el peso.", s: "Cuando corriges la técnica de alguien que baja la pesa muy rápido.", sEn: "When you correct someone's form as they drop the weight too fast.", n: "Para personas, di \"go down slowly\"; \"lower it\" es para objetos o pesas.", nEn: "For people say \"go down slowly\"; \"lower it\" is for objects or weights." },
    "loc-gym09": { e: "Come on, one more set and then we're done for today.", t: "Vamos, una serie más y terminamos por hoy.", s: "Cuando animas a un cliente a completar la última ronda del ejercicio.", sEn: "When you encourage a client to finish the last round of the exercise.", n: "\"Set\" es una serie de repeticiones; \"rep\" es cada repetición individual.", nEn: "A \"set\" is a series of reps; a \"rep\" is each individual repetition." },
    "loc-gym10": { e: "Great session today, just stretch when you finish to avoid soreness.", t: "Excelente sesión hoy, solo estire al terminar para evitar dolores.", s: "Cuando cierras el entrenamiento y recomiendas estiramientos finales.", sEn: "When you wrap up the workout and recommend final stretches.", n: "\"Stretch\" suena la 'tch' como en \"church\", no como una 's' suave.", nEn: "In \"stretch\" the 'tch' sounds like in \"church,\" not a soft 's.'" },
    // ===================== Home & helpers (hogar-en) =====================
    "loc-hog01": { e: "Don't worry, it's fixed now and the faucet isn't leaking anymore.", t: "No se preocupe, ya está arreglado y la llave ya no gotea.", s: "Cuando le avisas al dueño de casa que terminaste una reparación.", sEn: "When you tell the homeowner you finished a repair.", n: "\"It's fixed\" describe el resultado; \"I fixed it\" enfatiza que tú lo hiciste.", nEn: "\"It's fixed\" describes the result; \"I fixed it\" stresses that you did it." },
    "loc-hog02": { e: "Just to confirm, what time do I pick up the kids from school?", t: "Solo para confirmar, ¿a qué hora recojo a los niños de la escuela?", s: "Cuando organizas el día con la familia y necesitas la hora exacta.", sEn: "When you plan the day with the family and need the exact time.", n: "\"Pick up\" para personas; di \"drop off\" cuando los llevas y los dejas.", nEn: "\"Pick up\" is for getting people; use \"drop off\" when you leave them." },
    "loc-hog03": { e: "I can't open this, I need a tool, do you have a screwdriver?", t: "No puedo abrir esto, necesito una herramienta, ¿tiene un destornillador?", s: "Cuando una tarea requiere algo que no tienes a mano en la casa.", sEn: "When a task needs something you don't have on hand at the house.", n: "\"Tool\" se pronuncia con 'u' larga, como \"tu\", no \"tul\".", nEn: "\"Tool\" is pronounced with a long 'oo,' like \"too,\" not \"tull.\"" },
    "loc-hog04": { e: "The food is ready, should I serve it now or keep it warm?", t: "La comida está lista, ¿la sirvo ahora o la mantengo caliente?", s: "Cuando terminas de cocinar y avisas a la familia.", sEn: "When you finish cooking and let the family know.", n: "\"Food\" es incontable, así que no digas \"the foods are ready\".", nEn: "\"Food\" is uncountable, so don't say \"the foods are ready.\"" },
    "loc-hog05": { e: "Once everyone's done eating, I'll clean the kitchen.", t: "Cuando todos terminen de comer, voy a limpiar la cocina.", s: "Cuando organizas tus tareas y avisas qué harás después.", sEn: "When you plan your tasks and say what you'll do next.", n: "\"I'll\" suena \"ail\"; junta las palabras para sonar mas fluido y natural.", nEn: "\"I'll\" sounds like \"ail\"; blend the words to sound more fluent." },
    "loc-hog06": { e: "I finished the laundry, where do I put this clean towel?", t: "Terminé la ropa, ¿dónde guardo esta toalla limpia?", s: "Cuando no sabes el lugar correcto para algo en la casa.", sEn: "When you don't know the right place for something in the house.", n: "\"Where do I put this?\" es para guardar; \"where does this go?\" es otra variante.", nEn: "\"Where do I put this?\" is for storing; \"where does this go?\" is a variant." },
    "loc-hog07": { e: "The kids already ate, so they just need a bath before bed.", t: "Los niños ya comieron, así que solo falta bañarlos antes de dormir.", s: "Cuando informas el estado de los niños al volver el papá o la mamá.", sEn: "When you update the parent on the kids when they get home.", n: "\"Already\" va antes del verbo principal: \"already ate\", no \"ate already\".", nEn: "\"Already\" goes before the main verb: \"already ate,\" not \"ate already.\"" },
    "loc-hog08": { e: "I'm running to the store, I'll be back in an hour.", t: "Voy corriendo a la tienda, vuelvo en una hora.", s: "Cuando sales un momento y avisas cuándo regresas.", sEn: "When you step out briefly and say when you'll return.", n: "Se dice \"in an hour\" (no \"in one hour\") para una hora aproximada.", nEn: "Say \"in an hour\" (not \"in one hour\") for roughly one hour." },
    "loc-hog09": { e: "Just so you know, we're out of soap, can I buy more?", t: "Para que sepa, se acabó el jabón, ¿puedo comprar más?", s: "Cuando notas que falta un producto de limpieza en la casa.", sEn: "When you notice a cleaning product has run out at the house.", n: "\"We're out of\" significa que se acabó algo; muy común en casa y trabajo.", nEn: "\"We're out of\" means something has run out; very common at home and work." },
    "loc-hog10": { e: "The internet seems slow, should I check the Wi-Fi router?", t: "El internet parece lento, ¿reviso el router del wifi?", s: "Cuando la conexión falla y ofreces revisarla antes de actuar.", sEn: "When the connection fails and you offer to check before acting.", n: "\"Wi-Fi\" se dice \"wai-fai\"; ofrecer con \"Should I...?\" suena servicial.", nEn: "\"Wi-Fi\" is said \"wai-fai\"; offering with \"Should I...?\" sounds helpful." },
    "loc-hog11": { e: "To save energy, please turn off the light when you leave the room.", t: "Para ahorrar energía, por favor apague la luz al salir del cuarto.", s: "Cuando recuerdas a alguien apagar las luces al salir.", sEn: "When you remind someone to switch off the lights as they leave.", n: "\"Turn off\" para luces o aparatos; \"switch off\" es un sinónimo común.", nEn: "\"Turn off\" works for lights or devices; \"switch off\" is a common synonym." },
    "loc-hog12": { e: "The mixer broke, I need a spare part to fix it properly.", t: "La licuadora se dañó, necesito un repuesto para arreglarla bien.", s: "Cuando algo se descompone y hace falta una pieza de reemplazo.", sEn: "When something breaks and a replacement piece is needed.", n: "\"Spare part\" es el repuesto; \"replacement\" también sirve en este contexto.", nEn: "\"Spare part\" means the replacement piece; \"replacement\" also works here." },
  };

  var SC = window.SC || (window.SC = {});
  SC.contextDataLocals = C;
})();
